function shipWithinDays(weights, D) {
    let lb = Math.max(...weights) - 1;
    let ub = 1 << 30;

    while (ub - lb > 1) {
        let mid = Math.floor((lb + ub) / 2);
        let w = 0;
        let num = 1;

        for (let i = 0; i < weights.length; i++) {
            if (w + weights[i] <= mid) {
                w += weights[i];
            } else {
                w = weights[i];
                num++;
            }
        }

        if (num <= D) {
            ub = mid;
        } else {
            lb = mid;
        }
    }

    return ub;
}

