const fs = require('fs');

class Solution {
    matrixBlockSum(matrix, K) {
        const helper = (matrix, i, j) => {
            const n = matrix.length, m = matrix[0].length;
            return (n > i && i >= 0 && m > j && j >= 0) ? matrix[i][j] : 0;
        };

        const n = matrix.length, m = matrix[0].length;
        let lookup = Array.from({length: n}, () => Array(m).fill(-1));

        for (let i = 0; i < n; i++) {
            for (let j = 0; j < m; j++) {
                lookup[i][j] = matrix[i][j] + helper(lookup, i, j-1) + helper(lookup, i-1, j) - helper(lookup, i-1, j-1);
            }
        }

        let ans = Array.from({length: n}, () => Array(m).fill(-1));
        for (let i = 0; i < n; i++) {
            for (let j = 0; j < m; j++) {
                let left_row = i - K - 1, left_col = j - K - 1;
                let right_row = Math.min(i + K, n - 1), right_col = Math.min(j + K, m - 1);

                let biggest = helper(lookup, right_row, right_col);
                let leftish = helper(lookup, right_row, left_col);
                let rightish = helper(lookup, left_row, right_col);
                let smallest = helper(lookup, left_row, left_col);

                ans[i][j] = biggest - leftish - rightish + smallest;
            }
        }

        return ans;
    }
}

