function dominantIndex(nums) {
    let maxVal = Number.MIN_SAFE_INTEGER;
    let maxIndex = 0;

    for (let i = 0; i < nums.length; i++) {
        if (nums[i] > maxVal) {
            maxVal = nums[i];
            maxIndex = i;
        }
    }

    for (let j = 0; j < nums.length; j++) {
        if (j === maxIndex) {
            continue;
        }
        if (nums[j] * 2 > maxVal) {
            return -1;
        }
    }
    return maxIndex;
}

