class Solution {

    recur(i, s, total, dic, N, val, count) {
        if (val === total && count === N) {
            return true;
        }
        if ((N - count) * 2 > total - val || total - val < 2 || count >= N) {
            return false;
        }
        if (total - val >= dic[s[i]]) {
            const value = Math.floor((total - val) / s[i]);
            dic[s[i]] += value;
            val += value * s[i];
            count += value;
            while (dic[s[i]] > 0) {
                if (this.recur(i + 1, s, total, dic, N, val, count)) {
                    return true;
                }
                dic[s[i]] -= 1;
                val -= s[i];
                count -= 1;
            }
        }
        if (this.recur(i + 1, s, total, dic, N, val, count)) {
            return true;
        }
        return false;
    }

    sevenSegments(S, N) {
        let dic = { '0': 6, '1': 2, '2': 5, '3': 5, '4': 4, '5': 5, '6': 6, '7': 3, '8': 7, '9': 5 };
        let val_dic = { 6: '0', 2: '1', 5: '2', 4: '4', 3: '7', 7: '8' };
        let s = [6, 2, 5, 4, 3, 7];
        let a = {};
        let total = 0;

        for (let i = 0; i < N; i++) {
            total += dic[S[i]];
        }
        if (N === 1) {
            return val_dic[total];
        }

        for (let i = 0; i < s.length; i++) {
            a[s[i]] = 0;
        }

        let val = Math.floor(total / 6);
        while (val > 0) {
            if (this.recur(1, s, total, a, N, val * 6, val)) {
                a[6] = val;
                break;
            }
            val -= 1;
        }

        let arr = [];
        let ans = '';

        for (let i in a) {
            if (a[i] > 0) {
                for (let j = 0; j < a[i]; j++) {
                    arr.push(i);
                }
            }
        }

        for (let i = 0; i < arr.length; i++) {
            ans += val_dic[arr[i]];
        }
        return ans;
    }
}

