function findMin(S, n) {
    let total = S.reduce((a, b) => a + b, 0);
    let T = Array.from({ length: S.length + 1 }, () => Array(total + 1).fill(false));

    for (let i = 0; i <= S.length; i++) {
        T[i][0] = true;
    }

    for (let i = 1; i <= S.length; i++) {
        for (let j = 1; j <= total; j++) {
            T[i][j] = T[i - 1][j];
            if (S[i - 1] <= j) {
                T[i][j] = T[i][j] || T[i - 1][j - S[i - 1]];
            }
        }
    }

    let j = Math.floor(total / 2);
    while (j >= 0 && !T[S.length][j]) {
        j--;
    }
    return total - 2 * j;
}

