function minSumOfLengths(arr, target) {
    let i = 0, window = 0, result = Infinity;
    let premin = new Array(arr.length).fill(Infinity);

    for (let j = 0; j < arr.length; j++) {
        const num = arr[j];
        window += num;

        while (window > target) {
            window -= arr[i];
            i += 1;
        }

        if (window === target) {
            const curr = j - i + 1;
            result = Math.min(result, curr + (i > 0 ? premin[i - 1] : 0));
            premin[j] = Math.min(curr, j > 0 ? premin[j - 1] : Infinity);
        } else {
            premin[j] = j > 0 ? premin[j - 1] : Infinity;
        }
    }

    return result < Infinity ? result : -1;
}

