const fs = require('fs');

function helper(dp, h, w) {
	if (h < 0 || w < 0) {
		return 1;
	}
	if (h === 0 || w === 0) {
		dp[h][w] = h + 1;
		return dp[h][w];
	}
	if (dp[h][w] != -1) {
		return dp[h][w];
	}
	dp[h][w] = 0;
	for (let i = 0; i <= h; i++) {
		dp[h][w] += helper(dp, i, w - 1);
	}
	return dp[h][w];
}

function solve() {
	let input = fs.readFileSync(0, 'utf8');
	let nums = input.split(' ').map(Number);
	let n = nums[0], m = nums[1];
	let modulo = 1000000007;
	let dp = Array.from({ length: n + 1 }, () => Array(m + 1).fill(-1));
	let ans = 0;
	for (let h = 0; h < n; h++) {
		let part1 = helper(dp, h, m - 2);
		let part2 = helper(dp, n - h - 1, m - 1);
		ans += part1 * part2;
	}
	console.log(ans % modulo);
}

for (let _ = 0; _ < 1; _++) {
	solve();
}

