function multiply(arr, n) {
    var num = Math.floor(n / 2);
    var arr1 = arr.slice(0, num);
    var arr2 = arr.slice(num);
    var sum1 = sum(arr1);
    var sum2 = sum(arr2);
    return sum1 * sum2;
}

function sum(array) {
    var total = 0;
    for (let i = 0; i < array.length; i++) {
        total += array[i];
    }
    return total;
}

