function offerings(n, arr) {
    let prev = arr[0];
    let start = 0;
    let profit = 0;
    let dp1 = new Array(n).fill(0);

    for (let i = 1; i < n; i++) {
        if (arr[i] > arr[i - 1]) {
            profit = i - start;
        } else {
            start = i;
            profit = 0;
        }
        dp1[i] = profit;
    }

    prev = arr[n - 1];
    start = n - 1;
    profit = 0;
    let dp2 = new Array(n).fill(0);

    for (let i = n - 2; i >= 0; i--) {
        if (arr[i] > arr[i + 1]) {
            profit = start - i;
        } else {
            start = i;
            profit = 0;
        }
        dp2[i] = profit;
    }

    let ans = 0;

    for (let i = 0; i < n; i++) {
        ans += Math.max(dp1[i], dp2[i]) + 1;
    }
    return ans;
}

