class Searchable_BIT {
    constructor(N) {
        this.N = N;
        this.node = new Array(this.N + 1).fill(0);
        this.cnt = 0;
    }

    add(a) {
        let x = a;
        this.cnt += 1;
        while (x <= this.N) {
            this.node[x] += 1;
            x += x & -x;
        }
    }

    delete(x) {
        this.cnt -= 1;
        while (x <= this.N) {
            this.node[x] -= 1;
            x += x & -x;
        }
    }

    count(x) {
        if (x === 0) return 0;
        let tmp = 0;
        while (x > 0) {
            tmp += this.node[x];
            x -= x & -x;
        }
        return tmp;
    }

    get_maxval() {
        return this.get_lower_i(this.cnt);
    }

    get_min_left(x) {
        return this.get_lower_i(this.count(x - 1) + 1);
    }

    get_lower_i(i) {
        let NG = -1;
        let OK = this.N;
        while (OK - NG > 1) {
            let mid = Math.floor((OK + NG) / 2);
            if (this.count(mid) >= i) {
                OK = mid;
            } else {
                NG = mid;
            }
        }
        return OK;
    }
}

