function largestValsFromLabels(values, labels, num_wanted, use_limit) {
    const all_value_labels = createPairs(values, labels);
    sortPairs(all_value_labels);
    const used = {};
    const ans = [];

    for (let i = 0; i < all_value_labels.length; i++) {
        const current = all_value_labels[i];
        const value = current[0];
        const label = current[1];

        if (checkUseLimit(used, label, use_limit)) {
            incrementUse(used, label);
            ans.push(value);
            if (ans.length === num_wanted) {
                break;
            }
        }
    }
    return sumValues(ans);
}

function createPairs(values, labels) {
    const pairs = [];
    for (let i = 0; i < values.length; i++) {
        pairs.push([values[i], labels[i]]);
    }
    return pairs;
}

function sortPairs(pairs) {
    pairs.sort((a, b) => b[0] - a[0]);
}

function checkUseLimit(used, label, use_limit) {
    const current = used[label] || 0;
    return current + 1 <= use_limit;
}

function incrementUse(used, label) {
    if (used[label] == null) {
        used[label] = 0;
    }
    used[label] += 1;
}

function sumValues(arr) {
    let total = 0;
    for (let i = 0; i < arr.length; i++) {
        total += arr[i];
    }
    return total;
}

