class Solution {
    numSimilarGroups(A) {
        let rank = new Array(A.length).fill(0);
        let paren = new Array(A.length);
        let ans = A.length;

        for (let i = 0; i < paren.length; ++i) {
            paren[i] = i;
        }

        for (let i = 0; i < A.length - 1; ++i) {
            for (let j = i + 1; j < A.length; ++j) {
                if (this.similar(A[i], A[j])) {
                    let p1 = this.find(paren, i);
                    let p2 = this.find(paren, j);
                    if (p1 !== p2) {
                        ans--;
                        this.union(rank, paren, p1, p2);
                    }
                }
            }
        }

        return ans;
    }

    find(paren, curr) {
        if (paren[curr] === curr) {
            return curr;
        }
        paren[curr] = this.find(paren, paren[curr]);
        return paren[curr];
    }

    union(rank, paren, p1, p2) {
        if (rank[p1] >= rank[p2]) {
            paren[p2] = p1;
        } else {
            paren[p1] = p2;
        }
        if (rank[p1] === rank[p2]) {
            rank[p1]++;
        }
    }

    similar(s1, s2) {
        if (s1.length !== s2.length) {
            return false;
        }
        let count = 0;
        let arr1 = new Array(2);
        let arr2 = new Array(2);

        for (let i = 0; i < s1.length; ++i) {
            if (s1.charAt(i) !== s2.charAt(i)) {
                if (count === 2) {
                    return false;
                }
                arr1[count] = s1.charAt(i);
                arr2[count] = s2.charAt(i);
                count++;
            }
        }

        if (count !== 2) {
            return false;
        }

        return (arr1[0] === arr2[0] && arr1[1] === arr2[1]) || (arr1[0] === arr2[1] && arr1[1] === arr2[0]);
    }
}

