function convertFive(n) {
    let stk = [];
    let ans = 0;
    while (n !== 0) {
        stk.push(n % 10);
        n = Math.floor(n / 10);
    }
    while (stk.length > 0) {
        let ele = stk.pop();
        if (ele === 0) {
            ans = ans * 10 + 5;
        } else {
            ans = ans * 10 + ele;
        }
    }
    return ans;
}

function convertFiveRecursive(n) {
    if (n === 0) {
        return 0;
    }
    let digit = n % 10;
    if (digit === 0) {
        digit = 5;
    }
    return convertFiveRecursive(Math.floor(n / 10)) * 10 + digit;
}

