function calculateCumulativeSum(N, A) {
    let cusum = [0];
    for (let i = 0; i < N; i++) {
        let temp = cusum[i] + A[i];
        cusum.push(temp);
    }
    return cusum;
}

function bisect(arr, x) {
    let low = 0, high = arr.length;
    while (low < high) {
        let mid = Math.floor((low + high) / 2);
        if (arr[mid] <= x) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }
    return low;
}

function calculateAnswer(cusum, K) {
    let ans = 0;
    for (let i = 0; i < cusum.length; i++) {
        if (cusum[i] < K) {
            continue;
        }
        ans += bisect(cusum, cusum[i] - K);
    }
    return ans;
}

