const fs = require('fs')
const LARGE = 998244353

class SegmentTree {
	constructor(init_array, seg_func = Math.max, seg_func_null = 10 ** 9 + 7) {
		this.seg_func = seg_func
		this.seg_func_null = seg_func_null
		this.n = 1
		while (this.n < init_array.length) {
			this.n *= 2
		}
		this.dat = new Array(2 * this.n - 1).fill(0)
		for (let i = 0; i < init_array.length; i++) {
			this.dat[this.n - 1 + i] = init_array[i]
		}
		for (let i = this.n - 2; i >= 0; i--) {
			this.dat[i] = this.seg_func(this.dat[2 * i + 1], this.dat[2 * i + 2])
		}
	}

	update(k, a) {
		k += this.n - 1
		this.dat[k] = a
		while (k > 0) {
			k = Math.floor((k - 1) / 2)
			this.dat[k] = this.seg_func(this.dat[k * 2 + 1], this.dat[k * 2 + 2])
		}
	}

	query(p, q) {
		if (q <= p) return this.seg_func_null
		p += this.n - 1
		q += this.n - 2
		let res = this.seg_func_null
		while (q - p > 1) {
			if (p % 2 === 0) {
				res = this.seg_func(res, this.dat[p])
			}
			if (q % 2 === 1) {
				res = this.seg_func(res, this.dat[q])
				q -= 1
			}
			p = Math.floor(p / 2)
			q = Math.floor((q - 1) / 2)
		}
		if (p === q) {
			res = this.seg_func(res, this.dat[p])
		} else {
			res = this.seg_func(this.seg_func(res, this.dat[p]), this.dat[q])
		}
		return res
	}
}

function solve(n, x_list, d_list) {
	let reach_right = new Array(n).fill(0)
	reach_right[n - 1] = n - 1
	let seg = new SegmentTree(Array.from({ length: n }, (_, i) => i), Math.max, -1)
	for (let i = n - 2; i >= 0; i--) {
		let j = bisect_left(x_list, x_list[i] + d_list[i])
		let k = seg.query(i, j)
		seg.update(i, k)
		reach_right[i] = k
	}
	let dp = Array.from({ length: n }, () => [0, 0])
	dp[n - 1][0] = 1
	dp[n - 1][1] = 1
	for (let i = n - 2; i >= 0; i--) {
		dp[i][0] = (dp[i + 1][0] + dp[i + 1][1]) % LARGE
		let j = reach_right[i] + 1
		if (j <= n - 1) {
			dp[i][1] = (dp[j][0] + dp[j][1]) % LARGE
		} else {
			dp[i][1] = 1
		}
	}
	return (dp[0][0] + dp[0][1]) % LARGE
}

function bisect_left(arr, x) {
	let low = 0, high = arr.length
	while (low < high) {
		let mid = Math.floor((low + high) / 2)
		if (arr[mid] < x) low = mid + 1
		else high = mid
	}
	return low
}

function main() {
	let input = fs.readFileSync(0, 'utf8').split('\n')
	let n = parseInt(input[0])
	let xd_list = Array.from({ length: n }, (_, i) => input[i + 1].split(' ').map(Number)).sort((a, b) => a[0] - b[0])
	let x_list = xd_list.map(xd => xd[0])
	let d_list = xd_list.map(xd => xd[1])
	let res = solve(n, x_list, d_list)
	console.log(res)
}

