                if (r === 0) {
                    res = Math.min(res, dfs(q, cache) + cost);
                } else {
                    res = Math.min(res, dfs(q, cache) + cost + d * r);
                    res = Math.min(res, dfs(q + 1, cache) + cost + d * (p - r));
                }
            }

            cache[k] = res;
            return res;
