function findPairs(y) {
    let pairs = [];
    for (let i = 1; i <= Math.sqrt(y); i++) {
        if (y % i === 0) {
            if (i !== y / i) {
                pairs.push([i, y / i]);
                pairs.push([y / i, i]);
            } else {
                pairs.push([i, i]);
            }
        }
    }
    return pairs;
}

