let t = Array.from({ length: N }, () => Array(1 << N).fill(0));
let f = Array(1 << N).fill(0);
let c = Array.from({ length: N }, () => Array(1 << N).fill(0));
let n, edge = Array.from({ length: N }, () => Array(N).fill(0));
let s = Array(N).fill('');
let p = [];
