function FMT(x) {
    for(let i = 0; i < n; i++) {
        for(let j = 0; j < (1 << n); j++) {
            if((j >> i) & 1) {
                x[j] += x[j ^ (1 << i)];
            }
        }
    }
}

function dfs(x, y) {
    if(x === 0) {
        let res = BigInt(0);
        for(let i = 0; i < (1 << n); i++) {
            if((n - countBits(i)) & 1) res -= c[0][i];
            else res += c[0][i];
        }
        M.set(p.join(','), Number(res));
        return;
    }
    for(let i = y; i <= x; i++) {
        if(x !== i && 2 * i > x) continue;
        for(let j = 0; j < (1 << n); j++) {
            c[x - i][j] = c[x][j] * t[i][j];
        }
        p.push(i);
        dfs(x - i, i);
        p.pop();
    }
}

function countBits(num) {
    return num.toString(2).split('1').length - 1;
}

