function dijkstra(edges, size, src) {
    const INF = 10 ** 18;
    let dist = new Array(size).fill(INF);
    dist[src] = 0;
    let pq = [];
    pq.push([0, src]);

    while (pq.length > 0) {
        let [d, v] = pq.shift();
        if (d > dist[v]) {
            continue;
        }
        for (let [u, weight] of edges[v]) {
            let nd = d + weight;
            if (dist[u] > nd) {
                dist[u] = nd;
                pq.push([nd, u]);
                pq.sort((a, b) => a[0] - b[0]); // A simple way to sort for priority queue
            }
        }
    }
    return dist;
}

