function reverseString(s) {
    let rev = '';
    for(let i = s.length - 1; i >= 0; i--) {
        rev += s[i];
    }
    return rev;
}

function countZerosBetweenOnes(a) {
    let le = a.length;
    let f1 = -1;
    let f2 = -1;
    let res = 0;

    for(let i = 0; i < le; i++) {
        if (a[i] === '1') {
            f1 = i;
            break;
        }
    }

    const reva = reverseString(a);

    for(let j = 0; j < le; j++) {
        if (reva[j] === '1') {
            f2 = le - j - 1;
            break;
        }
    }

    for(let k = f1; k <= f2; k++) {
        if (a[k] === '0') {
            res += 1;
        }
    }

    return {f1, res};
}

