    for (let i = 0; i < H; i++) {
        cost[i] = Array(W).fill(-1);
    }

    while (Q.length > 0) {
        const [r, c, cnt] = Q.shift();
        if (cost[r][c] !== -1) {
            continue;
        }
        cost[r][c] = cnt;

        for (let dr = -2; dr <= 2; dr++) {
            for (let dc = -2; dc <= 2; dc++) {
                const nr = r + dr;
                const nc = c + dc;
                if (0 <= nr && nr < H && 0 <= nc && nc < W && S[nr][nc] === '.') {
                    if (Math.abs(dr) + Math.abs(dc) === 1) {
                        Q.unshift([nr, nc, cnt]);
                    } else if (Math.abs(dr) + Math.abs(dc) >= 2) {
                        Q.push([nr, nc, cnt + 1]);
                    }
                }
            }
        }
    }

