const fs = require('fs');

class Deque {
    constructor() {
        this.items = [];
    }

    append(item) {
        this.items.push(item);
    }

    appendLeft(item) {
        this.items.unshift(item);
    }

    pop() {
        if (this.items.length > 0) {
            return this.items.pop();
        }
        return undefined;
    }

    popLeft() {
        if (this.items.length > 0) {
            return this.items.shift();
        }
        return undefined;
    }

    getItems() {
        return this.items;
    }
}

function processInput() {
    let input = fs.readFileSync(0, 'utf8').split('\n');
    let n = parseInt(input[0]);
    let d = new Deque();

    for (let i = 1; i <= n; i++) {
        let cmd = input[i].split(' ');
        if (cmd[0] === 'append') {
            d.append(parseInt(cmd[1]));
        } else if (cmd[0] === 'appendleft') {
            d.appendLeft(parseInt(cmd[1]));
        } else if (cmd[0] === 'pop') {
            d.pop();
        } else if (cmd[0] === 'popleft') {
            d.popLeft();
        }
    }

    return d.getItems();
}

function main() {
    let result = processInput();
    for (let i = 0; i < result.length; i++) {
        if (i > 0) {
            process.stdout.write(' ');
        }
        process.stdout.write(result[i].toString());
    }
}

