function calculateBinaryValue(s) {
    let k = s.length - 1;
    let ans = 0;
    for (let i = 0; i < s.length; i++) {
        ans += parseInt(s[i]) * Math.pow(2, k);
        k--;
    }
    return ans;
}

function findLargestN(ans) {
    let sum = 0;
    let n = 0;
    while (true) {
        if (sum >= ans) {
            break;
        } else {
            sum = Math.pow(4, n);
            n++;
        }
    }
    return n;
}

