function strongPasswordCheckerII(password) {
    let found = true;
    let prev = ' ';
    let mask = 0;
    const special = "!@#$%^&*()-+";

    for(let i = 0; i < password.length; i++) {
        let x = password[i];

        if(x <= 'Z' && x >= 'A') {
            mask = mask | (1 << 0);
        }
        if(x <= 'z' && x >= 'a') {
            mask = mask | (1 << 1);
        }
        if(x <= '9' && x >= '0') {
            mask = mask | (1 << 2);
        }
        if(special.indexOf(x) !== -1) {
            mask = mask | (1 << 3);
        }
        if(x === prev) {
            found = false;
        }
        prev = x;
    }

    if(found && mask === (2 ** 4 - 1) && password.length >= 8) {
        return true;
    }
    return false;
}

