class Solution {

  minCoins(coins, M, amount) {

    const f = (coins, amt) => {
      if (amt === 0) {
        return 0;
      }
      if (amt < 0) {
        return Infinity;
      }
      if (memo[amt] !== undefined) {
        return memo[amt];
      }
      let ans = Infinity;
      for (let i = 0; i < n; i++) {
        ans = Math.min(ans, 1 + f(coins, amt - coins[i]));
      }
      memo[amt] = ans;
      return memo[amt];
    };

    if (amount === 0) {
      return 0;
    }

    let ans = Infinity;
    const n = coins.length;
    let memo = {};

    for (let i = 0; i < n; i++) {
      ans = Math.min(ans, 1 + f(coins, amount - coins[i]));
    }

    return ans !== Infinity ? ans : -1;
  }
}

