class TreeNode {
    public $data;
    public $left;
    public $right;

    function __construct($data){
        $this->data = $data;
        $this->left = null;
        $this->right = null;
    }
}

function print_paths($root, $target_sum, $curr_sum, &$paths, $path) {
    if ($root == null) {
        return;
    }
    $curr_sum += $root->data;
    array_push($path, $root->data);
    if ($curr_sum == $target_sum) {
        array_push($paths, $path);
    }
    print_paths($root->left, $target_sum, $curr_sum, $paths, array_merge([], $path));
    print_paths($root->right, $target_sum, $curr_sum, $paths, array_merge([], $path));
    return;
}

class Solution {

    function printPaths($root, $target_sum) {
        $paths = [];
        print_paths($root, $target_sum, 0, $paths, []);
        return $paths;
    }
}

