func main() {
	reader := bufio.NewReader(os.Stdin)
	n, m := readInts(reader)
	lab := readLab(reader, m)
	cnt := countLab(lab)

	res := 0
	for amt_ := 1; amt_ <= cnt[len(cnt)-1].count; amt_++ {
		if checkSum(cnt, amt_, n) {
			res = amt_
		} else {
			break
		}
	}
	fmt.Println(res)
}

type entry struct {
	value int
	count int
}

func readInts(reader *bufio.Reader) (int, int) {
	var n, m int
	fmt.Fscan(reader, &n, &m)
	return n, m
}

func readLab(reader *bufio.Reader, m int) []int {
	lab := make([]int, m)
	for i := 0; i < m; i++ {
		fmt.Fscan(reader, &lab[i])
	}
	return lab
}

func countLab(lab []int) []entry {
	countMap := make(map[int]int)
	for _, item := range lab {
		countMap[item]++
	}

	countSlice := make([]entry, 0, len(countMap))
	for key, val := range countMap {
		countSlice = append(countSlice, entry{value: key, count: val})
	}

	sort.Slice(countSlice, func(i, j int) bool {
		return countSlice[i].count < countSlice[j].count
	})

	return countSlice
}

func checkSum(cnt []entry, amt_ int, n int) bool {
	sum := 0
	for _, entry := range cnt {
		if entry.count >= amt_ {
			sum += entry.count / amt_
		}
	}
	return sum >= n
}

