type StreamChecker struct {
	trie     map[rune]map[rune]interface{}
	queries  string
	W        int
}

func NewStreamChecker(words []string) StreamChecker {
	tmpTrie := make(map[rune]map[rune]interface{})
	for _, word := range words {
		node := tmpTrie
		for _, c := range reverseString(word) {
			if _, ok := node[c]; !ok {
				node[c] = make(map[rune]interface{})
			}
			node = node[c].(map[rune]interface{})
		}
		node['$'] = nil
	}

	maxLen := 0
	for _, w := range words {
		if len(w) > maxLen {
			maxLen = len(w)
		}
	}
	return StreamChecker{trie: tmpTrie, queries: "", W: maxLen}
}

func (s *StreamChecker) Query(letter rune) bool {
	s.queries += string(letter)
	node := s.trie
	ret := false
	for _, c := range reverseString(s.queries) {
		if c in node {
			node = node[c].(map[rune]interface{})
			if _, found := node['$']; found {
				return true
			}
		} else {
			break // extra check to exit if character not found
		}
	}
	return ret
}

func reverseString(s string) string {
	res := ""
	for _, c := range s {
		res = string(c) + res
	}
	return res
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	var n int
	fmt.Fscan(reader, &n)
	var words []string
	for i := 0; i < n; i++ {
		var word string
		fmt.Fscan(reader, &word)
		words = append(words, word)
	}
	checker := NewStreamChecker(words)

	var q int
	fmt.Fscan(reader, &q)
	for i := 0; i < q; i++ {
		var letter string
		fmt.Fscan(reader, &letter)
		found := checker.Query(rune(letter[0]))
		if found {
			fmt.Println("true")
		} else {
			fmt.Println("false")
		}
	}
}

