import (
	"container/heap"
	"fmt"
	"os"
	"sort"
)

type IntHeap []int64

func (h IntHeap) Len() int           { return len(h) }
func (h IntHeap) Less(i, j int) bool { return h[i] > h[j] }
func (h IntHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *IntHeap) Push(x interface{}) {
	*h = append(*h, x.(int64))
}

func (h *IntHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func solve() {
	var n int
	fmt.Scan(&n)

	a := make([]int64, n)
	var sum int64 = 0
	h := &IntHeap{}
	heap.Init(h)

	for i := 0; i < n; i++ {
		fmt.Scan(&a[i])
	}

	sort.Slice(a, func(i, j int) bool {
		return a[i] < a[j]
	})

	for i := 0; i < n; i++ {
		sum += a[i]
	}
	heap.Push(h, sum)

	for i := n - 1; i >= 0; i-- {
		for (*h)[0] > a[i] {
			node := heap.Pop(h).(int64)

			if h.Len() > n {
				fmt.Println("NO")
				return
			}

			heap.Push(h, node/2)
			heap.Push(h, (node+1)/2)
		}

		if (*h)[0] < a[i] {
			fmt.Println("NO")
			return
		} else {
			heap.Pop(h)
		}
	}

	fmt.Println("YES")
}

func main() {
	var t int
	fmt.Scan(&t)

	for t > 0 {
		solve()
		t--
	}
}

