	data, _ := reader.ReadString('\n')
	return data
}

func parseInput() (int, []int) {
	n := 0
	fmt.Sscan(input(), &n)
	a := make([]int, n)
	line := input()
	for i, v := range line {
		fmt.Sscan(string(v), &a[i])
	}
	return n, a
}

func accumulateAbs(a []int) []int {
	acc := make([]int, len(a))
	for i := range a {
		if i == 0 {
			acc[i] = int(math.Abs(float64(a[i])))
		} else {
			acc[i] = int(math.Abs(float64(a[i]))) + acc[i-1]
		}
	}
	return acc
}

func leftMin(a []int) []int {
	lmin := make([]int, len(a))
	for i := range a {
		if i == 0 {
			lmin[i] = a[i]
		} else {
			lmin[i] = min(a[i], lmin[i-1])
		}
	}
	return lmin
}

func rightMin(a []int) []int {
	rmin := make([]int, len(a))
	for i := len(a) - 1; i >= 0; i-- {
		if i == len(a)-1 {
			rmin[i] = a[i]
		} else {
			rmin[i] = min(a[i], rmin[i+1])
		}
	}
	return rmin
}

func min(x, y int) int {
	if x < y {
		return x
	}
	return y
}

func main() {
	n, a := parseInput()
	acc := accumulateAbs(a)
	left := leftMin(a)
	right := rightMin(a)
	ans := -2000000000 // -10 ** 9 * 2
	for i := 0; i < n; i++ {
		val := a[i]
		if i > 0 {
			if left[i-1] < 0 {
				val += acc[i-1]
			} else {
				val += acc[i-1] - left[i-1]*2
			}
		}
		if i < n-1 {
			if right[i+1] < 0 {
				val += acc[n-1] - acc[i]
			} else {
				val += acc[n-1] - acc[i] - right[i+1]*2
			}
		}
		if val > ans {
			ans = val
		}
	}
	fmt.Println(ans)
}

