		var n int
		fmt.Fscan(reader, &n)

		line, _ := reader.ReadString('\n')
		line = strings.TrimSpace(line)
		k := strToIntSlice(line)

		maxi := findMax(k)
		mini := findMin(k)
		result := calculateResult(k, maxi, mini, n)
		fmt.Println(result)
	}
}

func strToIntSlice(s string) []int {
	strs := strings.Fields(s)
	ints := make([]int, len(strs))
	for i := 0; i < len(strs); i++ {
		fmt.Sscan(strs[i], &ints[i])
	}
	return ints
}

func findMax(arr []int) int {
	maxVal := arr[0]
	for _, value := range arr {
		if value > maxVal {
			maxVal = value
		}
	}
	return maxVal
}

func findMin(arr []int) int {
	minVal := arr[0]
	for _, value := range arr {
		if value < minVal {
			minVal = value
		}
	}
	return minVal
}

func calculateResult(k []int, maxi int, mini int, n int) int {
	countMax := countOccurrences(k, maxi)
	countMin := countOccurrences(k, mini)

	if maxi != mini {
		return 2 * (countMax * countMin)
	} else {
		return n * (n - 1)
	}
}

func countOccurrences(arr []int, value int) int {
	count := 0
	for _, v := range arr {
		if v == value {
			count++
		}
	}
	return count
}

