var in *Reader
var out *bufio.Writer

func main() {
	in = NewReader()
	out = bufio.NewWriter(os.Stdout)

	t := in.NextInt()
	for i := 0; i < t; i++ {
		run()
	}

	out.Flush()
	in.Close()
}

func run() {
	n := in.NextInt()
	a := make([]int, n+1)
	for i := 1; i <= n; i++ {
		a[i] = -1
	}

	three := make([]int, n-2+1)
	last := [2]int{-1, -1}

	for i := 1; i <= n-2; i += 3 {
		three[i] = query(i, i+1, i+2)
		last[three[i]] = i
	}

	pos := findZeroAndOnePos(last)
	a[pos[1]] = 1

	for i := 1; i <= n-2; i += 3 {
		diffPos := pos[three[i]^1]
		first := query(i, i+1, diffPos)
		second := query(i+1, i+2, diffPos)

		if three[i] == first && three[i] == second {
			a[i] = three[i]
			a[i+1] = three[i]
			a[i+2] = three[i]
		} else if three[i] != first && three[i] == second {
			a[i] = three[i] ^ 1
			a[i+1] = three[i]
			a[i+2] = three[i]
		} else if three[i] == first && three[i] != second {
			a[i] = three[i]
			a[i+1] = three[i]
			a[i+2] = three[i] ^ 1
		} else if three[i] != first && three[i] != second {
			a[i] = three[i]
			a[i+1] = three[i] ^ 1
			a[i+2] = three[i]
		}
	}

	k := n
	for i := 1; i <= n; i++ {
		k -= a[i]
	}

	fmt.Fprint(out, "! ", k, " ")
	for i := 1; i <= n; i++ {
		if a[i] == 0 {
			fmt.Fprint(out, i, " ")
		}
	}
	fmt.Fprintln(out)
}

func findZeroAndOnePos(last [2]int) [2]int {
	pos := [2]int{-1, -1}

	if last[0] == -1 || last[1] == -1 {
		target := 0
		if last[0] != -1 {
			target = 1
		}
		for i := 1; i <= 2; i++ {
			if query(i, 4, 5) == target || query(i, 5, 6) == target {
				pos[target] = i
				pos[target^1] = 3
				return pos
			}
		}
		pos[target] = 3
		pos[target^1] = 1
		return pos
	}

	first := query(last[0]+1, last[0]+2, last[1])
	second := query(last[0]+2, last[1], last[1]+1)

	if first == 1 {
		pos[0] = last[0]
		pos[1] = last[1]
	} else if second == 1 {
		pos[0] = last[0] + 1
		pos[1] = last[1] + 1
	} else {
		pos[0] = last[0] + 2
		pos[1] = last[1] + 2
	}
	return pos
}

func query(a, b, c int) int {
	fmt.Fprint(out, "? ", a, " ", b, " ", c, "\n")
	out.Flush()
	return in.NextInt()
}

