    "os"
)

func main() {
    reader := bufio.NewReader(os.Stdin)
    var k, A, h int
    fmt.Fscan(reader, &k, &A, &h)

    team := 1 << k
    mod := 998244353
    POW := make([]int, 101)
    POW[0] = 1

    for i := 1; i < 100; i++ {
        POW[i] = (POW[i-1] * A) % mod
    }

    ANS := make([]int, team/2)
    for i := range ANS {
        ANS[i] = (1 << (k - 1)) + 1
    }

    X := make([]int, team/2)
    for i := 0; i < team/2; i++ {
        X[i] = i
    }
    ALLLIST := [][]int{}

    half_all(ANS, X, []int{}, k-1, &ALLLIST)

    SCORE01 := make([]int, len(ALLLIST))
    SCORE02 := make([]int, len(ALLLIST))
    SCORE11 := make([]int, len(ALLLIST))
    SCORE12 := make([]int, len(ALLLIST))

    for i := range ALLLIST {
        LIST := ALLLIST[i]
        sc01, sc02 := 0, 0
        sc11, sc12 := 0, 0

        for j := 0; j < team/2; j++ {
            if LIST[j] != 2 {
                sc01 += (j + 1) * POW[LIST[j]] % mod
                sc02 += (j + 1) * POW[LIST[j]] % mod
                sc01 %= mod
                sc02 %= mod
                sc11 += (j + 1 + team/2) * POW[LIST[j]] % mod
                sc12 += (j + 1 + team/2) * POW[LIST[j]] % mod
                sc11 %= mod
                sc12 %= mod
            } else {
                sc01 += (j + 1) * POW[1] % mod
                sc02 += (j + 1) * POW[2] % mod
                sc01 %= mod
                sc02 %= mod
                sc11 += (j + 1 + team/2) * POW[1] % mod
                sc12 += (j + 1 + team/2) * POW[2] % mod
                sc11 %= mod
                sc12 %= mod
            }
        }

        SCORE01[i] = sc01
        SCORE02[i] = sc02
        SCORE11[i] = sc11
        SCORE12[i] = sc12
    }

    SCSET11 := make(map[int]struct{})
    SCSET12 := make(map[int]struct{})

    for _, score := range SCORE11 {
        SCSET11[score] = struct{}{}
    }
    for _, score := range SCORE12 {
        SCSET12[score] = struct{}{}
    }

    for i := range ALLLIST {
        if _, ok := SCSET12[(h-SCORE01[i])%mod]; ok {
            k := index_of(SCORE12, (h-SCORE01[i])%mod)
            LANS := append(ALLLIST[i], ALLLIST[k]...)
            fix_two_in_LANS(&LANS)
            fmt.Println(LANS)
            return
        }
        if _, ok := SCSET11[(h-SCORE02[i])%mod]; ok {
            k := index_of(SCORE11, (h-SCORE02[i])%mod)
            LANS := append(ALLLIST[i], ALLLIST[k]...)
            fix_two_in_LANS_reverse(&LANS)
            fmt.Println(LANS)
            return
        }
    }

    fmt.Println(-1)
}

func half_all(ANS []int, X []int, Y []int, i int, ALLLIST *[][]int) {
    if i == 0 {
        *ALLLIST = append(*ALLLIST, append([]int{}, ANS...))
        return
    }
    if len(X) == 0 {
        X = Y
        Y = []int{}
        half_all(ANS, X, Y, i-1, ALLLIST)
        return
    }

    p := X[len(X)-1]
    X = X[:len(X)-1]
    q := X[len(X)-1]
    X = X[:len(X)-1]

    ANS[p] = ANS[p]/2 + 1
    half_all(ANS, X, append(Y, p), i, ALLLIST)
    ANS[p] = (ANS[p]*2 - 1)
    ANS[q] = ANS[q]/2 + 1
    half_all(ANS, X, append(Y, q), i, ALLLIST)
}

func index_of(arr []int, val int) int {
    for i, v := range arr {
        if v == val {
            return i
        }
    }
    return -1
}

func fix_two_in_LANS(LANS *[]int) {
    for j := range *LANS {
        if (*LANS)[j] == 2 {
            (*LANS)[j] = 1
            break
        }
    }
}

func fix_two_in_LANS_reverse(LANS *[]int) {
    for j := len(*LANS) - 1; j >= 0; j-- {
        if (*LANS)[j] == 2 {
            (*LANS)[j] = 1
            break
        }
    }
}

