func main() {
	reader := bufio.NewReader(os.Stdin)
	var t int
	fmt.Fscan(reader, &t)

	dic := map[string]int{
		"sunday":    2,
		"monday":    3,
		"tuesday":   4,
		"wednesday": 5,
		"thursday":  6,
		"friday":    7,
		"saturday":  1,
	}

	for i := 0; i < t; i++ {
		weekStart, weekEnd, lStr, rStr := readInput(reader)
		l, r := parseLimits(lStr, rStr)

		rem := calculateRem(dic, weekStart, weekEnd)
		mrem := l % 7
		l = adjustL(l, rem, mrem)

		result := checkRange(l, r)
		printResult(result, l, r)
	}
}

func readInput(reader *bufio.Reader) (string, string, string, string) {
	var ws, we, l, r string
	fmt.Fscan(reader, &ws, &we, &l, &r)
	return ws, we, l, r
}

func parseLimits(lStr string, rStr string) (int, int) {
	l := 0
	r := 0
	fmt.Sscanf(lStr, "%d", &l)
	fmt.Sscanf(rStr, "%d", &r)
	return l, r
}

func calculateRem(dic map[string]int, ws string, we string) int {
	rem := (7 - dic[ws] + 1 + dic[we]) % 7
	return rem
}

func adjustL(l int, rem int, mrem int) int {
	if mrem <= rem {
		l += rem - mrem
	} else {
		l += 7 - mrem + rem
	}
	return l
}

func checkRange(l int, r int) string {
	if l <= r {
		if l + 7 <= r {
			return "many"
		} else {
			return "single"
		}
	} else {
		return "impossible"
	}
}

func printResult(result string, l int, r int) {
	if result == "many" {
		fmt.Println("many")
	} else if result == "single" {
		fmt.Println(l)
	} else {
		fmt.Println("impossible")
	}
}

