func chooseAndSwap(A string) string {
	s := make(map[rune]struct{})
	for _, e := range A {
		s[e] = struct{}{}
	}

	for _, e := range A {
		for p := 'a'; p < e; p++ {
			if _, ok := s[p]; ok {
				return swapLetters(A, p, e)
			}
		}
		delete(s, e)
	}
	return A
}

func swapLetters(A string, x rune, y rune) string {
    tmp := []rune(A)
	for i, e := range tmp {
		tmp[i] = swap(e, x, y)
	}
	return string(tmp)
}

func swap(e rune, x rune, y rune) rune {
	if e == x {
		return y
	}
	if e == y {
		return x
	}
	return e
}

