func main() {
	reader := bufio.NewReader(os.Stdin)
	nm, _ := reader.ReadString('\n')
	var n, m int
	fmt.Sscan(nm, &n, &m)

	xs := make([]string, n)
	for i := 0; i < n; i++ {
		line, _ := reader.ReadString('\n')
		xs[i] = strings.TrimSpace(line)
	}

	rxs := make([]string, n)
	for i := 0; i < n; i++ {
		rxs[i] = reverse(xs[i])
	}

	oans := ""
	for _, x := range xs {
		if isPalindrome(x) {
			oans = x
			break
		}
	}

	ans := []string{}
	rans := []string{}

	for i, x := range xs {
		for _, rx := range rxs[i + 1:] {
			if x == rx {
				ans = append(ans, x)
				rans = append(rans, reverse(x))
			}
		}
	}

	if len(ans) == 0 {
		ans = append(ans, oans)
	} else if oans != "" && !contains(ans, oans) {
		ans = append(ans, oans)
		ans = append(ans, reverseSlice(rans)...)
	} else {
		ans = append(ans, reverseSlice(rans)...)
	}

	result := strings.Join(ans, "")
	fmt.Println(len(result))
	fmt.Println(result)
}

func reverse(s string) string {
	n := len(s)
	r := make([]rune, n)
	for i, c := range s {
		r[n-1-i] = c
	}
	return string(r)
}

func isPalindrome(s string) bool {
	return s == reverse(s)
}

func contains(slice []string, item string) bool {
	for _, v := range slice {
		if v == item {
			return true
		}
	}
	return false
}

func reverseSlice(slice []string) []string {
	n := len(slice)
	result := make([]string, n)
	for i, v := range slice {
		result[n-1-i] = v
	}
	return result
}

