type TreeNode struct {
	val   int
	left  *TreeNode
	right *TreeNode
}

func maxPathSum(root *TreeNode, cache map[*TreeNode]int) int {
	if _, found := cache[root]; found {
		return cache[root]
	}
	if root == nil {
		cache[root] = 0
		return 0
	}
	left := maxPathSum(root.left, cache)
	right := maxPathSum(root.right, cache)
	cache[root] = max(left, right) + root.val
	return cache[root]
}

func help(root *TreeNode, limit int, acc *int, cache map[*TreeNode]int) {
	if root == nil {
		return
	}
	*acc += root.val
	if maxPathSum(root.left, cache)+*acc < limit {
		root.left = nil
	}
	if maxPathSum(root.right, cache)+*acc < limit {
		root.right = nil
	}
	help(root.left, limit, acc, cache)
	help(root.right, limit, acc, cache)
	*acc -= root.val
}

func sufficientSubset(root *TreeNode, limit int) *TreeNode {
	temp := &TreeNode{val: 0}
	temp.left = root
	cache := make(map[*TreeNode]int)
	acc := 0
	help(temp, limit, &acc, cache)
	return temp.left
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	var n, val int
	fmt.Fscan(reader, &n)
	var nodes []*TreeNode
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &val)
		nodes = append(nodes, &TreeNode{val: val})
	}
	for i := 0; i < n/2; i++ {
		if 2*i+1 < n {
			nodes[i].left = nodes[2*i+1]
		}
		if 2*i+2 < n {
			nodes[i].right = nodes[2*i+2]
		}
	}
	var limit int
	fmt.Fscan(reader, &limit)
	result := sufficientSubset(nodes[0], limit)
	printTree(result)
}

func printTree(root *TreeNode) {
	if root == nil {
		return
	}
	fmt.Print(root.val, " ")
	printTree(root.left)
	printTree(root.right)
}

