		n := toInt(s[0])
		k := toInt(s[1])
		count := 0

		s = readString(reader)
		d := float64(toInt(s[0])) / float64(k)

		if isInt(d) {
			count += int(d)
			x := d * float64(k) - float64(toInt(s[0]))
		} else {
			count += int(d) + 1
			x := (int(d) + 1) * k - toInt(s[0])
		}

		l := x
		j := 1
		for j < n {
			if l > 0 {
				l = l - 1
			}
			if l >= toInt(s[j]) {
				l = l - toInt(s[j])
				j += 1
				continue
			}
			l = toInt(s[j]) - l
			d = float64(l) / float64(k)
			if isInt(d) {
				count += int(d)
				l = d * float64(k) - float64(l)
			} else {
				count += int(d) + 1
				l = (int(d) + 1) * k - l
			}
			j += 1
		}
