func readInt(reader *bufio.Reader) int {
	line, _ := reader.ReadString('\n')
	n, _ := strconv.Atoi(line[:len(line)-1])
	return n
}

func readMatrix(reader *bufio.Reader, n int) [][]int {
	matrix := make([][]int, n)
	for i := 0; i < n; i++ {
		line, _ := reader.ReadString('\n')
		row := convertToIntSlice(line)
		matrix[i] = row
	}
	return matrix
}

func convertToIntSlice(line string) []int {
	words := make([]int, 0)
	temp := ""
	for _, ch := range line {
		if ch == ' ' || ch == '\n' {
			if temp != "" {
				num, _ := strconv.Atoi(temp)
				words = append(words, num)
				temp = ""
			}
		} else {
			temp += string(ch)
		}
	}
	if temp != "" {
		num, _ := strconv.Atoi(temp)
		words = append(words, num)
	}
	return words
}

func matrixDot(a [][]int, b [][]int, n int) [][]int {
	res := make([][]int, n)
	for i := 0; i < n; i++ {
		res[i] = make([]int, n)
		for j := 0; j < n; j++ {
			sum := 0
			for k := 0; k < n; k++ {
				sum += a[i][k] * b[k][j]
			}
			res[i][j] = sum
		}
	}
	return res
}

