	fmt.Println(result)
}

func minVal(a int, b int) int {
	// Convert b to binary and count the number of 1s
	B := strconv.FormatInt(int64(b), 2)
	b_one := countOnes(B)

	// Convert a to binary
	A := strconv.FormatInt(int64(a), 2)
	ans := make([]rune, len(A))

	// Fill the ans slice based on conditions
	for i := 0; i < len(A); i++ {
		if A[i] == '1' {
			if b_one > 0 {
				ans[i] = '1'
				b_one--
			} else {
				ans[i] = '0'
			}
		} else {
			ans[i] = '0'
		}
	}

	// Fill from the end if there are still 1s left to set
	for j := len(A) - 1; j >= 0; j-- {
		if ans[j] == '0' {
			if b_one > 0 {
				ans[j] = '1'
				b_one--
			}
		}
	}

	// If there are still 1s left, prepend them to ans
	if b_one > 0 {
		// Temporary array for the final binary representation
		var tmp []rune
		for b_one > 0 {
			tmp = append(tmp, '1')
			b_one--
		}
		ans = append(tmp, ans...) // concatenate
	}

	// Convert the binary representation back to an integer
	x := string(ans)
	return binaryToInt(x)
}

// Helper to count '1's in the string
func countOnes(s string) int {
	count := 0
	for _, char := range s {
		if char == '1' {
			count++
		}
	}
	return count
}

// Helper to convert binary string to integer
func binaryToInt(binStr string) int {
	result, _ := strconv.ParseInt(binStr, 2, 0)
	return int(result)
}

