func calc(grid [][]int, r int, c int, M int, N int) int {
	maxRange := min(r+1, c+1, M-c, N-r)
	k := 1
	temp := 0
	for k < maxRange {
		if grid[r-k][c] == grid[r+k][c] && grid[r][c-k] == grid[r][c+k] {
			temp += 1
		} else {
			return temp
		}
		k += 1
	}
	return temp
}

func min(a int, b int, c int, d int) int {
	tmp := a
	if b < tmp {
		tmp = b
	}
	if c < tmp {
		tmp = c
	}
	if d < tmp {
		tmp = d
	}
	return tmp
}

