		fmt.Fscan(reader, &N, &M)
		grid := make([][]int, N)
		for j := 0; j < N; j++ {
			grid[j] = make([]int, M)
			for k := 0; k < M; k++ {
				fmt.Fscan(reader, &grid[j][k])
			}
		}

		answer := 0
		for r := 1; r < N-1; r++ {
			for c := 1; c < M-1; c++ {
				answer += calc(grid, r, c, M, N)
			}
		}
		answer += M * N
		fmt.Println(answer)
	}
}

