		l[x[1]] = append(l[x[1]], x[0])
	}
	an := []int{}
	for i := 0; i < n; i++ {
		if !vi[i] {
			p1 := []int{}
			find(p1, i, l, vi)
			an = append(an, len(p1))
		}
