func calculateAverage(ps []int, n int) float64 {
    sum := 0
    for _, v := range ps {
        sum += v
    }
    average := float64(sum) / float64(n)
    return round(average)
}

func round(x float64) float64 {
    return math.Floor(x + 0.5)
}

func calculatePSig(ps []int, pave float64) float64 {
    psig := 0.0
    for _, p := range ps {
        diff := float64(p) - pave
        psig += diff * diff
    }
    return psig
}

