			result1 := doWork1(b, c, x, d, e)
			fmt.Println(result1)
		} else {
			result2 := doWork2(b, c, x, d, e)
			fmt.Println(result2)
		}
	}
}

func doWork1(b, c, x, d, e int) int {
	if x >= 1 {
		tmp1 := min(b, x)
		tmp2 := x - min(tmp1, x)
		return d * tmp1 + e * min(c, tmp2)
	}
	return 0
}

func doWork2(b, c, x, d, e int) int {
	if x >= 1 {
		tmp3 := min(c, x)
		tmp4 := x - min(b, tmp3)
		return tmp3 * e + d * min(b, tmp4)
	}
	return 0
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

