func avoidFlood(rains []int) []int {
	returnArr := make([]int, len(rains))
	for i := 0; i < len(returnArr); i++ {
		returnArr[i] = -1
	}
	rainsDict := make(map[int]int)
	zerosIndices := []int{}

	for i := 0; i < len(rains); i++ {
		if rains[i] == 0 {
			returnArr[i] = 1
			zerosIndices = append(zerosIndices, i)
		} else {
			if _, ok := rainsDict[rains[i]]; !ok {
				rainsDict[rains[i]] = i
			} else {
				if len(zerosIndices) == 0 {
					return []int{}
				}
				index := 0
				for zerosIndices[index] < rainsDict[rains[i]] {
					index++
					if index == len(zerosIndices) {
						return []int{}
					}
				}
				returnArr[zerosIndices[index]] = rains[i]
				rainsDict[rains[i]] = i
				zerosIndices = removeIndex(zerosIndices, index)
			}
		}
	}
	return returnArr
}

func removeIndex(s []int, index int) []int {
	if index < 0 || index >= len(s) {
		return s
	}
	return append(s[:index], s[index+1:]...)
}

