		var a, b int
		fmt.Fscan(reader, &a, &b)
		pairs[i] = []int{a, b}
	}
	result := validArrangement(pairs)
	for _, r := range result {
		fmt.Println(r)
	}
}

func validArrangement(pairs [][]int) [][]int {
	totalEdges := make(map[int]int)
	outgoing := make(map[int][]int)

	for i := 0; i < len(pairs); i++ {
		if _, exists := totalEdges[pairs[i][0]]; !exists {
			totalEdges[pairs[i][0]] = 0
		}

		if _, exists := totalEdges[pairs[i][1]]; !exists {
			totalEdges[pairs[i][1]] = 0
		}

		outgoing[pairs[i][0]] = append(outgoing[pairs[i][0]], i)
		totalEdges[pairs[i][0]]++
		totalEdges[pairs[i][1]]++
	}

	oddPoints := make([]int, 0)
	for k, v := range totalEdges {
		if v%2 == 1 {
			oddPoints = append(oddPoints, k)
		}
	}

	path := make([]int, 0)

	if len(oddPoints) == 2 {
		if len(outgoing[oddPoints[0]])*2 > totalEdges[oddPoints[0]] {
			path = append(path, oddPoints[0])
		} else {
			path = append(path, oddPoints[1])
		}
		for len(outgoing[path[len(path)-1]]) > 0 {
			nextVert := pairs[outgoing[path[len(path)-1]][len(outgoing[path[len(path)-1]])-1]][1]
			outgoing[path[len(path)-1]] = outgoing[path[len(path)-1]][:len(outgoing[path[len(path)-1]])-1]
			path = append(path, nextVert)
		}
	} else {
		path = append(path, pairs[0][0])
	}

	flag := true
	for flag {
		newRoot := -1
		for i := 0; i < len(path); i++ {
			if len(outgoing[path[i]]) > 0 {
				newRoot = i
				break
			}
		}
		if newRoot == -1 {
			flag = false
		} else {
			temppath := []int{path[newRoot]}
			for len(outgoing[temppath[len(temppath)-1]]) > 0 {
				nextVert := pairs[outgoing[temppath[len(temppath)-1]][len(outgoing[temppath[len(temppath)-1]])-1]][1]
				outgoing[temppath[len(temppath)-1]] = outgoing[temppath[len(temppath)-1]][:len(outgoing[temppath[len(temppath)-1]])-1]
				temppath = append(temppath, nextVert)
			}
			path = append(path[:newRoot+1], append(temppath[1:], path[newRoot+1:]...)...) 
		}
	}

	ans := make([][]int, 0)
	for i := 0; i < len(path)-1; i++ {
		nextEdge := []int{path[i], path[i+1]}
		ans = append(ans, nextEdge)
	}

	return ans
}

