	exams := make([][2]int, 0)

	for i := 0; i < n; i++ {
		a, b := readInts(reader)
		cur_sum += a
		if a < r {
			exams = append(exams, [2]int{a, b})
		}
	}

	if cur_sum/n >= avg {
		fmt.Println(0)
		return
	}

	sort.Slice(exams, func(i, j int) bool {
		return exams[i][1] < exams[j][1]
	})

	req_sum := avg * n
	d := req_sum - cur_sum
	added := 0
	pos := 0

	for {
		if pos >= len(exams) {
			break
		}

		a, b := exams[pos][0], exams[pos][1]
		z := r - a

		if z >= d {
			added += d * b
			fmt.Println(added)
			return
		}

		if z < d {
			added += z * b
			pos++
			d -= z
		}
	}
