	strs := strings.Fields(input)
	n := make([]int, len(strs))

	for i := 0; i < len(strs); i++ {
		n[i], _ = strconv.Atoi(strs[i])
	}

	result := doLogic(n)
	fmt.Println(result)
}

func doLogic(n []int) string {
	if len(n) < 2 {
		return "-1"
	}

	if n[0] == n[1] {
		return handleEqual(n[0], n[1])
	} else if n[1] - n[0] == 1 {
		return handleAdjacent(n[0], n[1])
	} else if n[1] == 1 && n[0] == 9 {
		return handleSpecialCase(n[0])
	} else {
		return handleDefault()
	}
}

func handleEqual(a int, b int) string {
	tmpA := strconv.Itoa(a)
	tmpB := strconv.Itoa(b)
	return tmpA + "1 " + tmpB + "2"
}

func handleAdjacent(a int, b int) string {
	tmpA := strconv.Itoa(a)
	tmpB := strconv.Itoa(b)
	return tmpA + "9 " + tmpB + "0"
}

func handleSpecialCase(a int) string {
	return strconv.Itoa(a) + " 10"
}

func handleDefault() string {
	return "-1"
}

