        node /= 2
    }

    return reverseSlice(result)
}

func reverseSlice(data []int) []int {
    n := len(data)
    tmp := make([]int, n)

    for i := 0; i < n; i++ {
        tmp[i] = data[n - 1 - i]
    }

    return tmp
}

