func nextPowerOf2(n int) int {
    p := 1
    if (n > 0 && (n & (n - 1)) == 0) {
        return n
    }
    for p < n {
        p <<= 1
    }
    return p
}

func update(st []int, k int, x int, n int) {
    k += n
    st[k] += x
    k /= 2
    for k >= 1 {
        st[k] = st[2*k] + st[2*k+1]
        k /= 2
    }
}

func query(st []int, qa int, qb int, a int, b int, i int) int {
    if qa <= a && b <= qb {
        return st[i]
    }
    if qb < a || qa > b {
        return 0
    }
    mid := a + (b-a)/2
    left := query(st, qa, qb, a, mid, 2*i)
    right := query(st, qa, qb, mid+1, b, 2*i+1)
    return left + right
}

func main() {
    reader := bufio.NewReader(os.Stdin)
    var t int
    fmt.Fscan(reader, &t)

    for ; t > 0; t-- {
        var n int
        fmt.Fscan(reader, &n)
        n = nextPowerOf2(n)

        a := make([]int, n)
        var size int
        for i := 0; i < n; i++ {
            if i < n {
                fmt.Fscan(reader, &a[i])
                size++
            }
        }

        C := make(map[int]int)
        tmpArray := make([]int, size)
        copy(tmpArray, a[:size])
        sort.Ints(tmpArray)

        for i, v := range tmpArray {
            C[v] = i
        }

        st := make([]int, 2*n)

        ans := 0
        for _, num := range a[:size] {
            leftQuery := query(st, 1, C[num], 1, n, 1)
            rightQuery := query(st, C[num]+2, n, 1, n, 1)
            ans += min(leftQuery, rightQuery)
            update(st, C[num], 1, n)
        }

        fmt.Println(ans)
    }
}

