var tree map[int][]int
var guess map[[2]int]bool

func dfs1() int {
	seen := make(map[int]bool)
	seen[1] = true
	stack := []int{1}
	count := 0
	for len(stack) > 0 {
		node := stack[len(stack)-1]
		stack = stack[:len(stack)-1]
		for _, child := range tree[node] {
			if !seen[child] {
				seen[child] = true
				if guess[[2]int{node, child}] {
					count++
				}
				stack = append(stack, child)
			}
		}
	}
	return count
}

func dfs2(cost, k int) int {
	seen := make(map[int]bool)
	seen[1] = true
	stack := [][2]int{{1, cost}}
	t_win := 0
	for len(stack) > 0 {
		nodeCost := stack[len(stack)-1]
		stack = stack[:len(stack)-1]
		node, cost := nodeCost[0], nodeCost[1]
		if cost >= k {
			t_win++
		}
		for _, child := range tree[node] {
			if !seen[child] {
				seen[child] = true
				newCost := cost - boolToInt(guess[[2]int{node, child}]) + boolToInt(guess[[2]int{child, node}])
				stack = append(stack, [2]int{child, newCost})
			}
		}
	}
	return t_win
}

func boolToInt(b bool) int {
	if b {
		return 1
	}
	return 0
}

func readInput() (int, []int) {
	var t int
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Scan()
	t, _ = strconv.Atoi(scanner.Text())
	var testCases []int
	for i := 0; i < t; i++ {
		scanner.Scan()
		n, _ := strconv.Atoi(scanner.Text())
		testCases = append(testCases, n)
		tree = make(map[int][]int)
		for j := 0; j < n-1; j++ {
			scanner.Scan()
			u, v := splitInts(scanner.Text())
			tree[u] = append(tree[u], v)
			tree[v] = append(tree[v], u)
		}
		var g, k int
		scanner.Scan()
		g, k = splitInts(scanner.Text())
		guess = make(map[[2]int]bool)
		for j := 0; j < g; j++ {
			scanner.Scan()
			a, b := splitInts(scanner.Text())
			guess[[2]int{a, b}] = true
		}
		cost := dfs1()
		win := dfs2(cost, k)
		testCases = append(testCases, win, n)
	}
	return t, testCases
}

func splitInts(s string) (int, int) {
	parts := strings.Fields(s)
	a, _ := strconv.Atoi(parts[0])
	b, _ := strconv.Atoi(parts[1])
	return a, b
}

func gcd(a, b int) int {
	if b == 0 {
		return a
	}
	return gcd(b, a%b)
}

