func main() {
	reader := bufio.NewReader(os.Stdin)
	line1, _ := reader.ReadString('\n')
	line1 = strings.TrimSpace(line1)

	// Split and parse N and M
	parts := strings.Split(line1, " ")
	N, _ := strconv.Atoi(parts[0])
	M, _ := strconv.Atoi(parts[1])

	SC := make([][2]int, M)

	// Reading the next M lines for SC
	for i := 0; i < M; i++ {
		line, _ := reader.ReadString('\n')
		line = strings.TrimSpace(line)
		pairs := strings.Split(line, " ")
		si, _ := strconv.Atoi(pairs[0])
		ci, _ := strconv.Atoi(pairs[1])
		SC[i] = [2]int{si, ci}
	}

	// Now we need to find the answer
	found := false

	for i := 0; i < 10000000000; i++ {
		ans := strconv.Itoa(i)
		if len(ans) != N {
			continue
		}
		if checkConditions(ans, SC) {
			fmt.Println(ans)
			found = true
			break
		}
	}

	if !found {
		fmt.Println(-1)
	}
}

func checkConditions(ans string, sc [][2]int) bool {
	for _, pair := range sc {
		si, ci := pair[0], pair[1]
		if int(ans[si-1]-'0') != ci {
			return false
		}
	}
	return true
}

