const BUFSIZE = 8192

type FastIO struct {
	_      int
	file   *os.File
	buffer *bytes.Buffer
	write  bool
	newln  int
}

func NewFastIO(f *os.File) *FastIO {
	return &FastIO{
		file:   f,
		buffer: new(bytes.Buffer),
		write:  f.Mode()&os.O_WRONLY != 0 || f.Mode()&os.O_RDWR != 0,
	}
}

func (fio *FastIO) read() []byte {
	for {
		b := make([]byte, BUFSIZE)
		n, err := fio.file.Read(b)
		if err != nil || n == 0 {
			break
		}
		fio.buffer.Write(b[:n])
	}
	return fio.buffer.Bytes()
}

func (fio *FastIO) readline() []byte {
	for fio.newln == 0 {
		b := make([]byte, BUFSIZE)
		n, err := fio.file.Read(b)
		if err != nil || n == 0 {
			break
		}
		fio.newln = bytes.Count(b[:n], []byte{'\n'}) + 1
		fio.buffer.Write(b[:n])
	}
	fio.newln--
	return fio.buffer.Bytes()
}

func (fio *FastIO) flush() {
	if fio.write {
		fio.file.Write(fio.buffer.Bytes())
		fio.buffer.Reset()
	}
}

type IOWrapper struct {
	fio *FastIO
}

func NewIOWrapper(f *os.File) *IOWrapper {
	fio := NewFastIO(f)
	return &IOWrapper{fio: fio}
}

func (io *IOWrapper) write(s string) {
	io.fio.buffer.WriteString(s)
}

func (io *IOWrapper) read() []byte {
	return io.fio.read()
}

func (io *IOWrapper) readline() []byte {
	return io.fio.readline()
}

var input = func() []byte {
	return NewIOWrapper(os.Stdin).readline()
}

var rstr = func() string {
	return string(input())
}

var rints = func() []int {
	data := rstr()
	return convertToIntSlice(data)
}

func convertToIntSlice(data string) []int {
	var ints []int
	var buffer bytes.Buffer
	for i := 0; i < len(data); i++ {
		if data[i] == ' ' || data[i] == '\n' {
			if buffer.Len() > 0 {
				val := buffer.String()
				buffer.Reset()
				intValue := simpleAtoi(val)
				ints = append(ints, intValue)
			}
		} else {
			buffer.WriteByte(data[i])
		}
	}
	if buffer.Len() > 0 {
		val := buffer.String()
		intValue := simpleAtoi(val)
		ints = append(ints, intValue)
	}
	return ints
}

func simpleAtoi(s string) int {
	var n int
	for i := 0; i < len(s); i++ {
		n = n*10 + int(s[i]-'0')
	}
	return n
}

func main() {
