	div, mod := su/n, su%n

	for j := n - 1; j >= 0; j-- {
		ext := 0
		if n-j <= mod {
			ext = 1
		}
		for numbers[j] > div+ext {
			rem0, rem1 := div+ext-numbers[be], numbers[j]-div-ext
			if rem0 < rem1 {
				numbers[j] -= rem0
				be += 1
				ans += rem0
			} else if rem1 == rem0 {
				ans += rem0
				be += 1
				break
			} else {
				ans += rem1
				numbers[be] += rem1
				break
			}
		}
	}

	fmt.Println(ans)
}

