func splitToInts(input string) []int {
	parts := make([]int, 0)
	tmp := ""
	for _, r := range input {
		if r == ' ' || r == '\n' {
			if tmp != "" {
				val, _ := strconv.Atoi(tmp)
				parts = append(parts, val)
				tmp = ""
			}
		} else {
			tmp += string(r)
		}
	}
	if tmp != "" {
		val, _ := strconv.Atoi(tmp)
		parts = append(parts, val)
	}
	return parts
}

