	for i := 0; i < 6; i++ {
		for i1 := i + 1; i1 < 6; i1++ {
			for i2 := i1 + 1; i2 < 6; i2++ {
				tmpSum := a[i] + a[i1] + a[i2]
				if 2 * tmpSum == s {
					return true
				}
			}
		}
	}
	return false
}

