)

func main() {
    reader := bufio.NewReader(os.Stdin)
    // Read input
    inputStr := readInput(reader)

    // Split the input into parts
    inputs := splitInput(inputStr)
    if len(inputs) < 2 {
        return
    }
    str := inputs[0]
    length := toInt(inputs[1])

    // Get permutations
    permuts := getPermutations(str, length)

    // Sort the permutations
    sort.Strings(permuts)

    // Print the permutations
    printPermutations(permuts)
}

func readInput(reader *bufio.Reader) string {
    input, _ := reader.ReadString('\n')
    return input
}

func splitInput(inputStr string) []string {
    var result []string
    temp := ""
    for i := 0; i < len(inputStr); i++ {
        if inputStr[i] == ' ' || inputStr[i] == '\n' {
            if temp != "" {
                result = append(result, temp)
                temp = ""
            }
        } else {
            temp += string(inputStr[i])
        }
    }
    if temp != "" {
        result = append(result, temp)
    }
    return result
}

func toInt(str string) int {
    var num int
    fmt.Sscanf(str, "%d", &num)
    return num
}

func getPermutations(s string, length int) []string {
    if length > len(s) {
        return []string{}
    }
    res := []string{}
    used := make([]bool, len(s))
    temp := make([]byte, 0, length)

    backtrack(s, used, temp, length, &res)
    return res
}

func backtrack(s string, used []bool, temp []byte, length int, res *[]string) {
    if len(temp) == length {
        *res = append(*res, string(temp))
        return
    }

    for i := 0; i < len(s); i++ {
        if used[i] {
            continue
        }
        used[i] = true
        temp = append(temp, s[i])
        backtrack(s, used, temp, length, res)
        temp = temp[:len(temp)-1]
        used[i] = false
    }
}

func printPermutations(permutations []string) {
    for _, p := range permutations {
        fmt.Println(p)
    }
}

