func cal(l1, r1, u1, d1 int) int {
	k1 := int(math.Log2(float64(r1 - l1 + 1)))
	k2 := int(math.Log2(float64(d1 - u1 + 1)))

	// Maximum value with four potential checks
	return max(s[k1][k2][r1][d1], 
		s[k1][k2][r1][u1+(1<<k2)-1], 
		s[k1][k2][l1+(1<<k1)-1][d1], 
		s[k1][k2][l1+(1<<k1)-1][u1+(1<<k2)-1])
}

func max(x ...int) int {
	m := x[0]
	for _, v := range x {
		if v > m {
			m = v
		}
	}
	return m
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var n, m int
	if _, err := fmt.Fscan(reader, &n, &m); err != nil {
		log.Fatal(err)
	}

	for x := 1; x <= n; x++ {
		for y := 1; y <= m; y++ {
			if _, err := fmt.Fscan(reader, &a[x][y]); err != nil {
				log.Fatal(err)
			}
			if a[x][y] == 1 {
				u[x][y] = u[x-1][y] + 1
				l[x][y] = l[x][y-1] + 1
				mx[x][y] = min(min(mx[x-1][y-1]+1, u[x][y]), l[x][y])
			}
			s[0][0][x][y] = mx[x][y]
		}
	}

	for k1 := 0; k1 <= 10; k1++ {
		for x := (1 << k1); x <= n; x++ {
			if k1 != 0 {
				for y := 1; y <= m; y++ {
					s[k1][0][x][y] = max(s[k1-1][0][x-(1<<k1-1)][y], s[k1-1][0][x][y])
				}
			}
			for k2 := 1; k2 <= 10; k2++ {
				for y := (1 << k2); y <= m; y++ {
					s[k1][k2][x][y] = max(s[k1][k2-1][x][y-(1<<k2-1)], s[k1][k2-1][x][y])
				}
			}
		}
	}

	var t int
	if _, err := fmt.Fscan(reader, &t); err != nil {
		log.Fatal(err)
	}
	for i := 0; i < t; i++ {
		var x1, y1, x2, y2 int
		if _, err := fmt.Fscan(reader, &x1, &y1, &x2, &y2); err != nil {
			log.Fatal(err)
		}
		l1 := 1
		r1 := min(x2-x1+1, y2-y1+1)
		ans := 0
		for l1 <= r1 {
