func gcd(a int64, b int64) int64 {
	if a == 0 {
		return b
	}
	return gcd(b%a, a)
}

func lcm(a int64, b int64) int64 {
	return a * (b / gcd(a, b))
}

func f(grid [][]int, k int, adj [][]int) (int, int) {
	n := len(grid)
	m := len(grid[0])
	cnt := make([]int, 1<<m)
	for i := 0; i < len(cnt); i++ {
		cnt[i] = -1
	}
	for i := 0; i < n; i++ {
		mask := 0
		for j := 0; j < m; j++ {
			if grid[i][j] >= k {
				mask |= (1 << j)
			}
		}
		cnt[mask] = i
		for _, v := range adj[mask] {
			if cnt[v] != -1 {
				return i, cnt[v]
			}
		}
	}
	return -1, -1
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	var n, m int
	fmt.Fscan(reader, &n, &m)
	M := 1 << m
	adj := make([][]int, M)
	for i := 0; i < M; i++ {
		for j := 0; j < M; j++ {
			if (i|j) == (M-1) {
				adj[i] = append(adj[i], j)
			}
		}
	}

	grid := make([][]int, n)
	for i := 0; i < n; i++ {
		grid[i] = make([]int, m)
		for j := 0; j < m; j++ {
			fmt.Fscan(reader, &grid[i][j])
		}
	}

	l := 0
	r := int(1e9)
	for l <= r {
		mid := l + (r-l)/2
		if f(grid, mid, adj).first != -1 {
			l = mid + 1
		} else {
			r = mid - 1
		}
	}
	ans := f(grid, r, adj)
	fmt.Println(ans.first+1, ans.second+1)
}

