func splitInts(line string) []int {
	res := []int{}
	numStrs := bufio.NewScanner(bufio.NewReaderString(line))
	numStrs.Split(bufio.ScanWords)

	for numStrs.Scan() {
		num, _ := strconv.Atoi(numStrs.Text())
		res = append(res, num)
	}

	return res
}

func findK(S map[int]struct{}) int {
	ans := -1
	for k := 1; k < 1025; k++ {
		T := createXorSet(S, k)
		if equalSets(S, T) {
			ans = k
			break
		}
	}
	return ans
}

func createXorSet(S map[int]struct{}, k int) map[int]struct{} {
	T := make(map[int]struct{})
	for s := range S {
		T[s^k] = struct{}{}
	}
	return T
}

func equalSets(S1, S2 map[int]struct{}) bool {
	if len(S1) != len(S2) {
		return false
	}
	for s := range S1 {
		if _, exists := S2[s]; !exists {
			return false
		}
	}
	return true
}

