func doWork1(x int, y int, n int) int {
	if n < x {
		return y
	}

	if n % x == y {
		return n
	}

	r := n % x
	return doWork2(r, y, n, x)
}

func doWork2(r int, y int, n int, x int) int {
	if r >= y {
		n = n - (r - y)
	} else {
		n = n - (n % x)
		n = n - (x - y)
	}

	return n // Final result
}

