func main() {
	reader := bufio.NewReader(os.Stdin)
	var N int
	fmt.Fscan(reader, &N)
	edges := make([][2]int, 0)
	for {
		var a, b int
		if _, err := fmt.Fscan(reader, &a, &b); err != nil {
			break
		}
		edges = append(edges, [2]int{a, b})
	}
	result := sumOfDistancesInTree(N, edges)
	for _, val := range result {
		fmt.Print(val, " ")
	}
}

func sumOfDistancesInTree(N int, edges [][2]int) []int {
	if N == 1 {
		return []int{0}
	}
	e := len(edges)
	memo := make([][2]int, e)
	memoc := make([][2]int, e)
	v2e := make(map[int][]int)
	for i := 0; i < e; i++ {
		a0 := edges[i][0]
		a1 := edges[i][1]
		if _, ok := v2e[a0]; !ok {
			v2e[a0] = []int{}
		}
		if _, ok := v2e[a1]; !ok {
			v2e[a1] = []int{}
		}
		v2e[a0] = append(v2e[a0], i)
		v2e[a1] = append(v2e[a1], i)
	}
	rst := make([]int, N)
	for i := 0; i < N; i++ {
		rst[i] = getNode(i, v2e, edges, memo, memoc)
	}
	return rst
}

func getNode(node int, v2e map[int][]int, edges [][2]int, memo [][2]int, memoc [][2]int) int {
	es := v2e[node]
	rst := 0
	for i := 0; i < len(es); i++ {
		dir := 0
		if edges[es[i]][0] != node {
			dir = 1
		}
		rst += calc(es[i], dir, v2e, edges, memo, memoc)[0]
	}
	return rst
}

func calc(e int, dir int, v2e map[int][]int, edges [][2]int, memo [][2]int, memoc [][2]int) [2]int {
	if memo[e][dir] > 0 {
		return [2]int{memo[e][dir], memoc[e][dir]}
	}
	nxtNode := edges[e][dir ^ 1] // switch 0 to 1 and 1 to 0
	es := v2e[nxtNode]
	rst := 0
	rstc := 0
	for i := 0; i < len(es); i++ {
		if es[i] == e {
			continue
		}
		ndir := 0
		if edges[es[i]][0] != nxtNode {
			ndir = 1
		}
		r := calc(es[i], ndir, v2e, edges, memo, memoc)
		rst += r[0]
		rstc += r[1]
	}
	rstc++
	rst += rstc
	memo[e][dir] = rst
	memoc[e][dir] = rstc
	return [2]int{memo[e][dir], memoc[e][dir]}
}

