func main() {
	reader := bufio.NewReader(os.Stdin)
	var T int
	fmt.Fscan(reader, &T)

	for i := 0; i < T; i++ {
		var n, k int
		fmt.Fscan(reader, &n, &k)

		list_num := make([]int, n)
		readInts(reader, list_num)

		list_remainder := make([]int, n)
		for j := 0; j < n; j++ {
			if list_num[j] % k == 0 {
				list_remainder[j] = 0
			} else {
				list_remainder[j] = k - list_num[j] % k
			}
		}

		dict_visit := make(map[int]int)
		ans := 0

		for j := 0; j < n; j++ {
			num := list_remainder[j]
			if num == 0 {
				continue
			}

			if _, exists := dict_visit[num]; !exists {
				dict_visit[num] = 1
				ans = max(ans, num + 1)
			} else {
				ans = max(ans, dict_visit[num] * k + num + 1)
				dict_visit[num] += 1
			}
		}
		fmt.Println(ans)
	}
}

