func splitString(s string) []string {
	words := []string{}
	start := 0
	for i, c := range s {
		if c == ' ' || c == '\n' {
			if start < i {
				words = append(words, s[start:i])
			}
			start = i + 1
		}
	}
	if start < len(s) {
		words = append(words, s[start:])
	}
	return words
}

