type ListNode struct {
	val  int
	next *ListNode
}

func swapkthnode(head *ListNode, total int, k int) *ListNode {
	pos1 := k
	pos2 := total + 1 - k
	var p1, n1, p2, n2 *ListNode
	curr := head
	curr_pos := 1

	for curr != nil {
		if curr_pos == pos1 - 1 {
			p1 = curr
		}
		if curr_pos == pos1 {
			n1 = curr
		}
		if curr_pos == pos2 - 1 {
			p2 = curr
		}
		if curr_pos == pos2 {
			n2 = curr
		}
		curr = curr.next
		curr_pos += 1
	}

	if n1 == nil || n2 == nil {
		return head
	}

	if p1 == nil {
		head = n2
	} else {
		p1.next = n2
	}

	if p2 == nil {
		head = n1
	} else {
		p2.next = n1
	}

	temp := n1.next
	n1.next = n2.next
	n2.next = temp

	return head
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	var n, k int

	fmt.Fscan(reader, &n, &k)
	var head *ListNode
	var tail *ListNode

	for i := 1; i <= n; i++ {
		node := &ListNode{val: i}
		if head == nil {
			head = node
			tail = node
		} else {
			tail.next = node
			tail = node
		}
	}

	head = swapkthnode(head, n, k)

	curr := head
	for curr != nil {
		fmt.Print(curr.val, " ")
		curr = curr.next
	}
}

