func solve(n int, arr []int) (int, []int) {
	ans := 0
	s := make(map[int]int)
	res := make([]int, n)
	lasts := [][]int{[]int{}, []int{}}

	for i, ch := range arr {
		lasts[ch] = append(lasts[ch], i)
		if s[ch^1] == 0 {
			ans += 1
			res[i] = ans
		} else {
			if len(lasts[ch^1]) > 0 {
				s[ch^1]--
				index := lasts[ch^1][len(lasts[ch^1])-1]
				lasts[ch^1] = lasts[ch^1][:len(lasts[ch^1])-1]
				res[i] = res[index]
			}
		}
		s[ch]++
	}
	return ans, res
}

