func longestPrefOnes(n int, s string) int {
	L := 0
	for L < n && s[L] == '1' {
		L++
	}
	R := L + 1
	mx := 0
	cur := 0

	for R < n {
		if s[R] == '0' {
			if cur > mx {
				mx = cur
			}
			cur = 0
		} else {
			cur++
		}
		R++
	}

	if cur > mx {
		mx = cur
	}
	return mx + L
}

