			tmp := q[0]
			q = q[1:]
			tmp.allcnt *= -1
			if A[a_ind] == tmp.key {
				keep = append(keep, tmp)
			} else {
				ans = append(ans, tmp.key)
				if tmp.bcnt - 1 > 0 {
					q = append(q, Item{-(tmp.allcnt - 1), tmp.bcnt - 1, tmp.key})
				}
				break
			}
		}
		for _, k := range keep {
			q = append(q, k)
		}
		a_ind++
	}

	for _, val := range ans {
		fmt.Print(val, " ")
	}
}

