func processLi(Li []int, N int) int {
	sort.Ints(Li)

	l := []int{}

	for _, v := range Li {
		count := countOccurrences(Li, v)
		if count % 2 != 0 {
			l = append(l, v)
		}
	}

	for _, v := range l {
		Li = append(Li, v)
	}

	if len(Li) % 4 == 0 {
		return len(Li) - N
	} else {
		return len(Li) - N + 2
	}
}

func countOccurrences(arr []int, x int) int {
	count := 0
	for _, v := range arr {
		if v == x {
			count++
		}
	}
	return count
