func main() {
	reader := bufio.NewReader(os.Stdin)
	var n int
	fmt.Fscan(reader, &n)
	edges := make([]int, n)
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &edges[i])
	}

	ans := countVisitedNodes(edges)
	for _, v := range ans {
		fmt.Print(v, " ")
	}
	fmt.Println()
}

func countVisitedNodes(edges []int) []int {
	n := len(edges)
	degrees := make([]int, n)
	mxDegree := 0
	mxNode := -1
	father := make([][]int, n)
	child := make(map[int]int)

	for i := 0; i < n; i++ {
		e := edges[i]
		degrees[e]++
		if degrees[e] > mxDegree {
			mxDegree = degrees[e]
			mxNode = e
		}
		child[i] = e
		father[e] = append(father[e], i)
	}

	ans := make([]int, n)
	path := make(map[int]int)

	var dfs func(int, int)
	dfs = func(pa int, curr int) {
		size := len(path)
		path[curr] = size
		next := child[curr]

		if ans[next] != 0 {
			ans[curr] = ans[next] + 1
			return
		}

		if _, exists := path[next]; exists {
			prev := path[next]
			ans[curr] = size - prev + 1
			for next != curr {
				ans[next] = ans[curr]
				next = child[next]
			}
			return
		} else {
			dfs(curr, next)
			if ans[curr] == 0 {
				ans[curr] = ans[next] + 1
			}
		}
	}

	for i := 0; i < n; i++ {
		if ans[i] != 0 {
			continue
		}
		path = make(map[int]int)
		dfs(-1, i)
	}
	return ans
}

