		var n int
		fmt.Fscan(reader, &n)
		aa := make([]int, n)
		ii := make([]int, n)
		yes := true
		for i := 0; i < n; i++ {
			var a int
			fmt.Fscan(reader, &a)
			a = a - 1
			aa[i] = a
			ii[a] = i
			if a % 2 != i % 2 {
				yes = false
			}
		}
		if !yes {
			fmt.Println(-1)
			continue
		}
		qu := make([]int, n * 5 / 2 + 1)
		cnt := 0
		for a, b := n-1, n-2; a > 0; a -= 2 {
			b -= 2
			for a != ii[a] || b != ii[b] {
				if ii[a] == 0 && ii[b] == 1 {
					swap(a + 1, &qu, &cnt, aa, ii)
				} else if ii[b] + 1 == ii[a] {
					swap(ii[a] + 1, &qu, &cnt, aa, ii)
				} else if ii[a] + 1 == ii[b] {
					swap(ii[a] + 3, &qu, &cnt, aa, ii)
				} else if ii[a] == 0 {
					swap(ii[b], &qu, &cnt, aa, ii)
				} else {
					swap(ii[a] + 1, &qu, &cnt, aa, ii)
				}
			}
		}
		fmt.Println(cnt)
		for h := 0; h < cnt; h++ {
			fmt.Print(qu[h], " ")
		}
		fmt.Println()
	}
}

func swap(p int, qu *[]int, cnt *int, aa []int, ii []int) {
	*qu = append(*qu, p)
	*cnt++
	for i, j := 0, p-1; i < j; i, j = i + 1, j - 1 {
		tmp := aa[i]
		aa[i] = aa[j]
		aa[j] = tmp
	}
	for i := 0; i < p; i++ {
		a := aa[i]
		ii[a] = i
	}
}

