func setKthBit(n int, k int) int {
	num := toBinaryString(n)
	// Checking if the length is big enough
	if len(num) >= k + 1 {
		tmp := num[len(num) - k - 1]
		if tmp == '1' {
			return n
		}
	}
	// if not enough bits, we just continue
	val := 1 << k 
	return val + n
}

func toBinaryString(n int) string {
	res := ""
	for n > 0 {
		remainder := n % 2
		res = strconv.Itoa(remainder) + res
		n = n / 2
	}
	// If res is empty, it means we have n = 0, we should handle that
	if res == "" {
		res = "0"
	}
	return res
}

