	for i := 0; i < n; i++ {
		var line string
		fmt.Fscan(reader, &line)
		matrix[i] = []rune(line)
	}

	var moveLine string
	fmt.Fscan(reader, &moveLine)

	start := []int{0, 0}
	found := false

	for i := 0; i < n; i++ {
		for j := 0; j < m; j++ {
			if matrix[i][j] == 'S' {
				start[0] = i
				start[1] = j
				found = true
				break
			}
		}
		if found {
			break
		}
	}

	steps := [][2]int{ {-1, 0}, {0, -1}, {1, 0}, {0, 1} }
	counter := 0

	for i1 := 0; i1 < len(steps); i1++ {
		for i2 := 0; i2 < len(steps); i2++ {
			for i3 := 0; i3 < len(steps); i3++ {
				for i4 := 0; i4 < len(steps); i4++ {
					uniqueSteps := map[[2]int]bool{}
					uniqueSteps[steps[i1]] = true
					uniqueSteps[steps[i2]] = true
					uniqueSteps[steps[i3]] = true
					uniqueSteps[steps[i4]] = true

					if len(uniqueSteps) != 4 {
						continue
					}

					moveMap := map[rune][2]int{
						'0': steps[i1],
						'1': steps[i2],
						'2': steps[i3],
						'3': steps[i4],
					}

					currentX := start[0]
					currentY := start[1]

					for _, el := range moveLine {
						currentX += moveMap[el][0]
						currentY += moveMap[el][1]

						if currentX < 0 || currentX >= n || currentY < 0 || currentY >= m {
							break
						}
						if matrix[currentX][currentY] == '#' {
							break
						}
						if matrix[currentX][currentY] == 'E' {
							counter++
							break
						}
					}
				}
			}
		}
	}
	fmt.Println(counter)
}

