)

func main() {
	reader := bufio.NewReader(os.Stdin)
	var n, m, t int
	fmt.Fscan(reader, &n, &m, &t)

	arrangements := 0

	for boys := 4; boys <= n; boys++ {
		girls := t - boys
		if girls >= 1 && girls <= m {
			combinationsBoys := nCr(n, boys)
			combinationsGirls := nCr(m, girls)
			arrangements += combinationsBoys * combinationsGirls
		} else {
			// nothing to do here if not valid
			continue
		}
	}

	if arrangements == 0 {
		fmt.Println(1)
	} else {
		fmt.Println(arrangements)
	}
}

func nCr(n int, r int) int {
	if r > n {
		return 0
	}
	numerator := 1
	denominator := 1
	for i := 0; i < r; i++ {
		numerator = numerator * (n - i)
		denominator = denominator * (i + 1)
	}
	return numerator / denominator
}

