	reader := bufio.NewReader(os.Stdin)
	var T int = 1 // replace with scanning if needed
	for t := 1; t <= T; t++ {
		runCase(reader)
	}
}

func runCase(reader *bufio.Reader) {
	n, m := readTwoInts(reader)
	neigh := make([][]int, n)
	path := make([]map[int]int, n)
	pre := make([]map[int]int, n)
	relation := make(map[[2]int]int)

	for i := range path {
		path[i] = make(map[int]int)
		pre[i] = make(map[int]int)
	}

	for _ := 0; _ < m; _++ {
		op, i, j := readThreeInts(reader)
		neigh[i-1] = append(neigh[i-1], j-1)
		neigh[j-1] = append(neigh[j-1], i-1)
		relation[[2]int{i - 1, j - 1}] = op - 1
		relation[[2]int{j - 1, i - 1}] = op - 1
	}

	direc := make([]int, n)
	for i := range direc {
		direc[i] = -1
	}

	queue := make([]int, 0)
	for i := 0; i < n; i++ {
		if direc[i] >= 0 {
			continue
		}
		queue = append(queue, i)
		direc[i] = 0
		processQueue(neigh, relation, &queue, &direc, path, pre)
	}

	ans := make([]int, n)
	seq := []int{}
	queue = findIndependent(pre, n)

	for len(queue) > 0 {
		index := queue[0]
		queue = queue[1:]
		seq = append(seq, index)
		for nextindex := range path[index] {
			delete(pre[nextindex], index)
			if len(pre[nextindex]) == 0 {
				queue = append(queue, nextindex)
			}
		}
	}

	if len(seq) < n {
		fmt.Println("NO")
		return
	}

	for x, index := range seq {
		ans[index] = x
	}

	fmt.Println("YES")
	for i := 0; i < n; i++ {
		if direc[i] == 0 {
			fmt.Println("R", ans[i])
		} else {
			fmt.Println("L", ans[i])
		}
	}
}

func processQueue(neigh [][]int, relation map[[2]int]int, queue *[]int, direc *[]int, path []map[int]int, pre []map[int]int) {
	for len(*queue) > 0 {
		index := (*queue)[0]
		*queue = (*queue)[1:]
		for _, nextindex := range neigh[index] {
			if (*direc)[nextindex] == (*direc)[index] {
				fmt.Println("NO")
				return
			} else {
				if (*direc)[nextindex] < 0 {
					(*direc)[nextindex] = 1 - (*direc)[index]
					*queue = append(*queue, nextindex)
				}
				if (relation[[2]int{index, nextindex}] + (*direc)[index])%2 == 0 {
					pre[index][nextindex] = 1
					path[nextindex][index] = 1
				} else {
					pre[nextindex][index] = 1
					path[index][nextindex] = 1
				}
			}
		}
	}
}

func findIndependent(pre []map[int]int, n int) []int {
	queue := []int{}
	for i := 0; i < n; i++ {
		if len(pre[i]) == 0 {
			queue = append(queue, i)
		}
	}
	return queue
}

