func checkPalindromeFormation(a string, b string) bool {
	n := len(a)
	i := 0
	j := n - 1
	apbs := 1
	bpas := 1

	for i < j {
		if a[i] != b[j] {
			apbs = 0
		}
		if apbs == 0 {
			break
		}
		i++
		j--
	}

	if check(a, i, j) || check(b, i, j) {
		return true
	}

	for i < j {
		if b[i] != a[j] {
			break
		}
		i++
		j--
	}

	if check(a, i, j) || check(b, i, j) {
		return true
	}
	return false
}

func check(s string, i int, j int) bool {
	for i < j {
		if s[i] != s[j] {
			return false
		}
		i++
		j--
	}
	return true
}

