func readInts() []int {
	reader := bufio.NewReader(os.Stdin)
	line, _ := reader.ReadString('\n')
	return splitInts(line)
}

func splitInts(s string) []int {
	parts := make([]int, 0)
	temp := ""
	for _, char := range s {
		if char == ' ' || char == '\n' {
			if temp != "" {
				// converting
				val, _ := strconv.Atoi(temp)
				parts = append(parts, val)
				temp = ""
			}
		} else {
			temp += string(char)
		}
	}
	if temp != "" {
		val, _ := strconv.Atoi(temp)
		parts = append(parts, val)
	}
	return parts
}

func getMax(arr []int) int {
	maxVal := arr[0]
	for _, val := range arr {
		if val > maxVal {
			maxVal = val
		}
	}
	return maxVal
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

func abs(x int) int {
	if x < 0 {
		return -x
	}
	return x
}

func toInt(s string) int {
	val, _ := strconv.Atoi(s)
	return val
}

func joinStrings(arr []string) string {
	result := ""
	for i, str := range arr {
		if i > 0 {
			result += " "
		}
		result += str
	}
	return result
}

