	for i := 2; i <= n; i++ {
		d[i] = 0
	}

	for i := 2; i <= n; i++ {
		factors := primeFactorize(i)
		for _, j := range factors {
			d[j] += 1
		}
	}

	a := 1
	const mod = 1000000007
	for _, v := range d {
		a = a * (v + 1)
		a = a % mod
	}

	fmt.Println(a)
}

func primeFactorize(n int) []int {
	a := []int{}
	tmp := n

	for tmp % 2 == 0 {
		a = append(a, 2)
		tmp /= 2
	}

	f := 3
	for f * f <= tmp {
		if tmp % f == 0 {
			a = append(a, f)
			tmp /= f
		} else {
			f += 2
		}
	}

	if tmp != 1 {
		a = append(a, tmp)
	}

	return a
}

