func totalFruit(tree []int) int {
	count := make(map[int]int)
	i := 0
	ans := 0
	for j := 0; j < len(tree); j++ {
		fruit := tree[j]
		count[fruit]++
		for len(count) > 2 {
			count[tree[i]]--
			if count[tree[i]] == 0 {
				delete(count, tree[i])
			}
			i++
		}
		if (j - i + 1) > ans {
			ans = (j - i + 1)
		}
	}
	return ans
}

