func countTriplets(arr []int) int {
	n := len(arr)
	if n < 2 {
		return 0
	}
	xors := make([]int, n)
	for i := 0; i < n; i++ {
		xors[i] = arr[i]
	}

	for i := 1; i < n; i++ {
		xors[i] ^= xors[i-1]
	}

	ans := 0
	for j := 1; j < n; j++ {
		cnt := make(map[int]int)
		for i := 1; i < j; i++ {
			temp := xors[j-1] ^ xors[i-1]
			cnt[temp]++
		}
		cnt[xors[j-1]]++
		for k := j; k < n; k++ {
			key := xors[k] ^ xors[j-1]
			ans += cnt[key]
		}
	}
	return ans
}

