type IntHeap [][2]int

func (h IntHeap) Len() int           { return len(h) }
func (h IntHeap) Less(i, j int) bool { return h[i][0] > h[j][0] }
func (h IntHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *IntHeap) Push(x interface{}) {
	*h = append(*h, x.([2]int))
}

func (h *IntHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func readInts() ([]int, error) {
	var n int
	var arr []int
	_, err := fmt.Scan(&n)
	if err != nil {
		return arr, err
	}
	for i := 0; i < n; i++ {
		var tmp int
		_, err = fmt.Scan(&tmp)
		if err != nil {
			return arr, err
		}
		arr = append(arr, tmp)
	}
	return arr, nil
}

func countRemoves(n int, a []int) int {
	h := &IntHeap{}
	heap.Init(h)
	for i, ai := range a {
		heap.Push(h, [2]int{-ai, i})
	}
	steps := 0
	ix := n
	for h.Len() > 0 {
		item := heap.Pop(h).([2]int)
		hix := item[1]
		if hix < ix {
			ix = hix
			steps += 1
		}
	}
	return steps
}

