#include <stdio.h>
#include <stdlib.h>

int main() {
    int n, k;
    scanf("%d %d", &n, &k);
    int *participants = (int *)malloc(n * sizeof(int));

    for(int i = 0; i < n; i++) {
        scanf("%d", &participants[i]);
    }

    for(int i = 0; i < n - 1; i++) {
        for(int j = 0; j < n - 1 - i; j++) {
            if(participants[j] < participants[j + 1]) {
                int tmp = participants[j];
                participants[j] = participants[j + 1];
                participants[j + 1] = tmp;
            }
        }
    }

    int minPass = participants[k - 1];
    int meron = 1;

    if(minPass <= 0) {
        // sorting again in ascending order
        for(int i = 0; i < n - 1; i++) {
            for(int j = 0; j < n - 1 - i; j++) {
                if(participants[j] > participants[j + 1]) {
                    int tmp2 = participants[j];
                    participants[j] = participants[j + 1];
                    participants[j + 1] = tmp2;
                }
            }
        }
        for(int x = 0; x < n; x++) {
            if(participants[x] > 0) {
                minPass = participants[x];
                break;
            }
        }

        if(minPass <= 0) {
            meron = 0;
            printf("0\n");
        }
    }

    if(meron) {
        // Sorting again to ensure order
        for(int i = 0; i < n - 1; i++) {
            for(int j = 0; j < n - 1 - i; j++) {
                if(participants[j] > participants[j + 1]) {
                    int tmp3 = participants[j];
                    participants[j] = participants[j + 1];
                    participants[j + 1] = tmp3;
                }
            }
        }

        int count = 0;
        for(int i = 0; i < n; i++) {
            if(participants[i] >= minPass) {
                count++;
            }
        }

        printf("%d\n", count);
    }

    free(participants);
