#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    int key;
    int p;
    int l;
    int r;
} Node;

typedef struct BinarySearchTree {
    Node* tree;
    int root;
    int size;
} BinarySearchTree;

Node create_node(int key, int p, int l, int r) {
    Node n;
    n.key = key;
    n.p = p;
    n.l = l;
    n.r = r;
    return n;
}

BinarySearchTree* create_bst() {
    BinarySearchTree* bst = (BinarySearchTree*)malloc(sizeof(BinarySearchTree));
    bst->tree = (Node*)malloc(100 * sizeof(Node));
    bst->root = -1;
    bst->size = 0;
    return bst;
}

void insert(BinarySearchTree* bst, int key) {
    int y = -1;
    int x = bst->root;
    while (x != -1) {
        y = x;
        if (key < bst->tree[x].key)
            x = bst->tree[x].l;
        else
            x = bst->tree[x].r;
    }
    bst->tree[bst->size] = create_node(key, y, -1, -1);
    int z = bst->size;
    bst->size++;
    if (y == -1) {
        bst->root = z;
    } else if (key < bst->tree[y].key) {
        bst->tree[y].l = z;
    } else {
        bst->tree[y].r = z;
    }
}

int find(BinarySearchTree* bst, int key) {
    int x = bst->root;
    while (x != -1 && key != bst->tree[x].key) {
        if (key < bst->tree[x].key)
            x = bst->tree[x].l;
        else
            x = bst->tree[x].r;
    }
    return x;
}

void delete(BinarySearchTree* bst, int key) {
    int node = find(bst, key);
    delete_node(bst, node);
}

void delete_node(BinarySearchTree* bst, int z) {
    int y = z;
    if (bst->tree[z].l == -1 || bst->tree[z].r == -1) {
        y = z;
    } else {
        y = get_successor(bst, z);
    }
    int x = -1;
    if (bst->tree[y].l != -1) {
        x = bst->tree[y].l;
    } else {
        x = bst->tree[y].r;
    }
    if (x != -1) {
        bst->tree[x].p = bst->tree[y].p;
    }
    if (bst->tree[y].p == -1) {
        bst->root = x;
    } else if (y == bst->tree[bst->tree[y].p].l) {
        bst->tree[bst->tree[y].p].l = x;
    } else {
        bst->tree[bst->tree[y].p].r = x;
    }
    if (y != z) {
        bst->tree[z].key = bst->tree[y].key;
    }
}

int get_successor(BinarySearchTree* bst, int x) {
    if (bst->tree[x].r != -1) {
        return get_minimum(bst, bst->tree[x].r);
    }
    int y = bst->tree[x].p;
    while (y != -1 && x == bst->tree[y].r) {
        x = y;
        y = bst->tree[y].p;
    }
    return y;
}

int get_minimum(BinarySearchTree* bst, int x) {
    while (bst->tree[x].l != -1) {
        x = bst->tree[x].l;
    }
    return x;
}

void preorder_traversal(BinarySearchTree* bst, int u) {
    if (u == -1) return;
    printf(" %d", bst->tree[u].key);
    preorder_traversal(bst, bst->tree[u].l);
    preorder_traversal(bst, bst->tree[u].r);
}

void inorder_traversal(BinarySearchTree* bst, int u) {
    if (u == -1) return;
    inorder_traversal(bst, bst->tree[u].l);
    printf(" %d", bst->tree[u].key);
    inorder_traversal(bst, bst->tree[u].r);
}

int main() {
    int n;
    scanf("%d", &n);
    BinarySearchTree* bst = create_bst();
    for (int i = 0; i < n; i++) {
        char order[10];
        scanf("%s", order);
        if (strcmp(order, "insert") == 0) {
