    }
}

void solve(char **A, int N) {
    for (int i = 0; i < N - 1; i++) {
        if (isSubstring(A[i + 1], A[i])) {
            continue; 
        } else {
            printf("NO\n");
            return;
        }
    }
    printf("YES\n");
    for (int i = 0; i < N; i++) {
