#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define INF 1000000000
#define MAXN 100010

typedef long long loint;

loint a[MAXN], b[MAXN];

int check(loint t, int n, loint *mi, loint *mx) {
    loint l = a[0] - t + b[0];
    loint r = a[0] + t - b[0];
    for(int i = 1; i < n; i++) {
        loint curl = a[i] - t + b[i];
        loint curr = a[i] + t - b[i];
        if(curl > r || curr < l) return 0;
        l = (curl > l) ? curl : l;
        r = (curr < r) ? curr : r;
    }
    *mi = l;
    *mx = r;
    return 1;
}

void solve() {
    int n;
    scanf("%d", &n);
    for(int i = 0; i < n; i++) {
        scanf("%lld", &a[i]);
    }
    for(int i = 0; i < n; i++) {
        scanf("%lld", &b[i]);
    }

    loint cost = INF;
    loint lo = 0, hi = INF;
    loint mi = INF, mx = -INF;

    while(lo <= hi) {
        loint mid = lo + (hi - lo) / 2;
        if(check(mid, n, &mi, &mx)) {
            cost = mid;
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }

    printf("%lf\n", (double)(mi + mx) / 2);
}

int main() {
    int t;
    scanf("%d", &t);
    while(t--) {
        solve();
    }
    return 0;
}

