#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef long long i64;
const int N=200010;
const int B=2310;

int n, q, nx[N];
struct Op { int op, x, y; } op[N];
i64 res[N], qcnt, sum[N], ad[N];
int tg[N], bl[N], tot, st[N], ed[N], c[B][B];

i64 read_i64() {
    i64 x = 0, f = 1;
    char ch = getchar();
    while (ch < '0' || ch > '9') {
        if (ch == '-') f = -1;
        ch = getchar();
    }
    while (ch >= '0' && ch <= '9') {
        x = (x << 1) + (x << 3) + (ch ^ 48);
        ch = getchar();
    }
    return x * f;
}

void process(int l, int r){
    for (int i = 1; i <= n; i++) tg[i] = bl[i] = 0;

    for (int i = l; i <= r; i++) {
        if (op[i].op == 3) {
            tg[nx[op[i].x]] = 1;
            tg[nx[op[i].y]] = 1;
        } else if (op[i].op == 2) {
            tg[op[i].x] = 1;
        }
    }

    tot = 0;
    for (int i = 1; i <= n; i++) {
        if (tg[i]) {
            st[++tot] = i; 
            int nw = i;
            do {
                bl[nw] = tot; 
                ed[tot] = nw; 
                nw = nx[nw];
            } while(!tg[nw]);
        }
    }

    int pos[B]; 
    int pcnt = 0; 
    for (int i = l; i <= r; i++) {
        if (op[i].op == 1) {
            pos[++pcnt] = op[i].x - 1; 
            pos[++pcnt] = op[i].y; 
        }
    }

    qsort(pos + 1, pcnt, sizeof(int), cmpfunc);
    pcnt = unique(pos + 1, pos + pcnt + 1) - pos - 1;

    for (int i = 1, lst = 0; i <= pcnt; i++) {
        for (int j = 1; j <= tot; j++) c[j][i] = c[j][i - 1];
        for (int j = lst + 1; j <= pos[i]; j++) c[bl[j]][i]++;
        lst = pos[i];
    }

    auto getrk = [&](int x) { return lower_bound(pos + 1, pos + pcnt + 1, x) - pos; };

    for (int i = l; i <= r; i++) {
        if (op[i].op == 1) {
            res[++qcnt] = sum[op[i].y] - sum[op[i].x - 1];
            int l = getrk(op[i].x - 1), r = getrk(op[i].y);
            for (int j = 1; j <= tot; j++) res[qcnt] += (c[j][r] - c[j][l]) * ad[j];
        } else if (op[i].op == 2) {
            int x = bl[op[i].x], nw = st[x];
            do {
                ad[bl[nw]] += op[i].y; 
                nw = nx[ed[bl[nw]]];
            } while(bl[nw] != x);
        } else if (op[i].op == 3) {
            int temp = nx[op[i].x];
            nx[op[i].x] = nx[op[i].y];
            nx[op[i].y] = temp;
        }
    }

    for (int i = 1; i <= n; i++) {
        a[i] += ad[bl[i]];
        sum[i] = sum[i - 1] + a[i];
    }
    for (int i = 1; i <= tot; i++) ad[i] = 0;
}

int main() {
#ifdef LOCAL
    freopen(".in", "r", stdin);
    freopen(".out", "w", stdout);
#endif
    n = read_i64();
    for (int i = 1; i <= n; i++) {
        a[i] = read_i64();
        sum[i] = sum[i - 1] + a[i];
    }

    for (int i = 1; i <= n; i++) {
        nx[i] = read_i64();
    }
    q = read_i64();

    for (int i = 1; i <= q; i++) {
        op[i].op = read_i64();
        op[i].x = read_i64();
        op[i].y = read_i64();
    }

    int siz = sqrt(n);
    for (int l = 1, r; l <= q; l = r + 1) {
        r = min(q, l + siz - 1);
        process(l, r);
    }

    for (int i = 1; i <= qcnt; i++) {
        printf("%lld\n", res[i]);
    }
    return 0;
}

