int main() {
    int t = readint();
    for (int i = 0; i < t; i++) {
        int ans = 0;
        IntArray n_k = readarray(1);
        int n = n_k.data[0];
        int k = n_k.data[1];

        IntArray ps = readarray(1);
        IntArray ss = readarray(1);
        int* adj = (int*)malloc(n * sizeof(int) * n);
        memset(adj, -1, n * sizeof(int) * n);

        for (int j = 0; j < n; j++) {
            adj[j] = (int*)malloc(n * sizeof(int));
            int p = ps.data[j];
            adj[p - 1][j] = j + 1;
        }

        int* ks = (int*)malloc(n * sizeof(int));
        ks[0] = k;
        for (int j = 1; j < n; j++) {
            ks[j] = 0;
        }

        int* cum_scores = (int*)malloc(n * sizeof(int));
        memset(cum_scores, 0, n * sizeof(int));

        dfs(0, adj, n, ss.data, ks, cum_scores, &ans);

        printf("%d\n", ans);

        for (int j = 0; j < n; j++) {
            free(adj[j]);
        }
