        free(n_k.data);
        free(ps.data);
        free(ss.data);
        free(ks);
        free(cum_scores);
    }
    return 0;
}

void dfs(int u, int* adj, int n, int* ss, int* ks, int* cum_scores, int* ans) {
    int k = ks[u];
    int nn = 0;
    for (int j = 0; j < n; j++) {
        if (adj[u][j] != -1) nn++;
    }

    *ans += ss[u] * k;
    if (nn == 0) {
        cum_scores[u] = ss[u];
        return;
    }

    int* scores = (int*)malloc(nn * sizeof(int));
    for (int v = 0; v < nn; v++) {
        ks[adj[u][v]] = k / nn;
        dfs(adj[u][v], adj, n, ss, ks, cum_scores, ans);
        scores[v] = cum_scores[adj[u][v]];
    }

    // Sorting scores in descending order
    for (int j = 0; j < nn; j++) {
        for (int l = j + 1; l < nn; l++) {
            if (scores[j] < scores[l]) {
                int tmp = scores[j];
                scores[j] = scores[l];
                scores[l] = tmp;
            }
        }
    }

    for (int l = 0; l < k % nn; l++) {
        *ans += scores[l];
    }

    cum_scores[u] = ss[u] + scores[k % nn];
    free(scores);
}

