#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int countUpper(char *strrr) {
    int upperCount = 0;
    for (int j = 0; j < strlen(strrr); j++) {
        if (strrr[j] >= 'A' && strrr[j] <= 'Z') {
            upperCount++;
        }
    }
    return upperCount;
}

int countLower(char *strrr) {
    int lowerCount = 0;
    for (int k = 0; k < strlen(strrr); k++) {
        if (strrr[k] >= 'a' && strrr[k] <= 'z') {
            lowerCount++;
        }
    }
    return lowerCount;
}

void convertString(char *inputStr) {
    int upper = countUpper(inputStr);
    int lower = countLower(inputStr);

    if (upper > lower) {
        for (int a = 0; a < strlen(inputStr); a++) {
            putchar(toupper(inputStr[a]));
        }
        putchar('\n');
    } else {
        for (int b = 0; b < strlen(inputStr); b++) {
            putchar(tolower(inputStr[b]));
        }
        putchar('\n');
    }
}

