void process_case(int n) {
    int* a = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }

    int minn = INT_MAX;
    int maxx = INT_MIN;

    for (int i = 0; i < n; i++) {
        int c = a[i];
        if (c > maxx) {
            maxx = c;
        }
        if (c < minn) {
            minn = c;
        }
    }

    if (minn < 0 && maxx < 0) {
        printf("%d %d\n", maxx * maxx, minn * minn);
    } else if (minn < 0 && maxx == 0) {
        printf("0 %d\n", minn * minn);
    } else if (minn < 0 && maxx > 0) {
        int b = fmax(fmax(minn * minn, maxx * maxx), abs(minn * maxx));
