#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    while (b != 0) {
        int tmp = b;
        b = a % b;
        a = tmp;
    }
    return a;
}

int main() {
    int n, m, q;
    scanf("%d %d %d", &n, &m, &q);

    int l = n * m / gcd(n, m);
    int nf = l / n;
    int mf = l / m;
    int barr = nf * mf / gcd(nf, mf);

    for (int i = 0; i < q; i++) {
        int sx, sy, ex, ey;
        scanf("%d %d %d %d", &sx, &sy, &ex, &ey);

        int sp;
        if (sx == 1) {
            sp = nf * (sy - 1);
        } 
        else {
            sp = mf * (sy - 1);
        }

        int ep;
        if (ex == 1) {
            ep = nf * (ey - 1);
        } 
        else {
            ep = mf * (ey - 1);
        }

        int start = sp < ep ? sp : ep;
        int end = sp > ep ? sp : ep;

        int barrier = start / barr * barr;

        if (barrier + barr <= end) {
            printf("NO\n");
        } 
        else {
            printf("YES\n");
        }
    }
    return 0;
}

#include <stdio.h>
