void swap(char *x, char *y) {
    char temp = *x;
    *x = *y;
    *y = temp;
}

void permute(char *str, int left, int right, char **result, int *index) {
    if (left == right) {
        strcpy(result[*index], str);
        (*index)++;
    } else {
        for (int i = left; i <= right; i++) {
            swap((str + left), (str + i));
            permute(str, left + 1, right, result, index);
            swap((str + left), (str + i));
        }
    }
}

