#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_N 100005

typedef struct {
    int key;
    int value;
} Item;

typedef struct {
    Item *items;
    int size;
} Dict;

void init_dict(Dict *d) {
    d->items = (Item *)malloc(sizeof(Item) * MAX_N);
    d->size = 0;
}

void insert_dict(Dict *d, int key) {
    for(int i = 0; i < d->size; i++) {
        if(d->items[i].key == key) {
            d->items[i].value++;
            return;
        }
    }
    d->items[d->size].key = key;
    d->items[d->size].value = 1;
    d->size++;
}

void remove_dict(Dict *d, int key) {
    for(int i = 0; i < d->size; i++) {
        if(d->items[i].key == key) {
            d->items[i].value--;
            if(d->items[i].value <= 0) {
                d->items[i] = d->items[d->size - 1];
                d->size--;
            }
            return;
        }
    }
}

int get_count(Dict *d, int key) {
    for(int i = 0; i < d->size; i++) {
        if(d->items[i].key == key) {
            return d->items[i].value;
        }
    }
    return 0;
}

void solve() {
    int N;
    scanf("%d", &N);
    int *arr = (int *)malloc(N * sizeof(int));
    for(int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }

    Dict l_dict, r_dict;
    init_dict(&l_dict);
    init_dict(&r_dict);

    int splits_count = 0;
    int l_dict_sum = 0, r_dict_sum = 0;

    for(int i = 0; i < N; i++) {
        insert_dict(&r_dict, arr[i]);
    }

    r_dict_sum = 0;
    for (int i = 0; i < r_dict.size; i++) {
        r_dict_sum += r_dict.items[i].key;
    }

    for(int i = 0; i < N; i++) {
        int left_len = i + 1;
        int right_len = N - (i + 1);
        int l_e_s = left_len * (left_len + 1) / 2;
        int r_e_s = right_len * (right_len + 1) / 2;

        remove_dict(&r_dict, arr[i]);
        if (get_count(&r_dict, arr[i]) == 0) {
            r_dict_sum -= arr[i];
        }

        insert_dict(&l_dict, arr[i]);
        if(get_count(&l_dict, arr[i]) == 1) {
            l_dict_sum += arr[i];
        }

        if(l_dict_sum == l_e_s && l_dict.size == left_len && r_dict_sum == r_e_s && r_dict.size == right_len) {
            splits_count++;
        }
    }

    printf("%d\n", splits_count);

    free(arr);
    free(l_dict.items);
    free(r_dict.items);
}

int main() {
    int T;
    scanf("%d", &T);
    for(int t = 0; t < T; t++) {
        solve();
    }
    return 0;
}

