#include <stdio.h>
#include <stdlib.h>

int minKBitFlips(int* A, int ASize, int K) {
    int res = 0;
    int flipped = 0;
    int* isFlipped = (int*)malloc(ASize * sizeof(int));

    for (int i = 0; i < ASize; i++) {
        // Resetting the flipped array
        isFlipped[i] = 0;
    }

    for (int i = 0; i < ASize; i++) {
        if (i >= K) {
            flipped ^= isFlipped[i - K];
        }

        // Checking condition here
        if ((A[i] ^ flipped) == 0) {
            if (i + K > ASize) {
                free(isFlipped);
                return -1;
            }
            // Flipping operation
            isFlipped[i] ^= 1;
            res += 1;
            flipped ^= 1; // After flipping
        }
    }

    free(isFlipped);
    return res;
}

