char *notes[MAX_NOTES] = {"C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "B", "H"};
int noteMap[MAX_NOTES];

void initNoteMap() {
    for(int i = 0; i < MAX_NOTES; i++) {
        noteMap[i] = i;
    }
}

int dist(const char *A, const char *B) {
    int a = -1, b = -1;
    for (int i = 0; i < MAX_NOTES; i++) {
        if (strcmp(A, notes[i]) == 0) {
            a = i;
        }
        if (strcmp(B, notes[i]) == 0) {
            b = i;
        }
    }
    if (a == -1 || b == -1) return -1; // error

    return (b - a + MAX_NOTES) % MAX_NOTES;
}

void swap(char **a, char **b) {
    char *temp = *a;
    *a = *b;
    *b = temp;
}

void permute(char **arr, int l, int r, char *result) {
    if (l == r) {
        int d0 = dist(arr[0], arr[1]);
        int d1 = dist(arr[1], arr[2]);
        int d2 = dist(arr[0], arr[2]);

        if (d0 == 4 && d1 == 3 && d2 == 7) {
            strcpy(result, "major");
            return;
        }
        if (d0 == 3 && d1 == 4 && d2 == 7) {
            strcpy(result, "minor");
            return;
        }
    } else {
        for (int i = l; i <= r; i++) {
            swap(&arr[l], &arr[i]);
            permute(arr, l + 1, r, result);
            swap(&arr[l], &arr[i]); // backtrack
        }
    }
}

void getInput(char *input) {
    fgets(input, MAX_INPUT, stdin);
    input[strcspn(input, "\n")] = 0; // strip newline
}

