    int i = 0;
    while (token != NULL && i < MAX_NOTES) {
        arr[i] = token;
        i++;
        token = strtok(NULL, " ");
    }

    permute(arr, 0, i - 1, result);

    printf("%s\n", result);
    return 0;
}

