#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_SKILLS 100000

void solve(int *skills, int skill_count, int (*quarrels)[2], int quarre_count, int *ans) {
    int *skills_mapping[MAX_SKILLS];
    int quarrels_mapping[MAX_SKILLS] = {0};
    int *temp;

    // Initialize skills_mapping
    for (int i = 0; i < skill_count; i++) {
        if (skills_mapping[skills[i]] == NULL) {
            skills_mapping[skills[i]] = malloc(sizeof(int) * MAX_SKILLS);
        }
        int j = 0;
        while (skills_mapping[skills[i]][j] != 0) {
            j++;
        }
        skills_mapping[skills[i]][j] = i + 1; // store index + 1
    }

    for (int j = 0; j < quarre_count; j++) {
        int i = quarrels[j][0];
        int j_ = quarrels[j][1];
        if (skills[i - 1] == skills[j_ - 1]) {
            continue;
        } else if (skills[i - 1] < skills[j_ - 1]) {
            int tmp = i;
            i = j_;
            j_ = tmp;
        }
        quarrels_mapping[i - 1] += 1;
    }

    int tmp = skill_count;
    for (int skill = MAX_SKILLS - 1; skill >= 0; skill--) {
        if (skills_mapping[skill] == NULL) {
            continue;
        }
        int group_size = 0;
        while (skills_mapping[skill][group_size] != 0) {
            group_size++;
        }
        for (int k = 0; k < group_size; k++) {
            int idx = skills_mapping[skill][k] - 1;
            ans[idx] = (tmp - quarrels_mapping[idx] - group_size < 0) ? 0 : tmp - quarrels_mapping[idx] - group_size;
        }
        tmp -= group_size;
    }
}

int main() {
    int k;
    int n;
    scanf("%d %d", &n, &k);
    int* skills = malloc(sizeof(int) * n);
    for (int i = 0; i < n; i++) {
        scanf("%d", &skills[i]);
    }

    int (*quarrels)[2] = malloc(sizeof(int[2]) * k);
    for (int j = 0; j < k; j++) {
        scanf("%d %d", &quarrels[j][0], &quarrels[j][1]);
    }

    int *result = malloc(sizeof(int) * n);
    for (int i = 0; i < n; i++) {
        result[i] = 0;
    }

    solve(skills, n, quarrels, k, result);

    for (int i = 0; i < n; i++) {
        printf("%d", result[i]);
        if (i < n - 1) {
            printf(" ");
        }
    }
    printf("\n");

    free(skills);
    free(quarrels);
    free(result);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Node {
    int data;
    struct Node* next;
    struct Node* prev;
};

struct List {
    struct Node* head;
};

void insert(struct List* list, int value) {
    struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
    newNode->data = value;
    newNode->next = NULL;
    if (list->head == NULL) {
        newNode->prev = NULL;
        list->head = newNode;
        return;
    }
    struct Node* temp = list->head;
    while (temp->next != NULL) {
        temp = temp->next;
    }
    temp->next = newNode;
    newNode->prev = temp;
    newNode->next = NULL;
}

void findPairsWithGivenSum(int target, struct List* list) {
    struct Node* high = list->head;
    struct Node* low = list->head;
    int *result = (int*)malloc(100 * sizeof(int)); 
    int count = 0;

    while (high != NULL && high->next != NULL) {
        high = high->next;
    }

    while (low != NULL && high != NULL && low->data < high->data) {
        int sum = low->data + high->data;
        if (sum > target) {
            high = high->prev;
        } else if (sum < target) {
            low = low->next;
        } else {
            result[count++] = low->data; 
            result[count++] = high->data; 
            low = low->next;
            high = high->prev;
        }
    }

    for (int i = 0; i < count; i += 2) {
        printf("[%d, %d]\n", result[i], result[i+1]);
    }
    free(result);
}

