#include <stdio.h>
#include <stdlib.h>

struct Node {
    int seatNumber;
    struct Node* next;
};

struct SeatManager {
    struct Node* unreserved;
};

struct SeatManager* createSeatManager(int n) {
    struct SeatManager* manager = (struct SeatManager*)malloc(sizeof(struct SeatManager));
    manager->unreserved = NULL;
    for (int i = n; i >= 1; i--) {
        struct Node* newSeat = (struct Node*)malloc(sizeof(struct Node));
        newSeat->seatNumber = i;
        newSeat->next = manager->unreserved;
        manager->unreserved = newSeat;
    }
    return manager;
}

int reserve(struct SeatManager* manager) {
    if (manager->unreserved == NULL) {
        return -1; 
    }
    int firstSeat = manager->unreserved->seatNumber;
    struct Node* temp = manager->unreserved;
    manager->unreserved = manager->unreserved->next;
    free(temp);
    return firstSeat;
}

void unreserve(struct SeatManager* manager, int seatNumber) {
    struct Node* newSeat = (struct Node*)malloc(sizeof(struct Node));
    newSeat->seatNumber = seatNumber;

    if (manager->unreserved == NULL || manager->unreserved->seatNumber > seatNumber) {
        newSeat->next = manager->unreserved;
        manager->unreserved = newSeat;
        return;
    }

    struct Node* current = manager->unreserved;
    struct Node* prev = NULL;

    while (current != NULL && current->seatNumber < seatNumber) {
        prev = current;
        current = current->next;
    }
    newSeat->next = current;
    if (prev != NULL) {
        prev->next = newSeat;
    }
}

void freeManager(struct SeatManager* manager) {
    struct Node* current = manager->unreserved;
    while (current != NULL) {
        struct Node* temp = current;
        current = current->next;
        free(temp);
    }
    free(manager);
}

int main() {
    int n = 5;
    struct SeatManager* obj = createSeatManager(n);

    int seat1 = reserve(obj);
    printf("Reserved: %d\n", seat1);

    unreserve(obj, 1);

    int seat2 = reserve(obj);
    printf("Reserved: %d\n", seat2);

    freeManager(obj);
    return 0;
}

