void nice_print(double x) {
    printf("%.1f\n", x);
}

void bisect_insert(double *a, int *len, int left, int right, double x) {
    int the_range = right - left;
    int middle = (the_range / 2) + left;
    if (a[middle] == x) {
        for (int i = *len; i > middle; i--) {
            a[i] = a[i - 1];
        }
        a[middle] = x;
        (*len)++;
    } else if (a[middle] < x) {
        if (the_range == 0) {
            for (int i = *len; i > middle; i--) {
                a[i] = a[i - 1];
            }
            a[middle] = x;
            (*len)++;
        } else if (the_range == 1) {
            for (int i = *len; i > middle + 1; i--) {
                a[i] = a[i - 1];
            }
            a[middle + 1] = x;
            (*len)++;
        } else {
            bisect_insert(a, len, middle, right, x);
        }
    } else {
        if (the_range == 0) {
            for (int i = *len; i > fmax(0, middle - 1); i--) {
                a[i] = a[i - 1];
            }
            a[fmax(0, middle - 1)] = x;
            (*len)++;
        } else if (the_range == 1) {
            for (int i = *len; i > fmax(0, middle - 2); i--) {
                a[i] = a[i - 1];
            }
            a[fmax(0, middle - 2)] = x;
            (*len)++;
        } else {
            bisect_insert(a, len, left, middle, x);
        }
    }
}

