#define MOD 1000000007

int cmpfunc(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

long long solve(int n, int *arr) {
    qsort(arr, n, sizeof(int), cmpfunc);
    long long res = 1;

    long long *lookup = (long long *)malloc(n * sizeof(long long));
    lookup[0] = 1;

    for(int i = 1; i < n; i++) {
        if(arr[i] != arr[i - 1]) {
            lookup[i] = res + 1;
            res += lookup[i];
        } else {
            lookup[i] = lookup[i - 1];
            res += lookup[i];
        }
        res = res % MOD;
    }

    free(lookup);
    return res;
}

