        int tmp = ans[i];
        ans[i] = ans[len - i - 1];
        ans[len - i - 1] = tmp;
    }
}

void trimArray(int *ans, int *ansLen) {
    while (*ansLen > 2) {
        (*ansLen)--;
    }
}

void printAnswer(int *ans, int ansLen) {
    if (ansLen > 1) {
        for (int i = 0; i < ansLen; i++) {
            printf("%d", ans[i]);
        }
        printf("\n");
    } else {
        printf("-1\n");
    }
}

