int sub(int x, int y) {
    return (x - y + MOD) % MOD;
}

int mul(int x, int y) {
    return (x * y) % MOD;
}

int gcd(int x, int y) {
    if (y == 0) {
        return x;
    }
    return gcd(y, x % y);
}

int lcm(int x, int y) {
    return (x * y) / gcd(x, y);
}

int power(int x, int y) {
    int res = 1;
    x %= MOD;
    while (y != 0) {
        if (y & 1) {
            res = mul(res, x);
        }
        y >>= 1;
        x = mul(x, x);
    }
    return res;
}

int mod_inv(int n) {
    return power(n, MOD - 2);
}

int prob(int p, int q) {
    return mul(p, power(q, MOD - 2));
}

