void help(int *A, int *B, int n, int **FI, int *sizeFI, int **FR, int *sizeFR) {
	*sizeFI = 0;
	*sizeFR = 0;
	*FI = (int*)malloc(n * sizeof(int));
	*FR = (int*)malloc(n * sizeof(int));
	for (int i = 0; i < n; i++) {
		if (A[i] == 0) {
			(*FI)[(*sizeFI)++] = B[i];
		} else {
			(*FR)[(*sizeFR)++] = B[i];
		}
	}
	// Simple bubble sort for FI
	for (int i = 0; i < *sizeFI - 1; i++) {
		for (int j = 0; j < *sizeFI - 1 - i; j++) {
			if ((*FI)[j] < (*FI)[j + 1]) {
				int tmp = (*FI)[j];
				(*FI)[j] = (*FI)[j + 1];
				(*FI)[j + 1] = tmp;
			}
		}
	}
	// Simple bubble sort for FR
	for (int i = 0; i < *sizeFR - 1; i++) {
		for (int j = 0; j < *sizeFR - 1 - i; j++) {
			if ((*FR)[j] < (*FR)[j + 1]) {
				int tmp = (*FR)[j];
				(*FR)[j] = (*FR)[j + 1];
				(*FR)[j + 1] = tmp;
			}
		}
	}
}

int sum(int *arr, int length) {
	int total = 0;
	for (int i = 0; i < length; i++) {
		total += arr[i];
	}
	return total;
}

int solve(int *FI, int sizeFI, int *FR, int sizeFR) {
	int ans = 0;
	int i = sizeFI < sizeFR ? sizeFI : sizeFR;
	int sumFI = sum(FI, i);
	int sumFR = sum(FR, i);
	ans += 2 * (sumFI + sumFR);
	if (sizeFI > sizeFR) {
		ans += 2 * FI[i];
		for (int j = i + 1; j < sizeFI; j++) {
			ans += FI[j];
		}
	} else {
		for (int j = i; j < sizeFR; j++) {
			ans += FR[j];
		}
	}
	return ans;
}

int main() {
	int N;
	scanf("%d", &N);
	for (int i = 0; i < N; i++) {
		int n;
		scanf("%d", &n);
		int *A = (int*)malloc(n * sizeof(int));
		int *B = (int*)malloc(n * sizeof(int));

		for (int j = 0; j < n; j++) {
			scanf("%d", &A[j]);
		}
		for (int j = 0; j < n; j++) {
			scanf("%d", &B[j]);
		}

		int totalA = sum(A, n);
		if (totalA == 0 || totalA == n) {
			printf("%d\n", sum(B, n));
			free(A);
			free(B);
			continue;
		}

		int *FI;
		int *FR;
		int sizeFI, sizeFR;
		help(A, B, n, &FI, &sizeFI, &FR, &sizeFR);
		int v1 = (sizeFR > 0) ? solve(FI, sizeFI, FR, sizeFR - 1) + FR[sizeFR - 1] : 0;
		int v2 = (sizeFI > 0) ? solve(FR, sizeFR, FI, sizeFI - 1) + FI[sizeFI - 1] : 0;
		printf("%d\n", (v1 > v2) ? v1 : v2);

		free(A);
		free(B);
		free(FI);
		free(FR);
	}
	return 0;
}

