struct ListNode {
    int val;
    struct ListNode *next;
};

void initMatrix(int **A, int m, int n) {
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            A[i][j] = -1; // initializing all to -1
        }
    }
}

int** createMatrix(int m, int n) {
    int **A = malloc(m * sizeof(int*));
    for (int i = 0; i < m; i++) {
        A[i] = malloc(n * sizeof(int));
    }
    initMatrix(A, m, n);
    return A;
}

void freeMatrix(int **A, int m) {
    for (int i = 0; i < m; i++) {
        free(A[i]);
    }
    free(A);
}

int** spiralMatrix(int m, int n, struct ListNode* head) {
    int **A = createMatrix(m, n);
    int i = 0, j = 0, di = 0, dj = 1;
    struct ListNode *cur = head;

    while (cur) {
        A[i][j] = cur->val;
        cur = cur->next;

        if (A[(i + di + m) % m][(j + dj + n) % n] != -1) { // checking next cell
            int tmp = di; 
            di = dj;
            dj = -tmp;
        }
        i += di; // moving to next cell
        j += dj; // moving to next cell
    }
    return A;
}

void printMatrix(int **A, int m, int n) {
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            printf("%d ", A[i][j]);
        }
        printf("\n");
    }
}

