    head->val = 1;
    head->next = malloc(sizeof(struct ListNode));
    head->next->val = 2;
    head->next->next = malloc(sizeof(struct ListNode));
    head->next->next->val = 3;
    head->next->next->next = NULL;

    int m = 3, n = 3;
    int **matrix = spiralMatrix(m, n, head);
    printMatrix(matrix, m, n);

    freeMatrix(matrix, m);
    free(head->next);
    free(head);

    return 0;
}

