double Time() {
    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    return ts.tv_sec * 1e9 + ts.tv_nsec;
}

struct TIMER {
    double start_t;
    TIMER() {
        start_t = Time();
    }
} Timer;

void fill_flg(int l, int r) {
    for(int i = l; i <= r; i++) {
        if(op[i][0] == 2) flg[op[i][1]] = 1;
        else if(op[i][0] == 3) {
            flg[op[i][1]] = 1;
            flg[op[i][2]] = 1;
        }
    }
}

void prepare_positions(int n, int pos[], int* size) {
    *size = 0;
    for(int i = 1; i <= n; i++) {
        if(flg[i]) {
            pos[(*size)++] = i;
            tag[i] = 0;
            int u = i; 
            while(flg[u = q[u]]) ;
            nxt[u] = i;
        }
    }
}

void handle_operations(int l, int r, int pos[], int size) {
    for(int i = l; i <= r; i++) {
        int opt = op[i][0];
        int x = op[i][1];
        int y = op[i][2];

        if(opt == 1) {
            long long ans = sum[y] - sum[x - 1];
            for(int j = 0; j < size; j++) {
                int c = pos[j];
                int* ql = lower_bound(pq[c], pq[c] + pq_size[c], x);
                int* qr = upper_bound(pq[c], pq[c] + pq_size[c], y);
                ans += tag[c] * (qr - ql);
            }
            printf("%lld\n", ans);
        } else if(opt == 2) {
            tag[x] += y;
            for(int i = x; (i = nxt[i]) != x;) {
                tag[i] += y;
            }
        } else {
            int temp = nxt[x];
            nxt[x] = nxt[y];
            nxt[y] = temp;
            int temp2 = p[x];
            p[x] = p[y];
            p[y] = temp2;
        }
    }
}

