void sort_and_zip(int *arr, int *ar, int n) {
    for(int i = 0; i < n - 1; i++) {
        for(int j = 0; j < n - i - 1; j++) {
            if(arr[j] > arr[j + 1]) {
                int tmp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = tmp;

                int tmp2 = ar[j];
                ar[j] = ar[j + 1];
                ar[j + 1] = tmp2;
            }
        }
    }
}

void compute_sums(int *ar, int *s, int n) {
    s[0] = ar[n - 1];
    for(int i = 1; i < n; i++) {
        s[i] = s[i - 1] + ar[n - 1 - i];
    }
}

