#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct {
    double x;
    double y;
} Point;

Point point_init(double x, double y) {
    Point p;
    p.x = x;
    p.y = y;
    return p;
}

Point point_add(Point a, Point b) {
    return point_init(a.x + b.x, a.y + b.y);
}

Point point_sub(Point a, Point b) {
    return point_init(a.x - b.x, a.y - b.y);
}

Point point_mul(Point a, double b) {
    return point_init(a.x * b, a.y * b);
}

double point_norm(Point a) {
    return pow(a.x, 2) + pow(a.y, 2);
}

double point_abs(Point a) {
    return sqrt(point_norm(a));
}

void point_repr(Point a) {
    printf("(%f,%f)", a.x, a.y);
}

typedef struct {
    Point pt1;
    Point pt2;
} Vector;

Vector vector_init(Point p1, Point p2) {
    return (Vector){p1, p2};
}

Vector vector_from_points(Point a, Point b) {
    return vector_init(a, point_sub(b, a));
}

double vector_dot(Vector v1, Vector v2) {
    return (v1.pt2.x - v1.pt1.x) * (v2.pt2.x - v2.pt1.x) + (v1.pt2.y - v1.pt1.y) * (v2.pt2.y - v2.pt1.y);
}

double vector_cross(Vector v1, Vector v2) {
    return (v1.pt2.x - v1.pt1.x) * (v2.pt2.y - v2.pt1.y) - (v1.pt2.y - v1.pt1.y) * (v2.pt2.x - v2.pt1.x);
}

void vector_repr(Vector v) {
    point_repr(v.pt1);
    printf(",");
    point_repr(v.pt2);
}

typedef struct {
    Vector vec;
} Segment;

Segment segment_init(Point p1, Point p2) {
    return (Segment){vector_init(p1, p2)};
}

double segment_projection(Segment s, Point p) {
    Vector v = vector_from_points(s.vec.pt1, p);
    return vector_dot(s.vec, v) / point_norm(v);
}

Point segment_projection_point(Segment s, Point p) {
    double t = segment_projection(s, p);
    return point_add(s.vec.pt1, point_mul(point_sub(s.vec.pt2, s.vec.pt1), t));
}

double segment_distance_to_point(Segment s, Point p) {
    Vector v1 = vector_from_points(s.vec.pt1, p);
    if (vector_dot(s.vec, v1) <= 0) {
        return point_abs(v1);
    }
    Vector v2 = vector_from_points(s.vec.pt2, p);
    if (vector_dot(vector_init(s.vec.pt1, s.vec.pt2), v2) <= 0) {
        return point_abs(v2);
    }
    return point_abs(point_sub(segment_projection_point(s, p), p));
}

