#define MAX_SIZE 1000

void replace_spaces(char *str) {
    for(int i = 0; str[i] != '\0'; i++) {
        if(str[i] == ' ') {
            str[i] = '.';
        }
    }
}

void pad_string(char *str, int len) {
    int current_len = strlen(str);
    for(int i = current_len; i < len; i++) {
        str[i] = '.';
    }
    str[len] = '\0';
}

void encrypt_six_columns(char *s, char *result) {
    char tmp[MAX_SIZE];
    int len_s = strlen(s);
    replace_spaces(s);

    // Increment length for padding
    if (len_s % 6 != 0) {
        len_s += (6 - (len_s % 6));
    }

    // Fill tmp with original string + padding
    strcpy(tmp, s);
    pad_string(tmp, len_s);

    int num_cols = len_s / 6;
    char arr[6][MAX_SIZE];

    // Fill each column with the corresponding characters
    for(int i = 0; i < 6; i++) {
        for(int j = 0; j < num_cols; j++) {
            arr[i][j] = tmp[i * num_cols + j];
        }
        arr[i][num_cols] = '\0'; // Null-terminating each "column"
    }

    // Build the result string
    int k = 0;
    for(int i = 0; i < num_cols; i++) {
        for(int j = 0; j < 6; j++) {
            if (j < 5) {
                result[k++] = arr[j][i];
            } else {
                result[k++] = arr[j][i];
                result[k++] = ' ';
            }
        }
    }
    result[k - 1] = '\0'; // Remove last extra space
}

int main() {
    char input[MAX_SIZE];
    char output[MAX_SIZE];

    printf("Enter your string: ");
    fgets(input, sizeof(input), stdin);

    // Remove newline character if exists
    input[strcspn(input, "\n")] = '\0';

    encrypt_six_columns(input, output);
    printf("Encrypted string: %s\n", output);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <deque>
#include <vector>

// define long long and other types
typedef long long ll;

const long MOD = 1000000007;

struct edge{
    int u, v;
    ll flow, cap;
    edge(int uu, int vv, ll cc): u(uu), v(vv), cap(cc), flow(0) {}
};

struct dinic{
    int n, s, t;
    std::vector<edge> edges;
    std::vector<int> ptr, lvl;
    std::vector<std::vector<int>> adj;
    std::deque<int> q;

    dinic(int numNodes, int source, int sink): n(numNodes), s(source), t(sink), adj(numNodes) {}

    void add_edge(int u, int v, ll cap){
        adj[u].push_back(edges.size());
        edges.emplace_back(u, v, cap);
        adj[v].push_back(edges.size());
        edges.emplace_back(v, u, 0);
    }

    bool bfs(){
        lvl.assign(n, -1);
        lvl[s] = 0;
        q = {s};
        while (!q.empty()){
            int u = q.front(); q.pop_front();
            for (int eid: adj[u]){
                if (edges[eid].cap - edges[eid].flow < 1) continue;
                int v = edges[eid].v;
                if (lvl[v] != -1) continue;
                lvl[v] = lvl[u] + 1;
                q.push_back(v);
            }
        }
        return lvl[t] != -1;
    }

    ll dfs(int u, ll pushed){
        if (pushed == 0) return 0;
        if (u == t) return pushed;
        for (int& eid = ptr[u]; eid < adj[u].size(); eid++){
            int id = adj[u][eid];
            if (edges[id].cap - edges[id].flow < 1) continue;
            int v = edges[id].v;
            if (lvl[v] != lvl[u] + 1) continue;
            ll pushing = dfs(v, std::min(pushed, edges[id].cap - edges[id].flow));
            if (pushing){
                edges[id].flow += pushing;
                edges[id^1].flow -= pushing;
                return pushing;
            }
        }
        return 0;
    }

    ll flow(){
        ll fl = 0;
        while (bfs()){
            ptr.assign(n, 0);
            while (ll pushing = dfs(s, 1e17)){
                fl += pushing;
            }
        }
        return fl;
    }
};

int main(){
    int n;
    scanf("%d", &n);
    dinic g(n + 2, 0, n + 1);
    int last[101] = {0};

    auto exist = [&](int v, int par) -> bool {
        int pos = last[v];
        for (int i = 2; i * v < 101; i++){
            if (pos < last[i * v] && par % (i * v) == 0) return true;
        }
        return false;
    };

    for (int i = 1; i <= n; i++){
        int val;
        scanf("%d", &val);
        for (int other = 1; other <= val; other++){
            if (!last[other] || val % other) continue;
            if (!exist(other, val)){
                g.add_edge(last[other], i, 1e17);
            }
        }
        last[val] = i;
    }

    ll total = 0;
    for (int i = 1; i <= n; i++){
        int val;
        scanf("%d", &val);
        if (val > 0){
            g.add_edge(i, n + 1, val);
            total += val;
        }
        else if (val < 0) {
            g.add_edge(0, i, -val);
        }
    }
    printf("%lld", total - g.flow());
}

