#define MAXN 100

struct BIT {
    int n;
    long *data;

    struct BIT *init(int n) {
        struct BIT *bit = malloc(sizeof(struct BIT));
        bit->n = n;
        bit->data = malloc((n + 1) * sizeof(long));
        memset(bit->data, 0, (n + 1) * sizeof(long));
        return bit;
    }

    void add(struct BIT *bit, int idx, long val) {
        for (int i = idx + 1; i <= bit->n; i += lsb(i)) {
            bit->data[i] += val;
        }
    }

    long sum(struct BIT *bit, int l, int r) {
        return sumBit(bit, r) - sumBit(bit, l - 1);
    }

    long sumBit(struct BIT *bit, int idx) {
        long res = 0;
        for (int i = idx + 1; i > 0; i -= lsb(i)) {
            res += bit->data[i];
        }
        return res;
    }

    int lsb(int i) {
        return i & -i;
    }

    int getKth(struct BIT *bit, int k) {
        int lo = 0, hi = bit->n;
        while (lo < hi) {
            int mid = (lo + hi) >> 1;
            if (k > sumBit(bit, mid)) {
                lo = mid + 1;
            } else {
                hi = mid;
            }
        }
        return lo;
    }
};

int *nextPermutation(int *perm, int n) {
    int *result = malloc(n * sizeof(int));
    memcpy(result, perm, n * sizeof(int));
    int swapIdx = -1;
    for (int i = n - 1; i >= 1; i--) {
        if (result[i - 1] < result[i]) {
            swapIdx = i - 1;
            break;
        }
    }
    if (swapIdx == -1) {
        free(result);
        return NULL;
    }
    for (int i = n - 1; i >= 1; i--) {
        if (result[i] > result[swapIdx]) {
            int tmp = result[i];
            result[i] = result[swapIdx];
            result[swapIdx] = tmp;
            break;
        }
    }
    int l = swapIdx + 1, r = n - 1;
    while (l < r) {
        int tmp = result[l];
        result[l++] = result[r];
        result[r--] = tmp;
    }
    return result;
}

void solve(int t) {
    char str[] = "ANTO";
    char *buf = malloc(100);
    while (t--) {
        scanf("%s", buf);
        int f[4] = {0};
        for (int i = 0; buf[i] != '\0'; i++) {
            f[strchr(str, buf[i]) - str]++;
        }

        long max = 0;
        char best[5] = "ANTO";
        int p[4] = {0, 1, 2, 3};
        while (1) {
            struct BIT *bit = bit->init(4);
            long inv = 0;

            for (int i = strlen(buf) - 1; i >= 0; i--) {
                bit->add(bit, strchr(str, buf[i]) - str, 1);
                inv += bit->sum(bit, strchr(str, buf[i]) - str, 3);
            }

            long curr = 0;
            curr += (long)(f[p[0]] + f[p[1]] + f[p[2]]) * f[p[3]];
            curr += (long)(f[p[0]] + f[p[1]]) * f[p[2]];
            curr += (long)f[p[0]] * f[p[1]];

            if (2 * inv > curr && inv > max) {
                max = inv;
                for (int i = 0; i < 4; i++) {
                    best[i] = str[p[3 - i]];
                }
                best[4] = '\0';
            }

            int *newP = nextPermutation(p, 4);
            if (!newP) break;
            free(p);
            p = newP;
        }
        for (int i = 0; i < 4; i++) {
            char c = best[i];
            int idx = strchr(str, c) - str;
            while (f[idx]-- > 0) {
                printf("%c", c);
            }
        }
        printf("\n");
    }
    free(buf);
}

int main() {
    int t;
    scanf("%d", &t);
    solve(t);
    return 0;
}

