    for (int ti = 0; ti < t; ti++) {
        int n, k;
        scanf("%d %d", &n, &k);
        char s[100001];
        scanf("%s", s);

        int d[256] = {0}; // assuming ASCII
        int M = 0;

        for (int i = 0; s[i] != '\0'; i++) {
            d[s[i]] += 1;
            if (d[s[i]] > M) {
                M = d[s[i]];
            }
        }

        int qs[500]; // max size to hold divisors, arbitrary choice
        int q_count = 0;

        qs[q_count++] = k;
        for (int j = 2; j <= (int)(sqrt(k)) + 1; j++) {
            if (k % j == 0) {
                qs[q_count++] = j;
                if (j != k / j) {
                    qs[q_count++] = k / j;
                }
            }
        }

        int L = M;

        for (int q_index = 0; q_index < q_count; q_index++) {
            int q = qs[q_index];
            int max_reps = n / q;

            for (int reps = max_reps; reps > 0; reps--) {
                int total_contribs = 0;

                for (int potential_contributor = 0; potential_contributor < 256; potential_contributor++) {
                    if (d[potential_contributor] > 0) {
                        int given_contrib = d[potential_contributor] / reps;
                        if (given_contrib == 0) {
                            break;
                        }
                        total_contribs += given_contrib;
                    }
                }

                if (total_contribs < q) {
                    continue;
                }

                if (L < q * reps) {
                    L = q * reps;
                }
                break;
            }
        }
        printf("%d\n", L);
    }
    return 0;
}

