int calculateSum(int* U, int* B, int N) {
    int maxSum = 0;
    for(int i = 0; i < N; i++) {
        int currentSum = 0;
        for(int j = 0; j <= i; j++) {
            currentSum += U[j];
        }
        for(int k = i; k < N - 1; k++) {
            currentSum += B[k];
        }
        if(currentSum > maxSum) {
            maxSum = currentSum;
        }
    }
    return maxSum;
}

