#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char* processString(char* input) {
    int len = strlen(input);
    char* result;

    if (len > 10) {
        result = (char*) malloc(sizeof(char) * (len - 1));
        if (result == NULL) {
            return NULL; 
        }
        result[0] = input[0];
        sprintf(result + 1, "%d", len - 2);
        result[1 + (len - 2 >= 10 ? 2 : 1)] = input[len - 1];
        result[2 + (len - 2 >= 10 ? 2 : 1)] = '\0';
    } else {
        result = (char*) malloc(sizeof(char) * (len + 1));
        if (result == NULL) {
            return NULL; 
        }
        strcpy(result, input);
    }

    return result;
}

int main() {
    int n;
