        }
    }

    int i1 = 0, j1 = 0, i2 = 0, j2 = 0;

    for(int i = 0; i < n; i++) {
        for(int j = 0; j < n; j++) {
            if(matrix[i][j] != 0) {
                continue;
            }
            if((i == j && k < 1) || (i != j && k < 2)) {
                break;
            }
            matrix[i][j] = 1;
            matrix[j][i] = 1;
            if(i == j) {
                k -= 1;
            } else {
                k -= 2;
            }
