void printPairs(int* arr, int size, int n) {
    int* even = (int*)malloc(size * sizeof(int));
    int* odd = (int*)malloc(size * sizeof(int));
    int evenCount = 0, oddCount = 0;

    for (int i = 0; i < size; i++) {
        if (arr[i] % 2 == 0) {
            even[evenCount] = i;
            evenCount++;
        } else {
            odd[oddCount] = i;
            oddCount++;
        }
    }

    int count = 0;

    for (int i = 0; i < evenCount - 1; i += 2) {
        if (count < n - 1) {
            printf("%d %d\n", even[i] + 1, even[i + 1] + 1);
            count++;
        }
        if (count == n - 1) {
            break;
        }
    }

    if (count < n - 1) {
        for (int j = 0; j < oddCount - 1; j += 2) {
            if (count < n - 1) {
                printf("%d %d\n", odd[j] + 1, odd[j + 1] + 1);
                count++;
            }
            if (count == n - 1) {
                break;
            }
        }
    }

    free(even);
    free(odd);
}

