#include <stdio.h>
#include <string.h>
#include <stdlib.h>

char greatestLetter(char* s) {
    char p[2] = ""; // to hold the result letter, empty initially
    char tmp; // to hold individual characters

    int len = strlen(s);

    for (int i = 0; i < len; i++) {
        tmp = s[i];

        // Check if upper and lower case versions exist
        char upperChar = tmp >= 'a' && tmp <= 'z' ? tmp - 'a' + 'A' : tmp; // convert to upper
        char lowerChar = tmp >= 'A' && tmp <= 'Z' ? tmp + 'a' - 'A' : tmp; // convert to lower

        int existsUpper = 0;
        int existsLower = 0;

        // Check if the uppercase exists
        for (int j = 0; j < len; j++) {
            if (s[j] == upperChar) {
                existsUpper = 1; 
                break; 
            }
        }

        // Check if the lowercase exists
        for (int k = 0; k < len; k++) {
            if (s[k] == lowerChar) {
                existsLower = 1; 
                break; 
            }
        }

        if (existsUpper && existsLower) {
            if (p[0] == '\0' || (upperChar > p[0])) {
                p[0] = upperChar;
                p[1] = '\0'; // ensure it's a valid string
            }
        }
    }

    return p[0]; // return the greatest letter found
}

