int** solve(int n, char** m, int* resSize) {
    int a = m[0][1] - '0';
    int b = m[1][0] - '0';
    int c = m[n - 1][n - 2] - '0';
    int d = m[n - 2][n - 1] - '0';

    int** res = malloc(10 * sizeof(int*)); 
    for (int i = 0; i < 10; i++) {
        res[i] = malloc(2 * sizeof(int));
    }
    *resSize = 0;

    if (a == b) {
        if (a == c) {
            res[*resSize][0] = n;
            res[*resSize][1] = n - 1;
            (*resSize)++;
        }
        if (a == d) {
            res[*resSize][0] = n - 1;
            res[*resSize][1] = n;
            (*resSize)++;
        }
    } else if (c == d) {
        if (c == a) {
            res[*resSize][0] = 1;
            res[*resSize][1] = 2;
            (*resSize)++;
        }
        if (b == c) {
            res[*resSize][0] = 2;
            res[*resSize][1] = 1;
            (*resSize)++;
        }
    } else {
        res[*resSize][0] = 2;
        res[*resSize][1] = 1;
        (*resSize)++;
        if (a == c) {
            res[*resSize][0] = n;
            res[*resSize][1] = n - 1;
            (*resSize)++;
        }
        if (a == d) {
            res[*resSize][0] = n - 1;
            res[*resSize][1] = n;
            (*resSize)++;
        }
    }
    return res;
}

