int isVowel(char ch) {
    char vowels[] = "aeiouy";
    for (int i = 0; i < strlen(vowels); i++) {
        if (ch == vowels[i]) {
            return 1; // It's a vowel
        }
    }
    return 0; // Not a vowel
}

char toLower(char ch) {
    if (ch >= 'A' && ch <= 'Z') {
        return ch + 32; // Convert to lowercase
    }
    return ch; // Already lowercase
}

void processString(const char *input, char *output) {
    int i = 0, j = 0;
    while (input[i] != '\0') {
        char current = toLower(input[i]);
        if (!isVowel(current)) {
            output[j++] = '.';
            output[j++] = current;
        }
        i++;
    }
    output[j] = '\0'; // Null terminate the output string
}

