#define MAX 100001

void initialize(int *arr, int size) {
    for(int z = 0; z < size; z++) {
        arr[z] = 0;
    }
}

void calculate_dp(int *arr, long long dp[MAX][2]) {
    for(int i = MAX - 1; i >= 0; i--) {
        dp[i][1] = dp[i + 1][0] + arr[i] * i;
        dp[i][0] = dp[i + 1][0] > dp[i + 1][1] ? dp[i + 1][0] : dp[i + 1][1];
    }
}

int main() {
    int n;
    scanf("%d", &n);

    int *a = (int *)malloc(n * sizeof(int));
    int arr[MAX];
    long long dp[MAX][2];

    initialize(arr, MAX);

    for(int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
        arr[a[i]] += 1;
    }

    initialize((int *)dp, sizeof(dp) / sizeof(dp[0][0]));

    for(int i = 0; i <= MAX; i++) {
        dp[i][0] = 0;
        dp[i][1] = 0;
    }

    calculate_dp(arr, dp);

    long long result = dp[0][0] > dp[0][1] ? dp[0][0] : dp[0][1];
    printf("%lld\n", result);

    free(a);
    return 0;
}

