int sfun(int n, int k, int *lst) {
    int *s = (int *)malloc(n * sizeof(int));
    int len_s = 0;

    for (int i = 0; i < n; i++) {
        int tmp = lst[i] * k;
        int found = 0;

        for (int j = 0; j < len_s; j++) {
            if (s[j] == tmp) {
                found = 1;
                break;
            }
        }

        if (found) {
            continue;
        }

        s[len_s] = lst[i];
        len_s++;
    }

    free(s);
    return len_s;
}

