} Pair;

typedef struct {
    unsigned char buf[BS];
    int bId;
    int size;
    char c;
    double cnt;
    FILE *in;
} FastScanner;

void initScanner(FastScanner *sc) {
    sc->in = stdin;
    sc->bId = 0;
    sc->size = 0;
    sc->c = 0;
    sc->cnt = 1;
}

char getChar(FastScanner *sc) {
    while (sc->bId == sc->size) {
        sc->size = fread(sc->buf, 1, BS, sc->in);
        sc->bId = 0;
        if (sc->size == 0) return 0;
    }
    return sc->buf[sc->bId++];
}

long long nextLong(FastScanner *sc) {
    sc->cnt = 1;
    bool neg = false;
    if (sc->c == 0) sc->c = getChar(sc);
    while (sc->c < '0' || sc->c > '9') {
        if (sc->c == '-') neg = true;
        sc->c = getChar(sc);
    }
    long long res = 0;
    while (sc->c >= '0' && sc->c <= '9') {
        res = (res * 10) + (sc->c - '0');
        sc->c = getChar(sc);
    }
    return neg ? -res : res;
}

void solve(int yo, FastScanner *sc) {
    while (yo-- > 0) {
        int n = (int)nextLong(sc);
        if (n % 2 == 0) {
            n /= 2;
            printf("0 0 %d\n", n);
        } else {
            printf("-1\n");
        }
    }
}

int main() {
    FastScanner sc;
    initScanner(&sc);
    int yo = (int)nextLong(&sc);
    solve(yo, &sc);
    return 0;
}

