void find(char room[][100], int *desk, char color[], int row, int col) {
    int foundTop = 0, foundBottom = 0;
    int i, j;

    for (i = 0; i < row; i++) {
        for (j = 0; j < col; j++) {
            if (strcmp(room[i][j], color) == 0) {
                desk[0] = i;
                desk[1] = j;
                foundTop = 1;
                break;
            }
        }
        if (foundTop) break;
    }

    for (i = row - 1; i >= 0; i--) {
        for (j = col - 1; j >= 0; j--) {
            if (strcmp(room[i][j], color) == 0) {
                desk[2] = i;
                desk[3] = j;
                foundBottom = 1;
                break;
            }
        }
        if (foundBottom) break;
    }
}

int count(char room[][100], int desk[], char color[], int row, int col) {
    int countSet = 0;
    char deputy[100][100];
    int totalDeputy = 0;

    if (desk[0] != 0) {
        for (int j = desk[1]; j <= desk[3]; j++) {
            if (strcmp(room[desk[0]-1][j], color) != 0) {
                int isNew = 1;
                for (int k = 0; k < totalDeputy; k++) {
                    if (strcmp(deputy[k], room[desk[0]-1][j]) == 0) {
                        isNew = 0;
                        break;
                    }
                }
                if (isNew) {
                    strcpy(deputy[totalDeputy++], room[desk[0]-1][j]);
                }
            }
        }
    }

    if (desk[2] != row - 1) {
        for (int j = desk[1]; j <= desk[3]; j++) {
            if (strcmp(room[desk[2]+1][j], color) != 0) {
                int isNew = 1;
                for (int k = 0; k < totalDeputy; k++) {
                    if (strcmp(deputy[k], room[desk[2]+1][j]) == 0) {
                        isNew = 0;
                        break;
                    }
                }
                if (isNew) {
                    strcpy(deputy[totalDeputy++], room[desk[2]+1][j]);
                }
            }
        }
    }

    if (desk[1] != 0) {
        for (int i = desk[0]; i <= desk[2]; i++) {
            if (strcmp(room[i][desk[1]-1], color) != 0) {
                int isNew = 1;
                for (int k = 0; k < totalDeputy; k++) {
                    if (strcmp(deputy[k], room[i][desk[1]-1]) == 0) {
                        isNew = 0;
                        break;
                    }
                }
                if (isNew) {
                    strcpy(deputy[totalDeputy++], room[i][desk[1]-1]);
                }
            }
        }
    }

    if (desk[3] != col - 1) {
        for (int i = desk[0]; i <= desk[2]; i++) {
            if (strcmp(room[i][desk[3]+1], color) != 0) {
                int isNew = 1;
                for (int k = 0; k < totalDeputy; k++) {
                    if (strcmp(deputy[k], room[i][desk[3]+1]) == 0) {
                        isNew = 0;
                        break;
                    }
                }
                if (isNew) {
                    strcpy(deputy[totalDeputy++], room[i][desk[3]+1]);
                }
            }
        }
    }

    for (int k = 0; k < totalDeputy; k++) {
        if (strcmp(deputy[k], ".") != 0) {
            countSet++;
        }
    }

    return countSet;
}

