const char nl = '\n';

void sortArray(int* arr, int size) {
    for (int i = 0; i < size - 1; i++) {
        for (int j = 0; j < size - 1 - i; j++) {
            if (arr[j] > arr[j + 1]) {
                int tmp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = tmp;
            }
        }
    }
}

long double accumulate(int* arr, int size) {
    long double total = 0;
    for (int i = 0; i < size; i++) {
        total += arr[i];
    }
    return total;
}

