#define MOD 1000000007

long long *fact;
long long *ifact;

long long mod_mul(long long a, long long b, long long m) {
    a = a % m; b = b % m;
    return (((a * b) % m) + m) % m;
}

long long gcd(long long a, long long b) {
    if (b > a) return gcd(b, a);
    if (b == 0) return a;
    return gcd(b, a % b);
}

long long mminvprime(long long a, long long b) {
    long long res = 1, pow = b - 2;
    while (pow) {
        if (pow & 1) res = mod_mul(res, a, b);
        a = mod_mul(a, a, b);
        pow >>= 1;
    }
    return res;
}

void init(int size) {
    fact = (long long *)malloc((size + 1) * sizeof(long long));
    ifact = (long long *)malloc((size + 1) * sizeof(long long));
    fact[0] = 1; ifact[0] = 1;

    for (long long i = 1; i <= size; i++) {
        fact[i] = mod_mul(fact[i - 1], i, MOD);
        ifact[i] = mminvprime(fact[i], MOD);
    }
}

long long ncr(long long n, long long r) {
    long long val1 = fact[n];
    long long val2 = ifact[n - r];
    long long val3 = ifact[r];
    return mod_mul(mod_mul(val1, val2, MOD), val3, MOD);
}

void solve() {
    int n, k; 
    scanf("%d %d", &n, &k);

    int *v = (int *)malloc(n * sizeof(int));
    int *count = (int *)calloc(100001, sizeof(int)); // arbitrary max size

    for (int i = 0; i < n; i++) {
        scanf("%d", &v[i]);
        count[v[i]]++;
    }

    int *present = (int *)calloc(100001, sizeof(int)); // arbitrary max size
    long long ans = 1;

    for (int i = 0; i < k; i++) {
        present[v[i]]++;
    }

    for (int i = 0; i <= 100000; i++) {
        if (present[i] > 0) {
            long long val = ncr(count[i], present[i]);
            ans = mod_mul(ans, val, MOD);
        }
    }

    printf("%lld\n", ans);

    free(v);
    free(count);
    free(present);
}

int main() {
    int test_cases = 1;
    init(1005); // initialize factorials up to 1005

    scanf("%d", &test_cases);
    while (test_cases--) {
        solve();
    }

    free(fact);
    free(ifact);
    return 0;
}

