struct CodeforcesTask253BSolution {
    char result[12];
    int measure_count;
    int* measurements;
};

void read_input(struct CodeforcesTask253BSolution* sol) {
    FILE* file = fopen("input.txt", "r");
    if (file == NULL) {
        fprintf(stderr, "Error opening input file\n");
        exit(1);
    }

    char buffer[256];
    fgets(buffer, sizeof(buffer), file);
    sol->measure_count = atoi(buffer);
    sol->measurements = malloc(sol->measure_count * sizeof(int));

    fgets(buffer, sizeof(buffer), file);
    char* token = strtok(buffer, " ");
    int index = 0;
    while (token != NULL && index < sol->measure_count) {
        sol->measurements[index++] = atoi(token);
        token = strtok(NULL, " ");
    }

    fclose(file);
}

void process_task(struct CodeforcesTask253BSolution* sol) {
    int occurs[5000] = {0};

    for (int i = 0; i < sol->measure_count; i++) {
        int m = sol->measurements[i];
        if (m > 0 && m <= 5000) {
            occurs[m - 1]++;
        }
    }

    int* dels = malloc(4999 * sizeof(int));

    for (int m = 1; m < 5000; m++) {
        int sum1 = 0, sum2 = 0;
        for (int j = 0; j < m - 1; j++) {
            sum1 += occurs[j];
        }
        for (int j = m * 2; j < 5000; j++) {
            sum2 += occurs[j];
        }
        dels[m - 1] = sum1 + sum2;
    }

    int minDel = dels[0];
    for (int i = 1; i < 4999; i++) {
        if (dels[i] < minDel) {
            minDel = dels[i];
        }
    }

    sprintf(sol->result, "%d", minDel);
    free(dels);
}

char* get_result(struct CodeforcesTask253BSolution* sol) {
    return sol->result;
}

int main() {
    struct CodeforcesTask253BSolution solution;
    read_input(&solution);
    process_task(&solution);

    FILE* outputFile = fopen("output.txt", "w");
    if (outputFile == NULL) {
        fprintf(stderr, "Error opening output file\n");
        exit(1);
    }

    fprintf(outputFile, "%s\n", get_result(&solution));
    fclose(outputFile);

    free(solution.measurements);
    return 0;
}

