#define MOD 1000000007

long long MODINV(long long n) {
    long long result = 1;
    long long base = n;
    long long exp = MOD - 2;
    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % MOD;
        }
        base = (base * base) % MOD;
        exp /= 2;
    }
    return result;
}

