                ans *= 3;
            }
            i += 2;
        }

        ans %= MOD;
    }

    if (S1[0] == S2[0]) {
        ans *= 3;
    } else {
        ans *= 6;
    }

    printf("%lld\n", ans % MOD);

    return 0;
}

