#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void subset(char *inp, char *out, char **sub, int *count) {
    if (strlen(inp) == 0) {
        sub[*count] = (char *)malloc((strlen(out) + 1) * sizeof(char));
        strcpy(sub[*count], out);
        (*count)++;
        return;
    }

    char out1[1000];
    char out2[1000];

    strcpy(out1, out);
    strcpy(out2, out);

    out2[strlen(out2)] = inp[0];
    out2[strlen(out2) + 1] = '\0';

    char *newInp = (char *)malloc((strlen(inp)) * sizeof(char));
    strncpy(newInp, inp + 1, strlen(inp) - 1);
    newInp[strlen(inp) - 1] = '\0';

    subset(newInp, out1, sub, count);
    subset(newInp, out2, sub, count);

    free(newInp);
}

int compare(const void *a, const void *b) {
    return strcmp(*(const char **)a, *(const char **)b);
}

char **AllPossibleStrings(char *s, int *returnSize) {
    char **sub = (char **)malloc(1000 * sizeof(char *));
    int count = 0;

    char out[1000] = "";
    subset(s, out, sub, &count);

    qsort(sub, count, sizeof(char *), compare);

    // We want to remove the empty string at index 0
    for (int i = 1; i < count; i++) {
        sub[i - 1] = sub[i];
    }
    count--;

    *returnSize = count;
    return sub;
}

int main() {
    char str[] = "abc";
    int size = 0;
    char **result = AllPossibleStrings(str, &size);

    for (int i = 0; i < size; i++) {
        printf("%s\n", result[i]);
        free(result[i]);
    }
    free(result);

    return 0;
}

