int longestOnes(int* A, int ASize, int K) {
    int i = 0, res = 0;
    for (int j = 0; j < ASize; j++) {
        K -= 1 - A[j];
        // Check if K goes negative
        while (K < 0) {
            K += 1 - A[i];
            i += 1; // Move the start pointer forward
        }
        // Update result if needed
        int currentLength = j - i + 1;
        if (currentLength > res) {
            res = currentLength;
        }
    }
    return res;
}

int main() {
    int K = 1; // Example K
    int A[] = {1, 0, 1, 1, 0}; // Example input array
    int ASize = sizeof(A) / sizeof(A[0]);

    int result = longestOnes(A, ASize, K);
    printf("The longest contiguous subarray with at most %d zeros is: %d\n", K, result);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 6

struct Dice {
    int sides[MAX_SIZE];
};

void init_dice(struct Dice *dice, int t, int s, int e, int w, int n, int b) {
    dice->sides[0] = s; 
    dice->sides[1] = e; 
    dice->sides[2] = n; 
    dice->sides[3] = w; 
    dice->sides[4] = t; 
    dice->sides[5] = b; 
}

int find_value(struct Dice *dice, int in_1, int in_2) {
    switch(in_1) {
        case 1: return dice->sides[4]; // t
        case 2: return (in_2 == 3) ? dice->sides[5] : dice->sides[4]; // w / e
        case 3: return dice->sides[0]; // s
        case 4: return dice->sides[2]; // n
        case 5: return (in_2 == 2) ? dice->sides[1] : dice->sides[0]; // e / s
        case 6: return (in_2 == 1) ? dice->sides[3] : dice->sides[5]; // t / b
        default: return -1; // error condition
    }
}

int main() {
    int t, s, e, w, n, b, p_num, in_1, in_2;

    scanf("%d %d %d %d %d %d", &t, &s, &e, &w, &n, &b);
    scanf("%d", &p_num);

    struct Dice dice_dict[MAX_SIZE];

    init_dice(&dice_dict[0], t, s, e, w, n, b);
    init_dice(&dice_dict[1], n, e, b, w, s, t);
    init_dice(&dice_dict[2], s, e, t, w, n, b);
    init_dice(&dice_dict[3], n, t, b, e, s, w);
    init_dice(&dice_dict[4], e, b, n, t, s, w);
    init_dice(&dice_dict[5], s, t, n, b, e, w);

    for (int i = 0; i < p_num; i++) {
        scanf("%d %d", &in_1, &in_2);
        int result = find_value(&dice_dict[in_1 - 1], in_1, in_2);
        printf("%d\n", result);
    }

    return 0;
}

#include <stdio.h>
