char* postToInfix(const char* postfix) {
    int len = strlen(postfix);
    char** st = (char**)malloc(len * sizeof(char*));
    int top = -1;

    for (int i = 0; i < len; i++) {
        char charA = postfix[i];

        if (isalnum(charA)) {
            st[++top] = (char*)malloc(2 * sizeof(char));
            st[top][0] = charA;
            st[top][1] = '\0';
        } else {
            // It's an operator
            char* b = st[top--];
            char* a = st[top--];

            int size = strlen(a) + strlen(b) + 4; // 2 for brackets and 1 for operator + null terminator
            char* tmp = (char*)malloc(size * sizeof(char));
            snprintf(tmp, size, "(%s%c%s)", b, charA, a);
            st[++top] = tmp;
            free(a);
            free(b);
        }
    }

    char* result = st[top];
    free(st);
    return result;
}

int main() {
    const char* postfix = "abc*-";
    char* infix = postToInfix(postfix);
    printf("%s\n", infix);
    free(infix);
    return 0;
}

