char* getBinaryRepresentation(char c) {
    if (c == '>') return "1000";
    else if (c == '<') return "1001";
    else if (c == '+') return "1010";
    else if (c == '-') return "1011";
    else if (c == '.') return "1100";
    else if (c == ',') return "1101";
    else if (c == '[') return "1110";
    else if (c == ']') return "1111";
    return "";
}

char* convertInputToBinary(char* input) {
    int len = strlen(input);
    char* output = (char*)malloc(len * 4 + 1); 
    output[0] = '\0';

    for (int i = 0; i < len; i++) {
        char* binary = getBinaryRepresentation(input[i]);
        strcat(output, binary);
    }
    return output;
}

long long calculateResult(char* binary) {
    long long result = 0;
    long long p = 1;

    int length = strlen(binary);
    for (int i = 1; i <= length; i++) {
        // Following code is a bit redundant but helps in clarity.
        char bit = binary[length - i];
        int bitValue = bit - '0';
        result += bitValue * p;
        p *= 2;
    }
    return result;
}

int main() {
    char input[100]; 
    printf("Enter a string: "); 
    scanf("%s", input);

    char* binaryRepresentation = convertInputToBinary(input);
    long long finalResult = calculateResult(binaryRepresentation);

    long long m = 1000003;
    printf("%lld\n", finalResult % m);

    free(binaryRepresentation);
    return 0;
}

