#define MAX_LEN 100 // Just a cap for lengths

void process_case(int index) {
    char tmp[MAX_LEN];
    int col_index, row_len;
    int num_obstructions;

    scanf("%s", tmp); // reading the blank line
    scanf("%d %d", &row_len, &num_obstructions);

    char *state_saver[MAX_LEN] = { NULL };
    int h_positions[MAX_LEN]; 
    int h_count = 0;

    for(int j = 0; j < num_obstructions; j++) {
        scanf("%d %d", &row_len, &col_index);
        col_index--; // to make it 0-based

        if(state_saver[col_index] == NULL) {
            state_saver[col_index] = (char*)malloc(MAX_LEN * sizeof(char));
            strcpy(state_saver[col_index], "");
        }
        char tmp2[MAX_LEN];
        sprintf(tmp2, "%s%d", state_saver[col_index], row_len);
        strcpy(state_saver[col_index], tmp2);

        h_positions[h_count] = col_index;
        h_count++;
    }

    if(h_count % 2 != 0) {
        printf("NO\n");
        return;
    }

    // sorting part for the h_positions
    for(int a = 0; a < h_count - 1; a++) {
        for(int b = 0; b < h_count - a - 1; b++) {
            if(h_positions[b] > h_positions[b+1]) {
                int temp = h_positions[b];
                h_positions[b] = h_positions[b+1];
                h_positions[b+1] = temp;
            }
        }
    }

    int is_possible = 1;

    for(int j = 0; j < h_count; j += 2) {
        int block1 = h_positions[j];
        int block2 = h_positions[j + 1];

        if(block1 == block2) {
            continue;
        }

        char* col_block1 = state_saver[block1];
        char* col_block2 = state_saver[block2];

        if(strcmp(col_block1, col_block2) == 0) {
            int separation_parity = (block2 - block1 - 1) % 2;
            if(separation_parity != 0) {
                is_possible = 0;
                break;
            }
        } else {
            int len_block1 = strlen(col_block1);
            int len_block2 = strlen(col_block2);
            if(len_block1 == len_block2) {
                int separation_parity = (block2 - block1 - 1) % 2;
                if(separation_parity == 0) {
                    is_possible = 0;
                    break;
                }
            } else {
                is_possible = 0;
                break;
            }
        }
    }

    if(is_possible) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }

    for(int k = 0; k < MAX_LEN; k++) {
        if(state_saver[k] != NULL) {
            free(state_saver[k]);
        }
    }
}

int main() {
    int in_length;
    scanf("%d", &in_length);

    for(int i = 0; i < in_length; i++) {
        process_case(i);
    }

    return 0;
}

