#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int* asteroidCollision(int* asteroids, int size, int* returnSize) {
    int* list = (int*) malloc(size * sizeof(int));
    int* stack = (int*) malloc(size * sizeof(int));

    int listCount = 0;
    int stackCount = 0;

    for (int i = 0; i < size; i++) {
        int aster = asteroids[i];

        if (aster < 0) {
            while (stackCount > 0 && stack[stackCount - 1] < abs(aster)) {
                stackCount--;
            }
            if (stackCount == 0) {
                list[listCount++] = aster;
            } else if (stackCount > 0 && stack[stackCount - 1] == abs(aster)) {
                stackCount--;
            }
        } else {
            stack[stackCount++] = aster;
        }
    }

    int totalSize = listCount + stackCount;
    int* res = (int*) malloc(totalSize * sizeof(int));

    for (int j = 0; j < listCount; j++) {
        res[j] = list[j];
    }

    int idx = totalSize - 1;
    while (stackCount > 0) {
        res[idx--] = stack[--stackCount];
    }

    *returnSize = totalSize;

    free(list);
    free(stack);

    return res;
}

int main() {
    int asteroids[] = {5, 10, -5};
    int size = sizeof(asteroids) / sizeof(asteroids[0]);
    int returnSize = 0;

    int* result = asteroidCollision(asteroids, size, &returnSize);

    for (int k = 0; k < returnSize; k++) {
        printf("%d ", result[k]);
    }
    printf("\n");

    free(result);

    return 0;
}

