int main() {
    int n;
    scanf("%d", &n);
    if (n == 1) {
        int c;
        scanf("%d", &c);
        printf("%d\n", c);
        printf("%d\n", c);
        return 0;
    }

    int **line = malloc((n - 1) * sizeof(int *));
    for (int i = 0; i < n - 1; i++) {
        line[i] = malloc(2 * sizeof(int));
        scanf("%d %d", &line[i][0], &line[i][1]);
    }

    int *c = malloc(n * sizeof(int));
    for (int j = 0; j < n; j++) {
        scanf("%d", &c[j]);
    }

    // Sort in reverse order
    for (int x = 0; x < n - 1; x++) {
        for (int y = 0; y < n - 1 - x; y++) {
            if (c[y] < c[y + 1]) {
                int tmp = c[y];
                c[y] = c[y + 1];
                c[y + 1] = tmp;
            }
        }
    }

    int sum = 0;
    for (int q = 0; q < n; q++) {
        sum += c[q];
    }

    sum -= c[0];

    int *ans = malloc(n * sizeof(int));
    for (int m = 0; m < n; m++) {
        ans[m] = 0;
    }

    int *vis = malloc(n * sizeof(int));
    for (int r = 0; r < n; r++) {
        vis[r] = 1;
    }

    int a = line[0][0] - 1;
    int b = line[0][1] - 1;
    ans[a] = c[0];
    ans[b] = c[1];
    vis[a] = 0;
    vis[b] = 0;

    for (int i = 1; i < n - 1; i++) {
        for (int k = 0; k < n - 1; k++) {
            a = line[k][0] - 1;
            b = line[k][1] - 1;
            if (vis[a] && !vis[b]) {
                ans[a] = c[i + 1];
                vis[a] = 0;
                break;
            } else if (vis[b] && !vis[a]) {
                ans[b] = c[i + 1];
                vis[b] = 0;
                break;
            }
        }
    }

    for (int v = 0; v < n; v++) {
        printf("%d", ans[v]);
        if (v < n - 1) {
            printf(" ");
        }
    }
    printf("\n");

    for (int i = 0; i < n - 1; i++) {
        free(line[i]);
    }
    free(line);
    free(c);
    free(ans);
    free(vis);

    return 0;
}

