#include <stdio.h>
#include <stdlib.h>

int calc_tip(int p, int r) {
    int last_digit = p % 10;
    if (last_digit < 5) {
        p = p - last_digit;
    } else {
        p = p + (10 - last_digit);
    }

    int T = 0;
    if (p >= 10) {
        T = p / 10;
    } else {
        T = 0;
    }

    int result = 0;
    if (r == 1) {
        result = T + 1;
    } else if (r == 0) {
        if (T - 1 < 0) {
            result = 0;
        } else {
            result = T - 1;
        }
    } else {
        if (T / 2 - 1 < 0) {
            result = 0;
        } else {
            result = T / 2 - 1;
        }
    }

    return result;
}

