#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    int val;
    struct Node* next;
} Node;

typedef struct Graph {
    Node** edges;
    int size;
} Graph;

typedef struct Set {
    int* data;
    int size;
} Set;

Set* createSet(int size) {
    Set* s = malloc(sizeof(Set));
    s->data = malloc(size * sizeof(int));
    s->size = 0;
    return s;
}

void addToSet(Set* s, int val) {
    for (int i = 0; i < s->size; i++) {
        if (s->data[i] == val) return;
    }
    s->data[s->size++] = val;
}

Graph* createGraph(int n) {
    Graph* g = malloc(sizeof(Graph));
    g->size = n;
    g->edges = malloc(n * sizeof(Node*));
    for(int i = 0; i < n; i++) {
        g->edges[i] = NULL;
    }
    return g;
}

void addEdge(Graph* g, int u, int v) {
    Node* nodeU = malloc(sizeof(Node));
    nodeU->val = v;
    nodeU->next = g->edges[u];
    g->edges[u] = nodeU;

    Node* nodeV = malloc(sizeof(Node));
    nodeV->val = u;
    nodeV->next = g->edges[v];
    g->edges[v] = nodeV;   
}

void freeGraph(Graph* g) {
    for(int i = 0; i < g->size; i++) {
        Node* current = g->edges[i];
        while(current) {
            Node* tmp = current;
            current = current->next;
            free(tmp);
        }
    }
    free(g->edges);
    free(g);
}

int dfs(Graph* g, int current, int parent, Set* guessSet) {
    int count = 0;
    for (Node* neighbor = g->edges[current]; neighbor != NULL; neighbor = neighbor->next) {
        if (neighbor->val == parent) continue;
        count += dfs(g, neighbor->val, current, guessSet);
        int edgePair = current * 1000 + neighbor->val; // some arbitrary multiplier 
        int reversePair = neighbor->val * 1000 + current;
        if (edgePair == 1 || edgePair == 2 || reversePair == 1 || reversePair == 2) {
            count++; 
        }
    }
    return count;
}

int rootCount(int** given, int givenSize, int* guess, int guessSize, int k) {
    Graph* g = createGraph(100); // 100 arbitrary size for the example
    Set* guessSet = createSet(guessSize);

    for (int i = 0; i < guessSize; i++) {
        addToSet(guessSet, guess[i]);
    }

    for (int i = 0; i < givenSize; i++) {
        addEdge(g, given[i][0], given[i][1]);
    }

    int totalCount = 0;
    for (int i = 0; i < g->size; i++) {
        int result = dfs(g, i, -1, guessSet);
        if (result >= k) {
            totalCount++;
        }
    }

    freeGraph(g);
    free(guessSet->data);
    free(guessSet);

    return totalCount;
}

#include <stdio.h>
#include <stdlib.h>
#include <math.h>

void resetFreq(int *freq, int base) {
    for(int i = 0; i < base; i++) {
        freq[i] = 0;
    }
}

void countingSort(int *arr, int n, int exp, int base, int *ans) {
    int *freq = (int *)malloc(base * sizeof(int));
    resetFreq(freq, base);

    for(int i = 0; i < n; i++) {
        int index = (arr[i] / exp) % base;
        freq[index]++;
    }

    for(int i = 1; i < base; i++) {
        freq[i] += freq[i - 1];
    }

    for(int i = n - 1; i >= 0; i--) {
        int index = (arr[i] / exp) % base;
        ans[freq[index] - 1] = arr[i];
        freq[index]--;
    }

    for(int i = 0; i < n; i++) {
        arr[i] = ans[i];
    }

    free(freq);
}

void sort(int *arr, int n) {
    int base = n;
    int max_elem = n * n - 1;
    int count = 0;

    while(max_elem > 0) {
        count++;
        max_elem /= base;
    }

    int *ans = (int *)malloc(n * sizeof(int));
    int exponent = 1;

    for(int i = 0; i < count; i++) {
        countingSort(arr, n, exponent, base, ans);
        exponent *= base;
    }

    free(ans);
}

