#include <stdio.h>
#include <stdlib.h>

int dist_to_origin(int x, int y) {
	return x * x + y * y;
}

void extended_gcd(int b, int n, int *gcd, int *x0, int *y0) {
	int x1 = 0, y1 = 1;
	*x0 = 1; 
	*y0 = 0;
	while (n != 0) {
		int q = b / n;
		int tmp = n;
		n = b % n;
		b = tmp;
		int tmp2 = *x0;
		*x0 = x1;
		x1 = tmp2 - q * x1;
		tmp2 = *y0;
		*y0 = y1;
		y1 = tmp2 - q * y1;
	}
	*gcd = b;
}

int getyforx(int x, int a, int b, int c) {
	return (c - a * x) / b;
}

int main() {
	int q;
	scanf("%d", &q);
	for (int i = 0; i < q; i++) {
		int a, b, c;
		scanf("%d %d %d", &a, &b, &c);
		int gcd, x0, y0;
		extended_gcd(a, b, &gcd, &x0, &y0);
		a /= gcd; 
		b /= gcd; 
		c /= gcd;
		int k = c;
		int x_point = k * x0;
		int y_point = k * y0;

		float x_closest = (float)a * c / (a * a + b * b);
		float y_closest = (float)b * c / (a * a + b * b);

		int x_diff = x_point - (int)x_closest;
		int x_steps = x_diff / b;
		int x_candidate = x_point - x_steps * b;
		int y_candidate = getyforx(x_candidate, a, b, c);

		while (!(x_candidate > 0)) {
			x_candidate += b;
		}

		while (x_candidate - b > 0) {
			int x_next = x_candidate - b;
			int y_next = getyforx(x_next, a, b, c);
			if (dist_to_origin(x_next, y_next) < dist_to_origin(x_candidate, y_candidate)) {
				x_candidate = x_next;
				y_candidate = y_next;
			} else {
				break;
			}
		}

		while (1) {
			int x_next = x_candidate + b;
			int y_next = getyforx(x_next, a, b, c);
			if (dist_to_origin(x_next, y_next) < dist_to_origin(x_candidate, y_candidate)) {
				x_candidate = x_next;
				y_candidate = y_next;
			} else {
				break;
			}
		}
		printf("%d %d\n", x_candidate, y_candidate);
	}
	return 0;
}

