#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int rearrangeCharacters(char *s, char *target) {
    int cnts[26] = {0}; // For count of characters in s
    int cntt[26] = {0}; // For count of characters in target
    int ans = 100000; 
    int i = 0, j = 0;

    // Count characters in s
    while(s[i] != '\0') {
        char ch = s[i];
        if(ch >= 'a' && ch <= 'z') {
            cnts[ch - 'a'] += 1;
        }
        i++;
    }

    // Count characters in target
    while(target[j] != '\0') {
        char ch2 = target[j];
        if(ch2 >= 'a' && ch2 <= 'z') {
            cntt[ch2 - 'a'] += 1;
        }
        j++;
    }

    // Process to find min number of times target can be formed
    for(int k = 0; k < 26; k++) {
        if(cntt[k] > 0) {
            if (cnts[k] == 0) {
                return 0; // if the character does not exist in s
            }
            int tmp = cnts[k] / cntt[k];
            if(tmp < ans) {
                ans = tmp;
            }
        }
    }

    return ans;
}

int main() {
    char s[100], target[100];
    printf("Enter string s: ");
    fgets(s, 100, stdin);
    s[strcspn(s, "\n")] = 0; // Remove newline character

    printf("Enter target string: ");
    fgets(target, 100, stdin);
    target[strcspn(target, "\n")] = 0; // Remove newline character

    int result = rearrangeCharacters(s, target);
    printf("Result: %d\n", result);
    return 0;
}

