using System;
using System.Collections.Generic;

class Program {
    static void Main() {
        List<long> arms = new List<long>();
        arms.Add(0);
        for (long i = 1; i <= 1000002; i++) {
            arms.Add(arms[(int)(i - 1)] + i);
        }

        string[] input = Console.ReadLine().Split();
        int N = int.Parse(input[0]);
        long X = long.Parse(input[1]);

        string[] arrInput = Console.ReadLine().Split();
        int[] arr = new int[arrInput.Length];

        for(int i = 0; i < arrInput.Length; i++) {
            arr[i] = int.Parse(arrInput[i]);
        }

        long result = find(arr, N, X, arms);
        Console.WriteLine(result);
    }

    static long find(int[] arr, int N, long X, List<long> arms) {
        long RR = 0;
        long S = 0;
        for(int i = 0; i < arr.Length; i++) {
            S += arr[i];
        }

        long SS = 0;
        for(int j = 0; j < arr.Length; j++) {
            SS += arms[arr[j]];
        }

        RR += SS * (X / S);
        X = X % S;
        List<long> cf = new List<long>();
        cf.Add(0);

        for(int i = 0; i < arr.Length; i++) {
            cf.Add(cf[cf.Count - 1] + arr[i]);
        }

        for(int i = 0; i < arr.Length; i++) {
            cf.Add(cf[cf.Count - 1] + arr[i]);
        }
        cf.RemoveAt(0);

        List<long> nod = new List<long>();
        nod.Add(0);

        for(int i = 0; i < arr.Length; i++) {
            nod.Add(nod[nod.Count - 1] + arms[arr[i]]);
        }

        for(int i = 0; i < arr.Length; i++) {
            nod.Add(nod[nod.Count - 1] + arms[arr[i]]);
        }
        nod.RemoveAt(0);

        long res = 0;

        for(int i = N; i < cf.Count; i++) {
            long K = cf[i] - X;
            int Z = bisect_left(cf, K);
            long Y = cf[Z] - K;
            long R = nod[i] - nod[Z];
            if (Y > 0) {
                R += arms[arr[Z - N]] - arms[arr[Z - N] - (int)Y];
            }
            if(R > res) {
                res = R;
            }
        }

        return RR + res;
    }

    static int bisect_left(List<long> arr, long x) {
        int low = 0, high = arr.Count;
        while (low < high) {
            int mid = low + (high - low) / 2;
            if (arr[mid] < x) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    }
}

