        int index = list.BinarySearch(value);
        if (index < 0) {
            index = ~index;
        }
        list.Insert(index, value);
    }

    static void PrintMedian(List<int> list) {
        int count = list.Count;
        if (count % 2 == 1) {
            Console.WriteLine(list[count / 2]);
        } else {
            double average = (list[count / 2] + list[count / 2 - 1]) / 2.0;
