        Console.WriteLine(result);
    }

    static int minSteps(int height, int up, int down)
    {
        int steps = 0;
        int currHeight = 0;

        while(currHeight < height)
        {
            currHeight += up;
            if(currHeight >= height)
            {
                steps++; // counting the final step
                break;
            }
            else
            {
                currHeight -= down;
                steps++;
            }
        }

        return steps;
    }
}

