    static string DoWork(int k)
    {
        string[] results = new string[k + 1];
        for (int i = 0; i <= k; i++)
        {
            long value = newt(k, i);
            results[i] = value.ToString();
        }
        return string.Join(" ", results);
    }

    static long newt(int n, int k)
    {
        long factN = Factorial(n);
        long factK = Factorial(k);
        long factNK = Factorial(n - k);
        long combination = factN / (factK * factNK);
        return combination % (1000000000);
    }

    static long Factorial(int num)
    {
        if (num == 0 || num == 1)
            return 1;
        long result = 1;
        for (int i = 2; i <= num; i++)
        {
            result *= i;
        }
        return result;
    }
}

