    static int CountDuplicates(List<string> arr)
    {
        HashSet<string> uniqueSet = new HashSet<string>(arr);
        int totalDuplicates = 0;

        foreach (string item in uniqueSet)
        {
            int count = CountOccurrences(arr, item);
            totalDuplicates += count / 2; // Integer division
        }

        return totalDuplicates;
    }

    static int CountOccurrences(List<string> arr, string item)
    {
        int count = 0;

        foreach (string element in arr)
        {
            if (element == item)
            {
                count++;
            }
        }

        return count;
    }
}

