class Solution {
    public List<int> sortedArrayToBST(int[] nums) {
        List<int> res = new List<int>();
        Node root = this.createTree(nums);
        res = this.preorder(root, res);
        return res;
    }

    public Node createTree(int[] nums) {
        if (nums.Length == 0) {
            return null;
        }
        int n = nums.Length;
        int mid;
        if (n % 2 == 0) {
            mid = n / 2 - 1;
        } else {
            mid = n / 2;
        }
        Node root = new Node(nums[mid]);
        root.left = this.createTree(this.sliceArray(nums, 0, mid));
        root.right = this.createTree(this.sliceArray(nums, mid + 1, n));
        return root;
    }

    public List<int> preorder(Node node, List<int> lst) {
        if (node == null) {
            return lst;
        }
        lst.Add(node.data);
        this.preorder(node.left, lst);
        this.preorder(node.right, lst);
        return lst; 
    }

    private int[] sliceArray(int[] arr, int start, int end) {
        int size = end - start;
        int[] sliced = new int[size];
        for (int i = 0; i < size; i++) {
            sliced[i] = arr[start + i];
        }
        return sliced;
    }
}

