using System;
using System.Collections.Generic;
using System.Linq;

class Program
{
    static void Main()
    {
        string input = Console.ReadLine();
        var nums = input.Split(' ').Select(int.Parse).ToArray();
        int n = nums[0];
        int k = nums[1];
        int luck = 0;
        List<int> luck_hq = new List<int>();

        for (int i = 0; i < n; i++)
        {
            string line = Console.ReadLine();
            var values = line.Split(' ').Select(int.Parse).ToArray();
            int l = values[0];
            int t = values[1];
            if (t == 0)
            {
                luck += l;
            }
            else
            {
                AddToHeap(luck_hq, -l);
            }
        }

        if (k >= luck_hq.Count)
        {
            luck += -luck_hq.Sum();
        }
        else
        {
            for (int j = 0; j < k; j++)
            {
                luck += -RemoveFromHeap(luck_hq);
            }
            luck += luck_hq.Sum();
        }
        Console.WriteLine(luck);
    }

    static void AddToHeap(List<int> heap, int value)
    {
        heap.Add(value);
        int index = heap.Count - 1;

        while (index > 0)
        {
            int parent = (index - 1) / 2;
            if (heap[parent] <= heap[index])
                break;

            Swap(heap, parent, index);
            index = parent;
        }
    }

    static int RemoveFromHeap(List<int> heap)
    {
        if (heap.Count == 0)
            throw new InvalidOperationException("Heap is empty.");

        int result = heap[0];
        heap[0] = heap[heap.Count - 1];
        heap.RemoveAt(heap.Count - 1);

        Heapify(heap, 0);
        return result;
    }

    static void Heapify(List<int> heap, int index)
    {
        int left = 2 * index + 1;
        int right = 2 * index + 2;
        int smallest = index;

        if (left < heap.Count && heap[left] < heap[smallest])
            smallest = left;

        if (right < heap.Count && heap[right] < heap[smallest])
            smallest = right;

        if (smallest != index)
        {
            Swap(heap, index, smallest);
            Heapify(heap, smallest);
        }
    }

    static void Swap(List<int> heap, int a, int b)
    {
        int temp = heap[a];
        heap[a] = heap[b];
        heap[b] = temp;
    }
}

