class Program {
    static void Main() {
        string[] inputs = Console.ReadLine().Split();
        int n = int.Parse(inputs[0]);
        int m = int.Parse(inputs[1]);
        int k = int.Parse(inputs[2]);

        string[] line = Console.ReadLine().Split();
        List<int> gov = new List<int>();
        for (int i = 0; i < k; i++) {
            gov.Add(int.Parse(line[i]) - 1);
        }

        Dictionary<int, HashSet<int>> graph = new Dictionary<int, HashSet<int>>();
        for (int i = 0; i < m; i++) {
            string[] edgeInputs = Console.ReadLine().Split();
            int u = int.Parse(edgeInputs[0]) - 1;
            int v = int.Parse(edgeInputs[1]) - 1;

            if (!graph.ContainsKey(u)) {
                graph[u] = new HashSet<int>();
            }
            if (!graph.ContainsKey(v)) {
                graph[v] = new HashSet<int>();
            }
            graph[u].Add(v);
            graph[v].Add(u);
        }

        Dictionary<int, HashSet<int>> govgraph = new Dictionary<int, HashSet<int>>();
        HashSet<int> nottaken = new HashSet<int>();
        for (int i = 0; i < n; i++) {
            nottaken.Add(i);
        }

        foreach (int x in gov) {
            nottaken.Remove(x);
            if (graph.ContainsKey(x)) {
                Queue<int> d = new Queue<int>();
                HashSet<int> reach = new HashSet<int>();
                reach.Add(x);
                d.Enqueue(x);

                while (d.Count > 0) {
                    int c = d.Dequeue();
                    foreach (int i in graph[c]) {
                        if (!reach.Contains(i)) {
                            reach.Add(i);
                            nottaken.Remove(i);
                            d.Enqueue(i);
                        }
                    }
                }
                govgraph[x] = reach;
            } else {
                govgraph[x] = new HashSet<int> { x };
            }
        }

        List<HashSet<int>> ar = new List<HashSet<int>>();
        foreach (var c in govgraph) {
            ar.Add(c.Value);
        }

        ar.Sort((a, b) => b.Count.CompareTo(a.Count));
        int meh = ar[0].Count + nottaken.Count;
        long ans = meh * (meh - 1) / 2;

        for (int i = 1; i < ar.Count; i++) {
            ans += (long)ar[i].Count * (ar[i].Count - 1) / 2;
        }

        Console.WriteLine(ans - m);
    }
}

