        string input = Console.ReadLine();
        if(input == null) return;        
        string[] S = input.Split();

        // Lowercase first element
        S[0] = S[0].ToLower();

        // Count occurrences
        var c = CountOccurrences(S);

        // Sort and get the most common and longest
        string often = GetMostCommon(c);
        string longest = GetLongest(c.Keys);

        // Output the results
        Console.WriteLine(often + " " + longest);
    }

    static Dictionary<string, int> CountOccurrences(string[] arr)
    {
        var counts = new Dictionary<string, int>();
        for(int i = 0; i < arr.Length; i++)
        {
            if(counts.ContainsKey(arr[i]))
            {
                counts[arr[i]] += 1;
            }
            else
            {
                counts[arr[i]] = 1;
            }
        }
        return counts;
    }

    static string GetMostCommon(Dictionary<string, int> counts)
    {
        var sortedItems = counts.ToList();
        sortedItems.Sort((x, y) => y.Value.CompareTo(x.Value));
        return sortedItems[0].Key;
    }

    static string GetLongest(IEnumerable<string> keys)
    {
        var sortedByLength = keys.OrderByDescending(k => k.Length).ToList();
        return sortedByLength[0];
    }
}

