int calc_and(int a, int b) {
    int result = 0;
    int distance = b - a + 1;
    for (int i = 0; i < 32; i++) {
        if (distance <= (1 << i)) {
            int mask = 1 << i;
            if ((a & mask) == (b & mask)) {
                result = result | (a & mask);
            }
        }
    }
    return result;
}

