        if(input != null) {
            string[] words = input.Split(new char[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
            foreach (string word in words) 
            {
                int totalDistance = tv_remote(word);
                Console.WriteLine(totalDistance);
            }
        }
    }

    static int tv_remote(string word) 
    {
        char[,] table = new char[,] 
        {
            { 'a', 'b', 'c', 'd', 'e', '1', '2', '3' },
            { 'f', 'g', 'h', 'i', 'j', '4', '5', '6' },
            { 'k', 'l', 'm', 'n', 'o', '7', '8', '9' },
            { 'p', 'q', 'r', 's', 't', '.', '@', '0' },
            { 'u', 'v', 'w', 'x', 'y', 'z', '_', '/' }
        };

        int[] cur = new int[] { 0, 0 };
        int result = 0;

        foreach (char c in word) 
        {
            int[] newPos = FindChar(table, c);
            if(newPos != null) 
            {
                result += 1 + Math.Abs(newPos[0] - cur[0]) + Math.Abs(newPos[1] - cur[1]);
                cur = newPos;
            }
        }
        return result;
    }

    static int[] FindChar(char[,] table, char c) 
    {
        for (int i = 0; i < table.GetLength(0); i++) 
        {
            for (int j = 0; j < table.GetLength(1); j++) 
            {
                if (table[i, j] == c) 
                {
                    return new int[] { i, j };
                }
            }
        }
        return null; 
    }
}

