    static string MaxNumber(int[] arr, int n)
    {
        string[] strArr = ConvertToStringArr(arr);
        string[] sortedArr = SortDescending(strArr);
        string finalResult = ConcatenateArr(sortedArr);
        return finalResult;
    }

    static string[] ConvertToStringArr(int[] arr)
    {
        string[] strArr = new string[arr.Length];
        for (int i = 0; i < arr.Length; i++)
        {
            strArr[i] = arr[i].ToString();
        }
        return strArr;
    }

    static string[] SortDescending(string[] strArr)
    {
        Array.Sort(strArr, (x, y) => (y + x).CompareTo(x + y));
        return strArr;
    }

    static string ConcatenateArr(string[] arr)
    {
        string result = "";
        for (int i = 0; i < arr.Length; i++)
        {
            result += arr[i];
        }
        return result;
    }
}

