    static int FindN(List<int> l)
    {
        int n = 0;
        int len = l.Count;

        for (int var = 0; var < len; var++)
        {
            var leftSum = SumList(l, 0, var);
            var rightSum = SumList(l, var, len);

            if (leftSum > rightSum)
            {
                n = var;
                break;
            }
            else if (leftSum == rightSum)
            {
                n = var + 1;
                break;
            }
        }

        return n;
    }

