    void dfs(int h) {
        while (ii[h] < aa[h].Length) {
            if (cc[h][ii[h]] != 0)
                ii[h]++;
            else {
                int i = ii[h];
                cc[h][i] = (byte)'L';
                List<long> l = mp[aa[h][i]];
                while (true) {
                    long hi = l[l.Count - 1];
                    l.RemoveAt(l.Count - 1);
                    h = (int)(hi / N);
                    i = (int)(hi % N);
                    if (cc[h][i] == 0) {
                        cc[h][i] = (byte)'R';
                        break;
                    }
                }
            }
        }
    }

