            for (int i = 0; i < n; i++) {
                char c = s[i];
                if (freq.ContainsKey(c)) {
                    freq[c]++;
                } else {
                    freq[c] = 1;
                }
                check[c] = 0; 
            }

            List<char> stack = new List<char>();
            for (int i = 0; i < n; i++) {
                char currentChar = s[i];
                freq[currentChar]--;

                if (check[currentChar] != 0) {
