                    char topChar = stack[stack.Count - 1];
                    stack.RemoveAt(stack.Count - 1);
                    check[topChar] = 0;
                }

                stack.Add(currentChar);
                check[currentChar] = 1;
            }

            string result = new string(stack.ToArray());
            Console.WriteLine(result);
        }
    }
