bool IsKPartitionPossible(int[] a, int k) {
    if (k == 1) {
        return true;
    }
    if (a.Length < k) {
        return false;
    }
    int sum = 0;
    for (int i = 0; i < a.Length; i++) {
        sum += a[i];
    }
    if (sum % k != 0) {
        return false;
    }
    int sumNum = sum / k;
    bool[] used = new bool[a.Length];
    bool res = false;

    bool Dfs(int index, int cur, int depth) {
        if (depth == k) {
            return true;
        }
        if (cur == sumNum) {
            return Dfs(0, 0, depth + 1);
        }
        for (int i = index; i < a.Length; i++) {
            if (used[i] || cur + a[i] > sumNum) {
                continue;
            }
            used[i] = true;
            bool tmpRes = Dfs(i + 1, cur + a[i], depth);
            if (tmpRes) {
                return true;
            }
            else {
                used[i] = false;
            }
        }
        return false;
    }
    return Dfs(0, 0, 0);
}

