            {
                maxValue = arr[i];
            }
        }
        return maxValue;
    }

    static int Min(int[] arr)
    {
        int minValue = arr[0];
        for (int j = 1; j < arr.Length; j++)
        {
            if (arr[j] < minValue) 
            {
                minValue = arr[j];
            }
        }
        return minValue;
    }

