class Program {
    static void Main() {
        var io = new FastIO(Console.OpenStandardInput(), Console.OpenStandardOutput());
        int t = int.Parse(io.ReadLine());

        for (int j = 0; j < t; j++) {
            var parts = io.ReadLine().Split();
            int n = int.Parse(parts[0]);
            int m = int.Parse(parts[1]);
            List<int>[] graph = new List<int>[n];
            for (int s = 0; s < n; s++) {
                graph[s] = new List<int>();
            }
            int root = 0;

            for (int s = 0; s < m; s++) {
                parts = io.ReadLine().Split();
                int u = int.Parse(parts[0]) - 1;
                int v = int.Parse(parts[1]) - 1;
                graph[u].Add(v);
                graph[v].Add(u);
                root = u;
            }

            HashSet<int> ans = new HashSet<int> { root + 1 };
            int cv = 1; 
            int par = 0; 
            Queue<int> queue = new Queue<int>();
            queue.Enqueue(root);
            HashSet<int> vis = new HashSet<int> { root };

            while (queue.Count > 0) {
                int v0 = queue.Dequeue();
                foreach (int s in graph[v0]) {
                    if (!vis.Contains(s)) {
                        queue.Enqueue(s);
                        vis.Add(s);
                    }
                }
                if (par % 2 == 0) {
                    ans.Add(v0 + 1);
                }

                cv--;
                if (cv == 0) {
                    par++;
                    cv = queue.Count;
                }
            }

            if (ans.Count <= n / 2) {
                io.WriteLine(ans.Count);
                io.WriteLine(string.Join(" ", ans));
            } else {
                List<int> newList = new List<int>();
                for (int s = 0; s < n; s++) {
                    if (!ans.Contains(s + 1)) {
                        newList.Add(s + 1);
                    }
                }
                io.WriteLine(newList.Count);
                io.WriteLine(string.Join(" ", newList));
            }
        }
        io.Flush();
        io.Close();
    }
}

