    static void Main(string[] args)
    {
        FastReader s = new FastReader();
        int n = s.nextInt();
        int m = s.nextInt();
        long[] a = s.readLongArray(n);
        long[] b = s.readLongArray(m);
        find(n, m, a, b);
    }

    static void find(int n, int m, long[] a, long[] b)
    {
        long gcd = 0;
        for (int i = 1; i < n; i++)
            gcd = GCD(gcd, Math.Abs(a[i] - a[i - 1]));

        for (int i = 0; i < m; i++)
        {
            long val = a[0] + b[i];
            Console.Write(gcd(val, gcd) + " ");
        }
        Console.WriteLine();
    }

    static long gcd(long x, long y)
    {
        return y == 0 ? x : gcd(y, x % y);
    }

    static long gcd(int x, int y)
    {
        return y == 0 ? x : gcd(y, x % y);
    }

    static long GCD(long x, long y)
    {
        return y == 0 ? x : GCD(y, x % y);
    }

    class FastReader
    {
        private StreamReader sr;
        private string[] tokens;
        private int currentIndex;

        public FastReader()
        {
            sr = new StreamReader(Console.OpenStandardInput());
            tokens = new string[0];
            currentIndex = 0;
        }

        public string next()
        {
            while (currentIndex >= tokens.Length)
            {
                string line = sr.ReadLine();
                if (line == null) break;
                tokens = line.Split(' ');
                currentIndex = 0;
            }
            return tokens[currentIndex++];
        }

        public int nextInt()
        {
            return int.Parse(next());
        }

        public long nextLong()
        {
            return long.Parse(next());
        }

        public long[] readLongArray(int n)
        {
            long[] a = new long[n];
            for (int i = 0; i < n; i++)
                a[i] = nextLong();
            return a;
        }

        public int[] readIntArray(int n)
        {
            int[] a = new int[n];
            for (int i = 0; i < n; i++)
                a[i] = nextInt();
            return a;
        }
    }
}

