        for (int i = 0; i < n; i++)
        {
            mls.Add((ls[i] % m, i));
        }
        mls.Sort();

        var bk1 = new HashSet<int>();
        var bk2 = new HashSet<int>();
        int aim = n / m;
        int cnt = 0;
        var mis = new List<int>();

        for (int i = 0; i < m; i++)
        {
            for (int j = 0; j < aim; j++)
            {
                mis.Add(i);
            }
        }

        int p1 = 0;
        int p2 = 0;

        while (p2 < n)
        {
            if (mls[p1].Item1 > mis[p2])
            {
