class Program
{
    static void Main()
    {
        int n = int.Parse(Console.ReadLine());
        string result = "";

        for (int i = 0; i < n; i++)
        {
            string[] inputs = Console.ReadLine().Split();
            int p = int.Parse(inputs[0]);
            int q = int.Parse(inputs[1]);
            int b = int.Parse(inputs[2]);

            if (Solve(p, q, b) == 1)
            {
                result += "Finite\n";
            }
            else
            {
                result += "Infinite\n";
            }
        }

        Console.Write(result);
    }

    static int Solve(int p, int q, int b)
    {
        long tmp = Pow(b, 64, q);
        long check = (p * tmp) % q;
        if (check == 0)
        {
            return 1;
        }
        else
        {
            return 0;
        }
    }

    static long Pow(int baseVal, int exp, int mod)
    {
        long result = 1;
        long basePow = baseVal % mod;

        while (exp > 0)
        {
            if ((exp & 1) == 1)
            {
                result = (result * basePow) % mod;
            }
            basePow = (basePow * basePow) % mod;
            exp >>= 1;
        }
        return result;
    }
}

