class Program {
    static void Main() {
        string string1 = Console.ReadLine();
        int y = string1.IndexOf('|');
        string[] stringArray = { string1.Substring(0, y), string1.Substring(y + 1) };
        string extra = Console.ReadLine();
        int first = stringArray[0].Length;
        int last = stringArray[1].Length;

        if (first == last) {
            if (extra.Length % 2 == 0) {
                for (int i = 0; i < extra.Length; i++) {
                    if (i % 2 == 0) {
                        stringArray[0] += extra[i];
                    } else {
                        stringArray[1] += extra[i];
                    }
                }
                stringArray = InsertPipe(stringArray);
                Console.WriteLine(string.Join("", stringArray));
            } else {
                Console.WriteLine("Impossible");
            }
        } else if (extra.Length < Math.Abs(first - last)) {
            Console.WriteLine("Impossible");
        } else if (extra.Length == Math.Abs(first - last)) {
            if (first > last) {
                for (int i = 0; i < extra.Length; i++) {
                    stringArray[1] += extra[i];
                }
            } else {
                for (int i = 0; i < extra.Length; i++) {
                    stringArray[0] += extra[i];
                }
            }
            stringArray = InsertPipe(stringArray);
            Console.WriteLine(string.Join("", stringArray));
        } else if (extra.Length > Math.Abs(first - last)) {
            if ((extra.Length - Math.Abs(first - last)) % 2 == 0) {
                char[] temp = extra.ToCharArray();
                if (first > last) {
                    for (int i = 0; i < Math.Abs(first - last); i++) {
                        char x = temp[0];
                        temp = RemoveFirst(temp);
                        stringArray[1] += x;
                    }
                    DistributeChars(stringArray, temp);
                } else {
                    for (int i = 0; i < Math.Abs(first - last); i++) {
                        char x = temp[0];
                        temp = RemoveFirst(temp);
                        stringArray[0] += x;
                    }
                    DistributeChars(stringArray, temp);
                }
            } else {
                Console.WriteLine("Impossible");
            }
        }
    }

    static string[] InsertPipe(string[] arr) {
        string[] newArr = new string[arr.Length + 1];
        newArr[0] = arr[0];
        newArr[1] = "|";
        newArr[2] = arr[1];
        return newArr;
    }

    static void DistributeChars(string[] stringArray, char[] extra) {
        for (int i = 0; i < extra.Length; i++) {
            if (i % 2 == 0) {
                stringArray[0] += extra[i];
            } else {
