class Program {
    static Dictionary<(int, int), int> dic = new Dictionary<(int, int), int>();

    static void Main() {
        var inputs = Console.ReadLine();
        var parts = inputs.Split(' ');
        int n = int.Parse(parts[0]);
        int m = int.Parse(parts[1]);
        int c0 = int.Parse(parts[2]);
        int d0 = int.Parse(parts[3]);

        List<int[]> l = new List<int[]>();
        l.Add(new int[] { -1, c0, d0 });

        for (int i = 0; i < m; i++) {
            var line = Console.ReadLine();
            var tokens = line.Split(' ');
            int a = int.Parse(tokens[0]);
            int b = int.Parse(tokens[1]);
            int c = int.Parse(tokens[2]);
            int d = int.Parse(tokens[3]);
            l.Add(new int[] { a / b, c, d });
        }

        Console.WriteLine(abc(l, n, 0, m + 1));
    }

    static int abc(List<int[]> l, int n, int i, int m) {
        if (dic.TryGetValue((n, i), out int existing)) {
            return existing;
        }

        if (i == m) {
            return 0;
        }

        if (l[i][0] == -1) {
            int b = l[i][1];
            int ans = abc(l, n, i + 1, m);
            int e = 1;

            while (b <= n) {
                ans = Math.Max(ans, e * l[i][2] + abc(l, n - b, i + 1, m));
                b += l[i][1];
                e += 1;
            }

            dic[(n, i)] = ans;
            return ans;
        }

        int res = abc(l, n, i + 1, m);
        int cb = l[i][1];
        int coeff = 1;

        while (cb <= n && coeff <= l[i][0]) {
            res = Math.Max(res, coeff * l[i][2] + abc(l, n - cb, i + 1, m));
            cb += l[i][1];
            coeff += 1;
        }

        dic[(n, i)] = res;
        return res;
    }
}

