                    var inds = (n + 1, m + 1, n, m + 1, n, m);
                    ops.Add(inds);
                    grid[n][m] ^= 1;
                    grid[n - 1][m] ^= 1;
                    grid[n - 1][m - 1] ^= 1;
                }
                if (grid[n][0] * grid[n][1] == 1) {
                    var inds = (n + 1, 1, n + 1, 2, n, 2);
                    ops.Add(inds);
                    grid[n][0] = 0;
                    grid[n][1] = 0;
                    grid[n - 1][1] ^= 1;
                } else if (grid[n][0] == 1) {
