                var neigh2 = (inds[0].Item1 + ((inds[0].Item1 % 2 == 1 && inds[0].Item1 < 2 && !flag) || (flag && inds[0].Item1 < 2) ? 1 : -1), inds[0].Item2);
                if (neigh1 == inds[1]) {
                    neigh1 = (inds[0].Item1 + ((inds[0].Item1 % 2 == 1 && inds[0].Item1 < 2 && !flag) || (flag && inds[0].Item1 < 2) ? 1 : -1), 
                        inde[0].Item2 + ((inds[0].Item2 % 2 == 1 && inds[0].Item2 < 2 && !flag2) || (flag2 && inds[0].Item2 < 2) ? 1 : -1));
                } else {
