            long[] a = new long[n];
            for (long i = 0; i < n; i++) 
            {
                a[i] = long.Parse(Console.ReadLine());
            }

            long cnt = 0;
            var s = new List<long>();
            // Insert first element to start
            Insert(s, a[0]);
            for (long i = 1; i < n; i++) 
            {
                cnt += (s.Count - OrderOfKey(s, a[i]));
                Insert(s, a[i]);
            }

            Console.WriteLine(cnt);
        }
    }

    static void Insert(List<long> list, long value) 
    {
        int index = list.BinarySearch(value);
        if (index < 0) 
        {
            index = ~index; // complement
        }
        list.Insert(index, value);
    }

    static int OrderOfKey(List<long> list, long value) 
    {
        int low = 0, high = list.Count;
        while (low < high) 
        {
            int mid = (low + high) / 2;
            if (list[mid] <= value) 
            {
                low = mid + 1;
            } 
            else 
            {
                high = mid;
            }
        }
        return low;
    }
}

