        // Split and call helper method
        string result = DoSequence(input);
        Console.WriteLine("Result: " + result);
    }

    static string DoSequence(string st)
    {
        if (string.IsNullOrEmpty(st)) return "";

        string s = st[0].ToString(); // Fix: start with the first char
        int count = 1;

        for (int i = 1; i < st.Length; i++)
        {
            if (st[i] == st[i - 1])
            {
                count += 1;
                // Check count again
                if (count < 3)
                {
                    s += st[i]; // Repeat less than 3 times
                }
                else
                {
                    continue; // Ignore this char
                }
            }
            else
            {
                // Reset count
                count = 1;
                s += st[i]; // Adding new character
            }
        }

        return s; // Final result
    }
}

