        var input = Console.ReadLine();
        var parts = input.Split();

        int a = int.Parse(parts[0]);
        int b = int.Parse(parts[1]);

        long mod = 1000000007;
        long tmp = Pow(2, b, mod);
        long tmp2 = (tmp - 1 + mod) % mod; // to avoid negative
        long r = Pow(tmp2, a, mod);

        Console.WriteLine(r);
    }

    static long Pow(long x, long y, long p) {
        long res = 1;
        x = x % p; // in case x is more than p
        if (x == 0) return 0; // if x is 0 then power is 0

        while (y > 0) {
            if ((y & 1) == 1) // if y is odd
                res = (res * x) % p;
            y = y >> 1; // y = y / 2
            x = (x * x) % p; // Change x to x^2
        }
        return res;
    }
}

