    static string GetFirstHalf(string str)
    {
        int mid = (str.Length + 1) / 2;
        return str.Substring(0, mid);
    }

    static string GetSecondHalf(string str)
    {
        int mid = (str.Length + 1) / 2;
        return str.Substring(mid);
    }

    static string ReverseString(string str)
    {
        char[] charArray = str.ToCharArray();
        Array.Reverse(charArray);
        return new string(charArray);
    }

    static string CombineHalves(string firstHalf, string secondHalf)
    {
        string result = "";
        int len = (firstHalf.Length + 1) / 2;
        for (int i = 0; i < len; i++)
        {
            result += firstHalf[i];
            if (i < secondHalf.Length) 
            {
                result += secondHalf[i];
            }
        }
        return result;
    }
}

