            int r = CalculateR(n, q, m);
            int result = CalculateResult(q, r, a, b, m);
            Console.WriteLine(result);
        }
    }

    static int CalculateQ(int n, int m) {
        int q = n / (m + 1);
        return q;
    }

    static int CalculateR(int n, int q, int m) {
        int r = n - q * (m + 1);
        return r;
    }

    static int CalculateResult(int q, int r, int a, int b, int m) {
        int min1 = Math.Min(a * m, b * (m + 1));
        int min2 = Math.Min(a, b);
        int result = q * min1 + r * min2;
        return result;
    }
}

