{
    bool[] prime = new bool[n + 1];
    for (long i = 2; i <= n; i++)
        prime[i] = true;

    for (long i = 2; i <= n; i++)
    {
        if (prime[i])
        {
            for (long j = i * i; j <= n; j++)
            {
                prime[j] = false;
            }
        }
    }

    List<long> res = new List<long>();
    for (long i = 2; i <= n; i++)
    {
        if (prime[i])
            res.Add(i);
    }
    return res;
}

