    static long DoWork1(int[] l, int n) {
        long ans = 0;
        Dictionary<int, int> d = new Dictionary<int, int>();
        d[0] = 1;
        int csl = 0;

        for (int j = 0; j < n; j++) {
            csl += l[j] - 1;
            ans = CheckDictionary(d, csl, ans);
            UpdateDictionary(d, csl);
        }

        return ans;
    }

    static long CheckDictionary(Dictionary<int, int> d, int csl, long ans) {
        if (d.ContainsKey(csl)) {
            ans += d[csl];
        }
        return ans;
    }

    static void UpdateDictionary(Dictionary<int, int> d, int csl) {
        if (d.ContainsKey(csl)) {
            d[csl] += 1;
        } else {
            d[csl] = 1;
        }
    }
}

