        while(number % divisor == 0) {
            number /= divisor;
            count++;
        }
        return count;
    }
}

using System;

class Program {
    static void Main() {
        string s = Console.ReadLine();
        int result = minimumTime(s);
        Console.WriteLine(result);
    }

    static int minimumTime(string s) {
        int n = s.Length;
        int[] cost = new int[n];

        for (int i = 0; i < n; i++) {
            if (s[i] == '0') {
                if (i == 0) {
                    cost[i] = 0;
                } else {
                    cost[i] = cost[i - 1];
                }
            } else {
                if (i == 0) {
                    cost[i] = 1;
                } else {
                    cost[i] = Math.Min(i + 1, cost[i - 1] + 2);
                }
            }
        }

        int[] cost2 = new int[n];

        for (int i = n - 1; i >= 0; i--) {
            if (s[i] == '0') {
                if (i == n - 1) {
                    cost2[i] = 0;
                } else {
                    cost2[i] = cost2[i + 1];
                }
            } else {
                if (i == n - 1) {
                    cost2[i] = 1;
                } else {
                    cost2[i] = Math.Min(n - i, cost2[i + 1] + 2);
                }
            }
        }

        int min = Math.Min(cost[n - 1], cost2[0]);

        for (int i = 0; i < n - 1; i++) {
            min = Math.Min(min, cost[i] + cost2[i + 1]);
        }

        return min;
    }
}

