using System;

class Solution
{
    public static int bsearch(int[] dp, int n, int ele)
    {
        int l = 0;
        int h = n;
        while (l != h)
        {
            int mid = (l + h) / 2;
            if (dp[mid] < ele)
            {
                l = mid + 1;
            }
            else
            {
                h = mid;
            }
        }
        return l;
    }

    public static int removeStudents(int[] H, int N)
    {
        int[] dp = new int[N];
        int llen = 0;
        for (int i = 0; i < N; i++)
        {
            int ind = bsearch(dp, llen, H[i]);
            dp[ind] = H[i];
            llen = Math.Max(llen, ind + 1);
        }
        return N - llen;
    }

    public static void Main()
    {
        string input = Console.ReadLine();
        string[] splitInput = input.Split(' ');
        int N = splitInput.Length;
        int[] H = new int[N];

        for (int i = 0; i < N; i++)
        {
            H[i] = int.Parse(splitInput[i]);
        }

        int result = removeStudents(H, N);
        Console.WriteLine(result);
    }
}

