class Program
{
    static void Main()
    {
        XmlNode rootNode = GetRoot();
        int maxDepth = FindMaxDepth(rootNode);
        Console.WriteLine(maxDepth);
    }

    static XmlNode GetRoot()
    {
        List<string> buf = new List<string>();
        int numLines;
        bool success = int.TryParse(Console.ReadLine(), out numLines);

        for (int i = 0; i < numLines; i++)
        {
            string inputLine = Console.ReadLine();
            if (inputLine != null)
            {
                buf.Add(inputLine.Trim());
            }
        }

        string inputBlock = string.Join("\n", buf);

        XmlDocument doc = new XmlDocument();
        doc.LoadXml(inputBlock);
        XmlNode root = doc.DocumentElement;
        return root;    
    }

    static int FindMaxDepth(XmlNode root)
    {
        if (root == null || root.ChildNodes.Count == 0)
            return 0;
        else
        {
            List<int> depths = new List<int>();
            foreach (XmlNode child in root.ChildNodes)
            {
                int depth = FindMaxDepth(child);
                depths.Add(depth);
            }
            int maxDepth = GetMax(depths);
            return maxDepth + 1;
        }
    }

    static int GetMax(List<int> depths)
    {
        int maxVal = 0;
        foreach (int depth in depths)
        {
            if (depth > maxVal)
            {
                maxVal = depth;
            }
        }
        return maxVal;
    }
}

