using System;
using System.Collections.Generic;

class Program {
    public class Segtree {
        public int unit;
        public int n, m;
        public Func<int, int, int> unite;
        public List<int> tree;

        public Segtree(int n_ = 0, int u = -1) {
            unit = u; 
            n = n_; 
            m = 1; 
            while (m < n) m *= 2; 
            tree = new List<int>(new int[m * 2 - 1]); 
            for (int i = 0; i < tree.Count; i++) tree[i] = unit; 
        }

        public void apply(int u, int w) {
            u += m - 1; 
            tree[u] = w; 
            while (u > 0) {
                u = (u - 1) >> 1; 
                int v = u << 1; 
                tree[u] = unite(tree[v + 1], tree[v + 2]); 
            }
        }

        public int get(int l, int r) {
            int u = unit, v = unit; 
            l += m - 1; 
            r += m - 1; 
            while (l < r) {
                if ((l & 1) == 0) u = unite(u, tree[l++]); 
                if ((r & 1) == 0) v = unite(tree[--r], v); 
                l >>= 1; 
                r >>= 1; 
            }
            return unite(u, v); 
        }

        public int get(int at) {
            return get(at, at + 1); 
        }
    }

    static void Main() {
        var input = Console.ReadLine();
        var tt = int.Parse(input); 

        while (tt-- > 0) {
            input = Console.ReadLine();
            var n = int.Parse(input);
            var a = new int[n];
            input = Console.ReadLine();
            var readNums = input.Split(' ');
            for (int i = 0; i < n; i++) {
                a[i] = int.Parse(readNums[i]); 
            }

            Segtree S = new Segtree(n, -1); 
            S.unite = (i, j) => {
                if (j == -1) return i; 
                if (i == -1) return j; 
                return a[i] < a[j] ? i : j; 
            };

            for (int i = 0; i < n; i++) S.apply(i, i); 

            input = Console.ReadLine();
            var q = int.Parse(input);
            while (q-- > 0) {
                input = Console.ReadLine();
                var lr = input.Split(' ');
                int l = int.Parse(lr[0]) - 1; 
                int r = int.Parse(lr[1]);

                List<int> can = new List<int>();
                if (r - l < 32) {
                    for (int i = l; i < r; i++) {
                        can.Add(i); 
                    }
                } else {
                    for (int i = 0; i < 32; i++) {
                        int u = S.get(l, r);
                        can.Add(u); 
                        S.apply(u, -1); 
                    }
                }

                int ans = int.MaxValue; 
                int m = can.Count; 
                for (int i = 1; i < m; i++) {
                    for (int j = 0; j < i; j++) {
                        ans = Math.Min(ans, a[can[i]] | a[can[j]]); 
                    }
                }

                Console.WriteLine(ans); 
                if (r - l >= 32) {
                    for (int i = 0; i < 32; i++) {
                        S.apply(can[i], can[i]); 
                    }
                }
            }
        }
    }
}

