class Program {

    static void Main() {
        var input = new Scan();
        StringBuilder ans = new StringBuilder("");

        int n = input.scanInt();
        int m = input.scanInt();

        int[] arr = new int[n];
        int[] freq = new int[m + 5];

        for (int i = 0; i < n; i++) {
            arr[i] = input.scanInt();
            if (arr[i] <= m) {
                freq[arr[i]]++;
            }
        }

        int[] freq1 = new int[m + 5];

        for (int i = 1; i < freq.Length; i++) {
            for (int j = 1; i * j < freq.Length; j++) {
                freq1[i * j] += freq[i];
            }
        }

        int max = 0;
        int lcm = 1;

        for (int i = 0; i <= m; i++) {
            if (freq1[i] > max) {
                max = freq1[i];
                lcm = i;
            }
        }

        ans.Append(lcm + " " + max + "\n");

        for (int i = 0; i < n; i++) {
            if (arr[i] > m) {
                continue;
            }
            if (lcm % arr[i] == 0) {
                ans.Append((i + 1) + " ");
            }
        }

        ans.Append("\n");
        Console.Write(ans);
    }

    static int[] Sort(int[] arr, int l, int r) {
        if (l == r) {
            return arr;
        }

        int mid = (l + r) / 2;
        Sort(arr, l, mid);
        Sort(arr, mid + 1, r);

        return Merge(arr, l, mid, mid + 1, r);
    }

    static int[] Merge(int[] arr, int l1, int r1, int l2, int r2) {
        int[] tmp = new int[r2 - l1 + 1];
        int indx1 = l1, indx2 = l2;

        for (int i = 0; i < tmp.Length; i++) {
            if (indx1 > r1) {
                tmp[i] = arr[indx2];
                indx2++;
                continue;
            }
            if (indx2 > r2) {
                tmp[i] = arr[indx1];
                indx1++;
                continue;
            }
            if (arr[indx1] < arr[indx2]) {
                tmp[i] = arr[indx1];
                indx1++;
                continue;
            }
            tmp[i] = arr[indx2];
            indx2++;
        }

        for (int i = 0, j = l1; i < tmp.Length; i++, j++) {
            arr[j] = tmp[i];
        }
        return arr;
    }

    class Scan {
        private byte[] buf = new byte[1024];
        private int index;
        private int total;

        public Scan() {
            // nothing
        }

        public int scan() {
            if (total < 0) throw new Exception();
            if (index >= total) {
                index = 0;
                total = Console.OpenStandardInput().Read(buf, 0, buf.Length);
                if (total <= 0) return -1;
            }
            return buf[index++];
        }

        public int scanInt() {
            int integer = 0;
            int n = scan();
            while (isWhiteSpace(n)) n = scan();
            int neg = 1;

            if (n == '-') {
                neg = -1;
                n = scan();
            }

            while (!isWhiteSpace(n)) {
                if (n >= '0' && n <= '9') {
                    integer *= 10;
                    integer += n - '0';
                    n = scan();
                } else throw new Exception();
            }

            return neg * integer;
        }

        private bool isWhiteSpace(int n) {
            return (n == ' ' || n == '\n' || n == '\r' || n == '\t' || n == -1);
        }
    }
}

using System;
using System.Collections.Generic;

class Program {
    static long[][] dp;
    static long[] pre;

    static void Solve(long i, List<int> nums) {
        long n = nums.Count;
        if(i == n + 1) {
            return;
        }
        long ans = dp[i - 1][0];
        long sum = -1 * dp[i - 1][1];
        if (sum <= nums[(int)(i - 1)]) {
            dp[i] = new long[] { ans + 1, -1 * nums[(int)(i - 1)] };
        } else {
            dp[i] = new long[] { ans, -1 * (sum + (long)nums[(int)(i - 1)]) };
        }

        long idx = Array.BinarySearch(pre, pre[(int)i] - nums[(int)(i - 1)] + sum);
        if (idx < 0) {
            idx = ~idx;
        }

        if (idx <= n) {
            dp[idx] = new long[] {
                Math.Max(dp[idx][0], ans + 1),
                Math.Max(dp[idx][1], -1 * (sum + pre[idx] - (pre[(int)i] - nums[(int)(i - 1)] + sum)))
            };
        }
        Solve(i + 1, nums);
    }

    static int FindMaximumLength(List<int> nums) {
        int n = nums.Count;
        pre = new long[n + 1];
        for(int i = 1; i <= n; i++) {
            pre[i] = nums[i - 1] + pre[i - 1];
        }
        dp = new long[n + 1][];
        for (int j = 0; j <= n; j++) {
            dp[j] = new long[2] { 0, 0 };
        }
        Solve(1, nums);
        return (int)dp[n][0];
    }

    static void Main() {
        List<int> nums = new List<int> { 1, 0, 1, 0, 1 }; // Example input
        int result = FindMaximumLength(nums);
        Console.WriteLine(result);
    }
}

