        var input = Console.ReadLine();
        var parts = input.Split(' ');
        int N = parts.Length;
        int[] parents = new int[N];
        for (int i = 0; i < N; i++) {
            parents[i] = int.Parse(parts[i]);
        }

        var treeRoot = createTree(parents, N);
        // You might want to print or do something with the 'treeRoot' here.
    }

    static Node createTree(int[] parents, int N) {
        Dictionary<int, Node> nodeAddressMap = new Dictionary<int, Node>();
        for (int i = 0; i < N; i++) {
            nodeAddressMap[i] = new Node(i);
        }

        Node root = null;
        for (int i = 0; i < N; i++) {
            int child = i;
            int parent = parents[i];
            if (parent == -1) {
                root = nodeAddressMap[child];
            } else {
                var parentNode = nodeAddressMap[parent];
                if (parentNode.left == null) {
                    parentNode.left = nodeAddressMap[child];
                } else if (parentNode.right == null) {
                    parentNode.right = nodeAddressMap[child];
                }
            }
        }
        return root;
    }
}

