using System;
using System.Collections.Generic;

class Program {
    static void Main() {
        var input = Console.ReadLine();
        var arr = new List<int>();
        int k = 0;

        if (input != null) {
            string[] parts = input.Split();
            for (int i = 0; i < parts.Length - 1; i++) {
                arr.Add(int.Parse(parts[i]));
            }
            k = int.Parse(parts[^1]);
        }

        int winner = getWinner(arr, k);
        Console.WriteLine(winner);
    }

    static int getWinner(List<int> arr, int k) {
        int ln = arr.Count;
        int cnt = -1;
        int idx = 0;

        if (k >= ln) {
            return maxArray(arr);
        }

        while (true) {
            idx = 0;
            List<int> arr2 = new List<int>();
            for (int i = 1; i < ln; i++) {
                if (arr[idx] > arr[i]) {
                    cnt += 1;
                    arr2.Add(arr[i]);
                } else {
                    arr2.Add(arr[idx]);
                    idx = i;
                    cnt = 1;
                }

                if (cnt >= k) {
                    return arr[idx];
                }
            }

            arr = new List<int> { arr[idx] };
            arr.AddRange(arr2);
        }
    }

    static int maxArray(List<int> arr) {
        int max = arr[0];
        for (int i = 1; i < arr.Count; i++) {
            if (arr[i] > max) {
                max = arr[i];
            }
        }
        return max;
    }
}

