class Program
{
    static void Main()
    {
        var input = Console.ReadLine();
        var parts = input.Split();
        int n = int.Parse(parts[0]);
        int m = int.Parse(parts[1]);
        int k = int.Parse(parts[2]);

        string[] P = new string[n];
        for(int i = 0; i < n; i++)
        {
            P[i] = Console.ReadLine().Trim();
        }

        string[][] S = new string[m][];
        for(int i = 0; i < m; i++)
        {
            S[i] = Console.ReadLine().Split();
            S[i][1] = (int.Parse(S[i][1]) - 1).ToString();
        }

        Dictionary<string, int> PDICT = new Dictionary<string, int>();
        for(int i = 0; i < n; i++)
        {
            PDICT[P[i]] = i;
        }

        List<(int, int)> E = new List<(int, int)>();
        for(int i = 0; i < m; i++)
        {
            string x = S[i][0];
            List<int> LIST = new List<int>();
            for(int j = 0; j < (1 << k); j++)
            {
                string t = "";
                for(int l = 0; l < k; l++)
                {
                    if((1 << l & j) != 0)
                    {
                        t += "_";
                    }
                    else
                    {
                        t += x[l];
                    }
                }

                if(PDICT.ContainsKey(t))
                {
                    LIST.Add(PDICT[t]);
                }
            }

            int s = int.Parse(S[i][1]);
            if(!LIST.Contains(s))
            {
                Console.WriteLine("NO");
                return;
            }
            else
            {
                for(int l = 0; l < LIST.Count; l++)
                {
                    if(LIST[l] != s)
                    {
                        E.Add((s, LIST[l]));
                    }
                }
            }
        }

        int[] EDGEIN = new int[n];
        List<int>[] EDGEOUTLIST = new List<int>[n];
        for(int i = 0; i < n; i++)
        {
            EDGEOUTLIST[i] = new List<int>();
        }

        foreach(var (x, y) in E)
        {
            EDGEIN[y]++;
            EDGEOUTLIST[x].Add(y);
        }

        Queue<int> QUE = new Queue<int>();
        for(int i = 0; i < n; i++)
        {
            if(EDGEIN[i] == 0)
            {
                QUE.Enqueue(i);
            }
        }

        List<int> TOP_SORT = new List<int>();
        while(QUE.Count > 0)
        {
            int x = QUE.Dequeue();
            TOP_SORT.Add(x);
            foreach(var to in EDGEOUTLIST[x])
            {
                EDGEIN[to]--;
                if(EDGEIN[to] == 0)
                {
                    QUE.Enqueue(to);
                }
            }
        }

        if(TOP_SORT.Count == n)
        {
            Console.WriteLine("YES");
            Console.WriteLine(string.Join(" ", TOP_SORT.Select(i => i + 1)));
        }
        else
        {
            Console.WriteLine("NO");
        }
    }
}

