class SegmentTree {
    private int[] st;
    private int size;
    private Func<int, int, int> function;
    private int bound;

    public SegmentTree(int n, Func<int, int, int> func, int bound) {
        this.st = new int[2 * n];
        this.size = n;
        this.function = func;
        this.bound = bound;

        for (int i = 0; i < 2 * n; i++) st[i] = bound;
    }

    public void Update(int x, int value) {
        x += size;
        st[x] = value;

        while (x > 1) {
            x >>= 1;
            st[x] = function(st[2 * x], st[2 * x + 1]);
        }
    }

    public int Query(int x, int y) {
        x += size;
        y += size + 1;

        int ans = bound;

        while (x < y) {
            if ((x & 1) != 0) {
                ans = function(ans, st[x]);
                x++;
            }
            if ((y & 1) != 0) {
                y--;
                ans = function(ans, st[y]);
            }
            x /= 2;
            y /= 2;
        }
        return ans;
    }
}

class DSU {
    private int[] p;
    private int[] rank;
    private int[][] nodes;

    public DSU(int n) {
        p = new int[n + 1];
        rank = new int[n + 1];
        nodes = new int[n + 1][];

        for (int i = 0; i <= n; i++) nodes[i] = new int[] { i };

        for (int i = 1; i <= n; i++) {
            p[i] = i;
        }
    }

    public int Find(int node) {
        if (p[node] == node) return node;
        p[node] = Find(p[node]);
        return p[node];
    }

    public void Union(int u, int v) {
        u = Find(u);
        v = Find(v);
        if (u == v) return;

        if (rank[u] == rank[v]) {
            Merge(v, u);
            p[v] = u;
            rank[u]++;
        } else if (rank[u] > rank[v]) {
            Merge(v, u);
            p[v] = u;
        } else {
            Merge(u, v);
            p[u] = v;
        }
    }

    private void Merge(int from, int to) {
        for (int i = 0; i < nodes[from].Length; i++) {
            int node = nodes[from][i];
            if (node + 1 <= nodes.Length - 1 && Find(node + 1) == to) {
                UpdateSegmentTree(node);
            }
            if (node > 1 && Find(node - 1) == to) {
                UpdateSegmentTree(node - 1);
            }
            nodes[to] = nodes[to].Concat(new int[] { node }).ToArray();
        }
    }

    private void UpdateSegmentTree(int node) {
        Program.time++;
        // Assuming st is accessible but not declared globally. This needs adjustment based on context.
        SegmentTree st = null; // Placeholder, need reference to an actual SegmentTree object
        st.Update(node, Program.time);
    }
}

