using System.Linq;

class Program
{
    static void Main()
    {
        int t = int.Parse(Console.ReadLine());
        string alphabet = "abcdefghijklmnopqrstuvwxyz";

        for (int i = 0; i < t; i++)
        {
            string w = Console.ReadLine();
            int lw = w.Length;

            if (lw % 2 == 1)
            {
                Console.WriteLine(-1);
                continue;
            }

            string a = w.Substring(0, lw / 2);
            string b = w.Substring(lw / 2, lw / 2);
            Dictionary<char, int> ha = Histogram(a, alphabet);
            Dictionary<char, int> hb = Histogram(b, alphabet);
            int r = CalculateDifference(ha, hb, alphabet);
            Console.WriteLine(r);
        }
    }

    static Dictionary<char, int> Histogram(string input, string alphabet)
    {
        Dictionary<char, int> h = new Dictionary<char, int>();

        foreach (char l in alphabet)
        {
            h[l] = 0;
        }

        foreach (char c in input)
        {
            if (h.ContainsKey(c))
            {
                h[c] += 1;
            }
        }
        return h;
    }

    static int CalculateDifference(Dictionary<char, int> ha, Dictionary<char, int> hb, string alphabet)
    {
        int total = 0;
        foreach (char l in alphabet)
        {
            int dif = hb[l] - Math.Min(hb[l], ha[l]);
            total += dif;
        }
        return total;
    }
}

