public class TreeNode {
    public int val;
    public TreeNode left;
    public TreeNode right;
    public TreeNode() {}
    public TreeNode(int val) { this.val = val; }
    public TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

class Program {
    static void Main() {
        TreeNode root = new TreeNode(1,
            new TreeNode(2, new TreeNode(4), new TreeNode(5)),
            new TreeNode(3, new TreeNode(6), new TreeNode(7))
        );

        var result = reverseOddLevels(root);

        Console.WriteLine(result.val);
    }

    public static TreeNode reverseOddLevels(TreeNode root) {
        Queue<TreeNode> queue = new Queue<TreeNode>();
        queue.Enqueue(root);
        int depth = 0;

        List<TreeNode> curr = new List<TreeNode>();

        while(queue.Count > 0) {
            for(int k = queue.Count; k > 0; k--) {
                TreeNode t = queue.Dequeue();
                if(t.left != null) queue.Enqueue(t.left);
                if(t.right != null) queue.Enqueue(t.right);
                curr.Add(t);
            }
            if(depth % 2 != 0) {
                for(int i = 0; i < curr.Count / 2; i++) {
                    TreeNode prev = curr[i];
                    TreeNode next = curr[curr.Count - i - 1];
                    int prevval = prev.val;
                    prev.val = next.val;
                    next.val = prevval;
                }
            }
            depth++;
            curr.Clear();
        }
        return root;
    }

    private static void helper(TreeNode root, int depth) {
        if(root == null) return;
        if(depth % 2 == 0) {
            TreeNode tmp = root.left;
            root.left = root.right;
            root.right = tmp;
        }
        helper(root.left, depth + 1);
        helper(root.right, depth + 1);
    }
}

