using System;
using System.Collections.Generic;
using System.Linq;

class Program {
    static void Main() {
        string[] inputs = Console.ReadLine().Split();
        int n = int.Parse(inputs[0]);
        int k = int.Parse(inputs[1]);
        int[] req = Console.ReadLine().Split().Select(int.Parse).ToArray();
        int each = int.Parse(Console.ReadLine());
        int[] prices = Console.ReadLine().Split().Select(int.Parse).ToArray();

        int total = 0;
        List<int> hp = new List<int>();
        Heapify(hp);

        for (int i = 0; i < n; i++) {
            hp.Add(prices[i]);
            SortHeap(hp);
            int needed = (req[i] - k + each - 1) / each;
            needed = Math.Max(0, needed);
            if (hp.Count < needed) {
                Console.WriteLine(-1);
                return;
            }
            for (int j = 0; j < needed; j++) {
                total += PopHeap(hp);
                k += each;
            }
        }
        Console.WriteLine(total);
    }

    static void Heapify(List<int> heap) {
        // This is a simple method to mimic heapify
        heap.Sort();
    }

    static void SortHeap(List<int> heap) {
        // Sort to keep it in a max-heap fashion, it's not efficient but it works here
        heap.Sort();
    }

    static int PopHeap(List<int> heap) {
        if (heap.Count == 0) return -1;
        int min = heap[0];
        heap.RemoveAt(0);
        return min;
    }
}

