using System;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        var s1 = Console.ReadLine();
        int k = int.Parse(Console.ReadLine());
        var l1 = Array.ConvertAll(Console.ReadLine().Split(), int.Parse);

        string alfie = "abcdefghijklmnopqrstuvwxyz";
        var cool = new List<int>();
        int ans = 0;

        // first loop to fill cool
        for (int i = 0; i < s1.Length; i++)
        {
            char letter = s1[i];
            int index = alfie.IndexOf(letter);
            cool.Add(l1[index]);
        }

        // adding max value k times
        for (int j = 0; j < k; j++)
        {
            int maxVal = FindMax(l1);
            cool.Add(maxVal);
        }

        // final computation of ans
        for (int z = 0; z < cool.Count; z++)
        {
            ans += (z + 1) * cool[z];
        }

        Console.WriteLine(ans);
    }

    static int FindMax(int[] array)
    {
        int max = array[0];
        for (int i = 1; i < array.Length; i++)
        {
            if (array[i] > max)
            {
                max = array[i];
            }
        }
        return max;
    }
}

using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;

class Program
{
    static long mod = (long)1e9 + 7;

    static void Main(string[] args)
    {
        FastReader sc = new FastReader();
        int t = sc.nextInt();

        while (t-- > 0)
        {
            int n = sc.nextInt();
            for (int i = 0; i < n; i++)
            {
                for (int j = 0; j <= i; j++)
                {
                    if (j == 0 || j == i)
                    {
                        Console.Write("1 ");
                    }
                    else
                    {
                        Console.Write("0 ");
                    }
                }
                Console.WriteLine();
            }
        }
    }

    static void printN()
    {
        Console.WriteLine("NO");
    }

    static void printY()
    {
        Console.WriteLine("YES");
    }

    static int findFrequencies(int[] a, int n)
    {
        int count = 0;
        for (int i = 0; i < a.Length; i++)
        {
            if (a[i] == n)
            {
                count++;
            }
        }
        return count;
    }

    class FastReader
    {
        BufferedReader reader;
        StringTokenizer st;

        public FastReader()
        {
            reader = new BufferedReader(new InputStreamReader(Console.OpenStandardInput()));
        }

        string next()
        {
            while (st == null || !st.hasMoreElements())
            {
                try
                {
                    st = new StringTokenizer(reader.readLine());
                }
                catch (IOException e)
                {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

        int nextInt() { return int.Parse(next()); }
        long nextLong() { return long.Parse(next()); }
        double nextDouble() { return double.Parse(next()); }
        float nextFloat() { return float.Parse(next()); }
        string nextLine() { return reader.readLine(); }

        int[] readArray(int n)
        {
            int[] a = new int[n];
            for (int i = 0; i < n; i++) a[i] = nextInt();
            return a;
        }
    }

    static int[] EvenOddArrangement(int[] nums)
    {
        int i1 = 0, i2 = nums.Length - 1;
        while (i1 < i2)
        {
            while (nums[i1] % 2 == 0 && i1 < i2) i1++;
            while (nums[i2] % 2 != 0 && i2 > i1) i2--;

            if (i1 < i2)
            {
                int temp = nums[i1];
                nums[i1] = nums[i2];
                nums[i2] = temp;
            }
        }
        return nums;
    }

    static int gcd(int a, int b)
    {
        while (b != 0)
        {
            int t = a;
            a = b;
            b = t % b;
        }
        return a;
    }

    static int lcm(int a, int b)
    {
        return (a / gcd(a, b)) * b;
    }

    static int DigitSum(int n)
    {
        int sum = 0;
        while (n > 0)
        {
            int r = n % 10;
            sum += r;
            n /= 10;
        }
        return sum;
    }

    static bool isPerfectSquare(int number)
    {
        double sqrt = Math.Sqrt(number);
        return (sqrt - Math.Floor(sqrt)) == 0;
    }

    static bool isPowerOfTwo(int n)
    {
        if (n == 0) return false;
        return (int)(Math.Ceiling((Math.Log(n) / Math.Log(2)))) == (int)(Math.Floor(((Math.Log(n) / Math.Log(2)))));
    }

    static bool isPrime(int n)
    {
        if (n <= 1) return false;
        if (n == 2) return true;
        if (n % 2 == 0) return false;

        for (int i = 3; i <= Math.Sqrt(n) + 1; i += 2)
        {
            if (n % i == 0) return false;
        }
        return true;
    }
}

using System;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        string input = Console.ReadLine();
        if (string.IsNullOrEmpty(input))
            return;

        string[] parts = input.Split(',');
        int distance = int.Parse(parts[0].Trim());
        string nType = parts.Length > 1 ? parts[1].Trim() : "moore";
        int x = int.Parse(parts[2].Trim());
        int y = int.Parse(parts[3].Trim());

        int[,] arr = new int[5, 5]; // Example array, you can change size or values.
        for (int i = 0; i < 5; i++)
            for (int j = 0; j < 5; j++)
                arr[i, j] = i * 5 + j;

        var result = get_neighbourhood(nType, arr, (x, y), distance);
        foreach (var item in result)
            Console.WriteLine(item);
    }

    static IEnumerable<(int, int)> get_offsets(int distance, bool moore)
    {
        List<int> offsets = new List<int>();
        for (int i = -distance; i <= distance; i++)
        {
            offsets.Add(i);
        }

        foreach (int dr in offsets)
        {
            foreach (int dc in offsets)
            {
                if (dr == 0 && dc == 0)
                    continue;
                if (!moore && (Math.Abs(dr) + Math.Abs(dc) > distance))
                    continue;

                yield return (dr, dc);
            }
        }
    }

    static List<int> get_neighbourhood(string n_type, int[,] arr, (int, int) coordinates, int distance = 1)
    {
        int h = arr.GetLength(0);
        int w = arr.GetLength(1);

        if (!(coordinates.Item1 >= 0 && coordinates.Item1 < h && coordinates.Item2 >= 0 && coordinates.Item2 < w))
            return new List<int>();

        List<int> results = new List<int>();
        int r = coordinates.Item1;
        int c = coordinates.Item2;

        foreach (var (dr, dc) in get_offsets(distance, n_type == "moore"))
        {
            if (r + dr >= 0 && r + dr < h && c + dc >= 0 && c + dc < w)
            {
                results.Add(arr[r + dr, c + dc]);
            }
        }

        return results;
    }
}
